/* 令和8年委員会データ（自動生成・分割ファイル） */
window.SHINAGAWA_DB.years.r08.committeeSessions.push(...[{"id":"r08-20260309-3","meetingId":"r08-yosan","date":"2026年3月9日","dateIso":"2026-03-09","committee":"予算特別委員会","time":"午前 ９時３０分～午後 ４時５５分","status":"正式会議録","sourceType":"formal","overview":"予算特別委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を140件整理しています。","topics":[{"id":"topic-01","title":"委員会での質疑","agenda":"委員会での質疑","exchanges":[{"speaker":"えのした委員","kind":"質問・要望","question":"は２４１ページ、地域生活支援事業、日常生活用具給付事業等、都内初となる視覚障害者向け遠隔サポートシステムの導入についてお伺いします。令和７年第４回定例会本会議での一般質問で、日常生活用具給付等事業の給付品目にスマートフォン・タブレット端末の追加を要望し、今回導入が実現し。","respondent":"松山障害者支援課長","answer":"予算規模は２１１万円余、内訳はシステム利用料で、月額４,４００円で４０人を見込んでおります。１２月分の費用となっております。","id":"exchange-001"},{"speaker":"えのした委員","kind":"確認","question":"予算規模２１１万円余、あと利用される方が４０人とのことで、初年度から必要な方にしっかりと届けていただけることを確認しました。そこでお伺いします。","respondent":"松山障害者支援課長","answer":"音声で案内するため、音声が聞き取りづらい駅のホームや、第三者のプライバシーに関わる場所での利用はできないこととなっております。区役所内でのご利用については、事業者のサービスにより無料で利用可能となっております。","id":"exchange-002"},{"speaker":"えのした委員","kind":"質問","question":"危険なところですか、駅のホームや、プライバシーに関わる場所。初めての導入とのことですから、視覚障害者の方への操作説明などを含め、周知についてお伺いいたします。","respondent":"松山障害者支援課長","answer":"ホームページ等、また視覚障害者団体を通じまして、ご案内したいと考えています。併せて、視覚障害者の方が円滑にご利用できるように、事業者から操作説明をしてもらう機会を設けるなど、丁寧に対応してまいります。","id":"exchange-003"},{"speaker":"えのした委員","kind":"質問・要望","question":"次に、実際の運用体制と安全性についてお伺いします。単なる案内役以上の高度なスキルと倫理感が求められると思いますが、区がどのように担保していくのかお伺いいたします。","respondent":"松山障害者支援課長","answer":"最近、自治体向けのサービスを創設した、実績のある事業者です。既に区民の方のご利用もあり、事業者側でオペレーターに関しての研修および個人情報保護は徹底しています。","id":"exchange-004"},{"speaker":"えのした委員","kind":"質問・要望","question":"やはり、安全第一での運用を徹底していただきますよう要望いたします。次に、２４５ページ、在宅生活支援事業、障害者医療ショートステイ事業についてお伺いします。","respondent":"松山障害者支援課長","answer":"実施場所は、第三北品川病院の予定です。今後、契約予定で、時期については現在、調整中です。","id":"exchange-005"},{"speaker":"えのした委員","kind":"質問","question":"そこでお伺いします。２４９ページの医療的ケア児等コーディネーター支援体制整備促進事業について、内容をご説明ください。","respondent":"松山障害者支援課長","answer":"障害者支援課にご連絡を頂き、今後は退院の際の連絡を、大原児童発達支援センター内のインクルーシブひろばベルに一本化いたします。区のケースワーカーや保健師と共に、カンファレンスへの参加、退院支援をチームで行ってまいります。","id":"exchange-006"},{"speaker":"山本委員","kind":"質問","question":"２６５ページの新条例制定検討経費、２６９ページのヤングケアラー支援事業、２８５ページの私立保育園費について伺います。そこで伺います。","respondent":"佐藤保育事業担当課長","answer":"近隣にあります公立保育園の改築工事のために設置いたしました仮園舎を、緊急対応として暫定的に、本日よりご利用いただくことといたしました。引き続き、園児や保護者、そして事業者の方々の不安を取り除けるようにしっかりと支援してまいります。","id":"exchange-007"},{"speaker":"山本委員","kind":"質問・要望","question":"区としてどのような機能や独立性を持たせる方向で検討するのか、お考えを伺います。以上３点、区のお考えを伺います。","respondent":"柴田子ども施策連携担当課長","answer":"設置の形態やその権限については様々ありますので、これからさらに研究を進め、区の実態に合った形での設置について検討してまいります。最後に、こちらはこれからの検討となりますが、そして利用のしやすさという視点を持って検討を進めてまいる考えです。","id":"exchange-008"},{"speaker":"山本委員","kind":"質問・要望","question":"これまで、令和６年度・令和７年度の決算特別委員会でもご質問し、デジタルも活用したアンケートの仕組みづくりを重ねて要望してまいりました。来年度予算において、この点はどのように取り組まれるのか尋ねました。","respondent":"吉野子ども家庭支援センター長","answer":"来年度ですけれども、ヤングケアラーの実態把握と当事者の支援、相談ニーズの抽出を目的とした調査を実施したいと考えております。気になるお子さんや家庭がないか、支援者側の目線で見ていただき、必要なニーズについても聞き取りを行いたいと考えております。","id":"exchange-009"},{"speaker":"山本委員","kind":"質問・要望","question":"そこで、まず３点伺います。こうした取組を重点分野として区が支援するべきと考えるかどうかについて、本事業に関する令和８年度の主な取組と対象人数について説明を求めました。","respondent":"樫村高齢者地域支援課長","answer":"１点目と２点目につきまして、健康寿命を延ばす取組についての認識ですけれども、そして社会参加につながるような取組を幅広く進めているところです。こういった取組は、高齢者の健康寿命を延ばすことにもつながるものであると認識しておりまして…","id":"exchange-010"},{"speaker":"山本委員","kind":"質問","question":"そこで伺います。対象年齢７０歳以上のものを６５歳以上にするなどの引下げや、健康寿命の延伸に資する有効な方策と考えますが、区の見解を伺います。","respondent":"樫村高齢者地域支援課長","answer":"例えば、先ほど申し上げましたシルバーセンターや多世代交流支援施設のゆうゆうプラザに関しましては、無料でできる運用となっております。高齢者の外出機会を後押しすることになりまして、その結果、健康寿命の延伸にも資することだと認識しております。","id":"exchange-011"},{"speaker":"山本委員","kind":"質問・要望","question":"区によるシルバーパス独自助成については、代表質問でも要望しておりますので、ここでは重ねての答弁は求めませんが、この場でも改めて要望します。高齢者の皆様全体の健康寿命の延伸につながる施策、そして住んでいてよかったと思える施策の充実を求めて、私の質問を終わります。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-012"},{"speaker":"ゆきた委員","kind":"質問","question":"私からは、また同じく２４１ページの日常生活用具給付事業等から、ＩＣＴ技術を活用した新規給付対象化についてお伺いしてまいります。生活介護延長受入運営費助成についてお伺いします。","respondent":"松山障害者支援課長","answer":"生活介護の延長の次年度予算の見込み数ですが、３,０００人余を見込んでおります。","id":"exchange-013"},{"speaker":"ゆきた委員","kind":"確認","question":"朝が間に合わなければ仕事にならないということも伺っています。そこで、朝の送迎や朝の受入れについて、区にどのような声が上がっているのか伺います。","respondent":"松山障害者支援課長","answer":"生活介護の延長の部分の朝の時間についての対応です。来年度、特別支援学校の卒業生のご家族から、就労継続のため、朝の個別の利用ニーズに対するご要望はあります。","id":"exchange-014"},{"speaker":"ゆきた委員","kind":"質問・要望","question":"一律に展開するのは難しいと思いますが、ニーズのあるところの要望を洗い出して、段階的に早朝での受入れをしてほしいと求めました。利用者の個別の事情に応じて、ニーズに合わせた受入れができるような取組を進めてほしいと求めましたが、区のお考えをお聞きします。","respondent":"松山障害者支援課長","answer":"心身障害者福祉会館での生活介護の延長の朝の受入れ等々、個別対応についてお尋ねがありました。朝の個別の利用ニーズに対応する必要がありまして、送迎なしであれば朝７時半から受入れが可能ということになりました。","id":"exchange-015"},{"speaker":"ゆきた委員","kind":"質問・要望","question":"これまで２０２３年、タブレットやスマホ端末を日常生活用具の給付対象にと要望してきましたが、大変に歓迎するものと受け止めています。併せて、厚生労働省では、機器名ではなく用途によって整理することが可能であるとの考えを示していますが、ここについて区の認識を伺います。","respondent":"松山障害者支援課長","answer":"国の認識、それから区の見解についてです。国の認識どおり、具体的な種目、上限価格等の運用方法については、国で一律に定めておりませんで、各自治体で決定することとなっております。","id":"exchange-016"},{"speaker":"ゆきた委員","kind":"確認","question":"予算案では、タブレットかスマホのいずれか一方を選択して給付するという仕組みであると伺っております。こうした実態を踏まえ、用途に応じた種目整理や、診断書を活用した要件設定を検討すべきと考えますが、区の見解をお聞きします。","respondent":"松山障害者支援課長","answer":"区では以前から、パソコンのソフトウエアについて情報・通信支援用具として給付していたことから、そちらに分類・整理いたしました。国の動向を注視しつつ、委員のご提案も含めてご意見を伺いながら、適切に給付に努めてまいりたいと考えています。","id":"exchange-017"},{"speaker":"安藤委員","kind":"質問","question":"伺いたいのですけれども、区でやりましたけれども２３区ではこの実施状況がどうなっているのか、分かる範囲で伺います。昨年９月の時点で送迎している事業所は１８事業所ということでしたけれども、加算で送迎を始めた事業所というのは何か所あるのか、伺います。","respondent":"佐藤障害者施策推進課長、松山障害者支援課長","answer":"１１月から開設費用の助成を始めてまいりましたけれども、こちらの制度を含めて対応した事業所、開設した事業所があるです。先ほどの２か所のうち１か所、申請がございましたので… 私からは、中・重度障害者の受入れのための加算の実施状況について、お答えいたします。そのほか、中・重度障害児受入れ促進助成を利用して受け入れ始めた事業所というのは、先ほどの送迎をしていただいている１事業所があります。","id":"exchange-018"},{"speaker":"安藤委員","kind":"質問","question":"直接、他区の法人や事業者に声かけなどはしたのか、伺いたいと思います。放課後等デイサービスの必要量について、区の分析は今どのようになっているのか伺いたいと思います。","respondent":"佐藤障害者施策推進課長","answer":"次年度も事業継続をする方向で予定していますので、そういったところで考えているところです。事業者の区内への誘致については進めていくというところになりますけれども、予算計上としましてはそういったところで予定しています。","id":"exchange-019"},{"speaker":"安藤委員","kind":"質問・要望","question":"経営体力が必ずしも大きくないところから、４月時点での定員割れに対する運営費助成を求める切実な声が毎年届いています。６か月間あるいは３か月間からでも、ぜひお願いしたいのですが、いかがか尋ねました。","respondent":"佐藤保育事業担当課長","answer":"区といたしましては、私立認可保育園の経営支援というのは必要なものであると認識しておりますので、様々な声を聞きながら適切に対応していきたいと考えております。","id":"exchange-020"},{"speaker":"せらく委員","kind":"質問","question":"質問なのですけれども、すまいるスクールの無償プログラムの充実についてお聞きします。子どもたちの声はどのように反映されるのか尋ねました。","respondent":"上野子ども育成課長","answer":"理科実験プログラム、ダンス教室、様々な授業のプレプログラムなどの提供を求めていく予定です。プログラム実施後、興味があったプログラムや、今後やってみたいプログラム等々の声を拾っていきたいと考えております。","id":"exchange-021"},{"speaker":"せらく委員","kind":"質問","question":"既存のプログラムなのですけれども、評価や見直しということは行っていますでしょうか。その充実によって、スケジュールの調整、施設を押さえるなどで増える、スタッフの役割、負担感については、どうお考えか尋ねました。","respondent":"上野子ども育成課長","answer":"来年度、さらなるプログラム充実・強化を図る取組を進めてまいりますので、そちらでさらなる強化を図ってまいりたいと考えております。区の担当指導員を中心に、プログラム実施については調整しながら対応してまいりたいと考えております。","id":"exchange-022"},{"speaker":"せらく委員","kind":"質問・要望","question":"指摘事項が減少しているというふうに見えますが、安全対策や運営管理が丁寧に行われて、指摘が減ってきているのでしょうか。こちらの改善後は、巡回などで実際に確認していますか尋ねました。","respondent":"芝野保育入園調整課長","answer":"施設の移転を前提に計画に盛り込んでいただきまして、それを改善状況報告書という形で提出いただいた場合には、改善済みとしているケースがあります。そういった点で改善に取り組んでいるというのが現状です。","id":"exchange-023"},{"speaker":"せらく委員","kind":"確認","question":"ハード面に関するところなのですけれども、区の指導検査実施要綱にも書いてありました。きちんと改善はしていないという受け止めになるのですけれども、計画書に沿ってしっかり取り組んでいるかというところの確認はいかがか尋ねました。","respondent":"芝野保育入園調整課長","answer":"計画書に基づいてしっかりと改善を行っているかという経過につきましても、しっかりと指導検査の中で確認させていただきながら進めているです。","id":"exchange-024"},{"speaker":"せらく委員","kind":"質問・要望","question":"しっかり確認してほしいと求めました。各種保育施設に指導検査を行っていますが、病児保育施設はどのような扱いか尋ねました。","respondent":"芝野保育入園調整課長","answer":"病児保育施設につきましては、児童福祉法上で病児保育事業として位置づけられておりまして、必要に応じて検査を行うというふうにされておりますので、定期的な指導検査は行っていないのが現状です。","id":"exchange-025"},{"speaker":"せらく委員","kind":"確認","question":"他自治体でも病児保育施設について確認体制を整えているところがありますが、区として検討はしていただけるのでしょうか。説明を求めました。","respondent":"芝野保育入園調整課長","answer":"今後の病児保育事業の指導検査体制につきましては、検討・研究をして進めていきたいと考えております。","id":"exchange-026"},{"speaker":"横山委員","kind":"質問・要望","question":"必要に応じて電話や、関係機関への同行を行う伴走型支援を、より明確に位置づけていただきたいのですが、区のお考えを伺います。そうした場面で子どもの心理的負担を軽減する共通の対応手順や研修体制は整備されているのか尋ねました。","respondent":"東野福祉計画課長、長谷川児童相談課長","answer":"重層的支援体制整備事業といたしまして、包括的相談支援の浸透に向けて、それから民間支援団体への説明会なども行っております。支援会議では、誰がどのように支援を行うのか、伴走型支援を行っていくというものです。 併せまして、特定の子どもだけの問題ではなく、児童相談所職員を対象とした研修や事例検討を通じて理解の促進に努めているところです。来年度におきましても、児童相談所職員に対する専門研修を継続し…","id":"exchange-027"},{"speaker":"横山委員","kind":"質問・要望","question":"一時保護所のしおりや子どもの権利を説明する冊子に多言語ＱＲをつけていただきたいと要望いたします。支援者を支える仕組み、やりたい福祉ができる体制を強化していただきたいのですが、研修や体制整備の現状と課題について、区の見解を伺います。","respondent":"長谷川児童相談課長","answer":"年３回の進行管理会議を実施いたしまして、管理職等による助言やスーパービジョンを通じて職員が相談しながら対応できる体制を整えております。区としましては、支援に携わる職員が安心して相談しながら専門性を高められる環境づくりに努め…","id":"exchange-028"},{"speaker":"澤田委員","kind":"質問","question":"本日は、２６５ページ、朝食支援、２４１ページ、就労移行支援等、同ページ、ガイドヘルプ・処遇改善加算等助成についてお伺いいたします。そして、効果測定は行われたのか尋ねました。","respondent":"上野子ども育成課長","answer":"朝食支援について、朝食支援により、児童の健全な成長を支援するという目的で事業を実施しております。児童の朝の欠食を防ぐなど、一定の効果があったと認識しております。","id":"exchange-029"},{"speaker":"澤田委員","kind":"意見","question":"お声からも、不登校支援としての効果や、家事・育児に余裕がない保護者への支援としても効果があったのかなと思います。本当に支援を必要としている子どもに届いているのか、届けるために区としてどのような対応をお考えなのか、区の見解を説明を求めました。","respondent":"上野子ども育成課長","answer":"朝の見守りの中で支援が必要な児童を発見した場合は、速やかに学校や子ども家庭支援センターと連携し、適切な支援につなげてまいります。ヤングケアラーなど特別な配慮が必要な児童につきましても、子ども家庭支援センターを中心に、配食支援を含め…","id":"exchange-030"},{"speaker":"澤田委員","kind":"質問・要望","question":"子どもや保護者が必要な支援へとつながるように、見守りというのをしっかりとやってほしいと求めました。それらを見つけるためにもしっかりと対応していただけるよう、体制の強化を要望いたしますが、区のご見解をお願いします。","respondent":"上野子ども育成課長","answer":"朝食支援を届けるための工夫ですけれども、特定原材料である８品目を表示し、保護者の方に確認いただいた上で申込みを頂いておりました。本格実施に向け、実績や利用者の声等から、適切な対応について今後検討してまいります。","id":"exchange-031"},{"speaker":"澤田委員","kind":"質問","question":"次に、就労移行支援についてお伺いいたします。先日、会派で飯田市へ視察に伺いました。","respondent":"松山障害者支援課長","answer":"就労継続支援Ｂ型である、かもめ第二工房については、作業メニューとしてお菓子作りを行っております。区のマークが変わったこともありまして、次の目玉商品ということで職員が奮闘しまして、区関係部署との協議・調整を経て開発したものです。","id":"exchange-032"},{"speaker":"澤田委員","kind":"意見","question":"スターバックスでのアルバイトが大学生に人気であるのも、洗練された店舗デザインが理由の一つであると聞きます。商品の価値がより一層上がり、売上げや皆さんの工賃を上げることにもつながると考えますが、区としてのお考えをお知らせくださいとの意見を述べました。","respondent":"松山障害者支援課長","answer":"委員がおっしゃられるように、商品価値を高めることは工賃を上げることにも直結いたします。工夫しまして、商品価値を高めるための環境の中で製品を販売するということで、売上げが上がっている状況です。","id":"exchange-033"},{"speaker":"澤田委員","kind":"質問・要望","question":"Ｋｉｔａｒａでも、おしゃれな店内をつくられたり、様々価値を上げる取組というのは今もされているということですので、うれしいと考えています。改めてヒアリングしていただいたり、いろいろな支援メニューを拡充していただけることを要望いたしますが、区のご見解を説明を求めました。","respondent":"松山障害者支援課長","answer":"商品価値を高める取組に対する区の支援についてお尋ねがございました。地域自立支援協議会の就労支援部会で、課題について協議してまいりましたが、区としても事業者の取組を今後も支援してまいります。","id":"exchange-034"},{"speaker":"澤田委員","kind":"質問・要望","question":"どうぞ引き続き、よろしくお願いいたします。活躍の場を広げる取組をぜひ進めていただきたいと要望するとともに、ウエルフェアトレードを、区としてのご所見を伺います。","respondent":"松山障害者支援課長","answer":"ウエルフェアトレードを後押しする、区の支援です。その価値を高めていく必要があると考えておりますし、今後もその価値を高め、多くの活躍の場をつくっていきたいと考えております。","id":"exchange-035"},{"speaker":"澤田委員","kind":"質問・要望","question":"我が会派からも要望しておりましたので、大変うれしく思うとともに、人材確保につながることを心より期待しております。「地域自立支援協議会の子ども支援部会の中でも、人材確保をしようということで、動画についての現況をお聞かせいただけますか尋ねました。","respondent":"松山障害者支援課長","answer":"子ども支援部会で企画いたしまして、ラシクラボという就労継続支援Ｂ型事業所が動画を作りました。２月の地域自立支援協議会全体会で動画をお披露目したところ、委員の方々から拍手が起きて、温かい動画であるということで好評を得たところです。","id":"exchange-036"},{"speaker":"澤田委員","kind":"意見","question":"２月のお披露目で大変好評だったということですけれども、Ｂ型就労支援にも寄与するすてきな取組であると思います。今後もこのような連携・展開を期待したいと思いますが、ご見解を聞かせてくださいとの意見を述べました。","respondent":"松山障害者支援課長","answer":"今後、移動支援の人材確保のために、様々な機会を捉えながら、来年度の移動支援の充実内容も含めまして、積極的なＰＲを推進してまいります。","id":"exchange-037"},{"speaker":"澤田委員","kind":"質問・要望","question":"先日の総務会でも触れさせていただいた、区としては広報紙の活用についてはどのようにお考えでしょうか。今回作成される動画のＱＲコードを載せるなどすることも、より多くの方に見ていただく機会になると考えますが、いかがか尋ねました。","respondent":"松山障害者支援課長","answer":"戦略広報課と連携しまして、移動支援の人材確保のために、なおＰＲ力が高まると考えております。積極的にＰＲしてまいります。","id":"exchange-038"},{"speaker":"筒井委員","kind":"質問","question":"２３８ページ、２５５ページ、認知症高齢者支援事業に関連してご質問します。令和７年度において本格実施されましたけれども、そして次年度、令和８年度の取組はどのように行っていくのかをお聞きいたします。","respondent":"東野福祉計画課長","answer":"庁内連携におきましては、先ほども横山委員にも説明させていただきました包括的相談支援のところで、重層的支援会議というものを行っております。いわゆる地域づくりについて課題があると考えていますので、令和８年度、取り組んでいこうと考えています。","id":"exchange-039"},{"speaker":"筒井委員","kind":"質問・要望","question":"ぜひ鋭意取り組んでいっていただきたいと存じます。孤独・孤立対策推進事業についてなのですけれども、サードプレイスの事業化について、現状どうなっていますか尋ねました。","respondent":"東野福祉計画課長","answer":"今後地域との接触を望んでいる方、そういった方たちへ向けたサードプレイスをどうするかという点で、これまで様々検討してまいりました。予算は、今後審議となりますけれども確保しておりますので、その中でどういったことができるのかを改めて考える準備を今現在しています。","id":"exchange-040"},{"speaker":"筒井委員","kind":"質問","question":"分かりました。まだ具体的な場所や設備をどうしようかという、そこまで具体化は進んでいないということなのか尋ねました。","respondent":"東野福祉計画課長","answer":"場所につきましては目星はついているのですけれども、そこで実際にできるかどうかという可能性も含めまして取り組んでいこうと考えています。","id":"exchange-041"},{"speaker":"筒井委員","kind":"質問・要望","question":"ぜひよろしくお願いします。残りの７ステーションは６５歳以上の相談のみということなのですけれども、支え愛・ほっとステーションは、その辺りのご予定をお伺いいたします。","respondent":"東野福祉計画課長","answer":"ホームページ上の表記につきましては、少し大きくするなど検討させていただければと思います。それから令和８年度は４ステーション、令和９年度で３ステーションということで、全ステーションの拡充を考えているところです。","id":"exchange-042"},{"speaker":"筒井委員","kind":"質問・要望","question":"熱中症になる危険性が高い方が多いかなと考えております。都民ファーストの会の要望によりまして、東京都の予算で、区として東京都の予算の活用のご予定というのはあるのか尋ねました。","respondent":"菅野高齢者福祉課長","answer":"具体的な補助対象経費としましては、熱中症の予防担当者による個別訪問等の実施や、避暑シェルターの設置。在宅の独り暮らしの高齢者や高齢者世帯の熱中症予防に対応するため、そういった事業のより充実したものに、その補助金も充てたいと考えています。","id":"exchange-043"},{"speaker":"筒井委員","kind":"意見","question":"認知症高齢者支援事業についてに移りますけれども、高齢者の６人に１人が認知症ということで、この対策・対応というのは急務かと思います。こうした状況を受けて、区の対応を説明を求めました。","respondent":"樫村高齢者地域支援課長","answer":"それから２点目の認知症検診支援事業につきましては、こちらは区でも都の補助金を活用しまして既に実施しています。区では令和９年４月策定に向けて、当然、都の計画につきましても参考にしながら進めてまいりたいと考えています。","id":"exchange-044"},{"speaker":"筒井委員","kind":"質問","question":"現状、既に高齢者に対する対応はできていると思うのですけれども、認知症というのは、予防がこれから大事になるかと思います。健康課としっかり連携していって、もう４０代からの認知症予防ということを呼びかけるべきだと思うのですけれども、その点はいかがお考えか尋ねました。","respondent":"樫村高齢者地域支援課長","answer":"高齢者地域支援課で既に、頭の元気度チェックという事業を実施しておりまして、引き続き充実した認知症施策となるように取り組んでまいりたいと考えています。","id":"exchange-045"},{"speaker":"高橋（伸）委員","kind":"質問・要望","question":"２８５ページ、病児・病後児保育委託、病児保育についてお伺いします。医療機関への積極的な働きをこれまでも要望してまいりました。","respondent":"染谷保育施設運営課長","answer":"医療機関併設型と保育所併設型とそれぞれありますが、医療機関併設型につきましては現状、４施設となっております。今年度１施設、現在２施設となっておりまして、区内合計６施設の病児保育施設となっています。","id":"exchange-046"},{"speaker":"高橋（伸）委員","kind":"意見","question":"これまでの、課長をはじめ、所管のご努力に敬意を表したいと思います。偏在も解消されたと私は理解しておりますけれども、それでよろしいのか、ご見解をお願いしたいと思いますとの意見を述べました。","respondent":"染谷保育施設運営課長","answer":"東京品川病院と旗の台内科・救急クリニックの開設により、一定程度、是正されたものと考えているところです。一定満たされていると考えているところですので、今後はより地域バランスに留意しながら、必要に応じて開設支援を行ってまいりたいと考えております。","id":"exchange-047"},{"speaker":"高橋（伸）委員","kind":"質問","question":"これは、保育所としては同じような規模であります家庭的保育事業・小規模保育事業には、区立連携保育園による支援があるとお聞きいたしました。そこで、保育に関する連携というのですか、それを簡単にご説明をお願いしたいと思います。","respondent":"染谷保育施設運営課長","answer":"今の小規模保育事業所との部分の話ですけれども、０から２歳のお預かりを頂いた後に、一定の定員数を連携の公立園に設けることで、その後の保育にスムーズに連結できるような体制を取っている内容のものになってあります。","id":"exchange-048"},{"speaker":"高橋（伸）委員","kind":"質問・要望","question":"品川区でも、区の保育士研修に、病児保育所の保育士も参加できる体制を検討すべきと私は考えております。この取組によって、ぜひこのネットワークの構築をしていただきたいのですけれども、ご見解を説明を求めました。","respondent":"染谷保育施設運営課長","answer":"充実した安定した研修は、人材確保にもつながるという側面がありますので、そういったところをご活用いただければと考えております。区民の方、新規開設施設にとっては、そういう情報交換ができるようなネットワークづくりなども進めていければと考えております。","id":"exchange-049"},{"speaker":"新妻委員","kind":"質問・要望","question":"品川区での対応を知りたい場合のために、区の問合せ先も明記するよう要望いたしますが、見解を伺います。さらに研修が受けられる体制を整備してほしいという要望に対して、新年度の予算に反映され、実施されることを伺います。","respondent":"松山障害者支援課長、佐藤保育事業担当課長、染谷保育施設運営課長","answer":"私からは、電話リレーサービスのホームページの内容についてお答え申し上げます。そのホームページ情報につきましては… 仮に補助制度を実施するとなった場合ですが、全員にということで行きますと、２億円を超えるような予算措置が必要ではないかと考えています。… 今やっている研修から少し内容を変えまして、１５分単位で実施可能な、ウェブを活用した研修の導入を予定しております。…","id":"exchange-050"},{"speaker":"新妻委員","kind":"確認","question":"ただいま、もし具体的に実施をする場合、２億円を超える予算額とお伺いいたしました。そこを区側でしっかりと見ていただいて、使える支援かどうかという確認も、また引き続きお願いしたいと思います。","respondent":"佐藤保育事業担当課長","answer":"一方で、実施されている区もあるというのは把握しています。こちらの制度に関しては、２３区の中でも上位の補助額になっているのではないかと考えているところです。","id":"exchange-051"},{"speaker":"新妻委員","kind":"意見","question":"様々な考え方があると思いますが、先ほども朝の食の支援で、朝食を食べていない子どもたちが一定程度いるというようなこともありました。その点も踏まえて、また幼稚園での給食費の無償化も、引き続き検討をお願いいたしますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-052"},{"speaker":"のだて委員","kind":"質問・要望","question":"私からは、２５９ページのすまいるスクール職員給与費に関わって、２６５ページの新条例制定検討経費（こどもの権利条例）について伺います。すまいるスクールに初めて着任する職員のところには、ぜひ複数配置してほしいと求めましたが、いかがか尋ねました。","respondent":"上野子ども育成課長","answer":"サポート体制ですけれども、ベテランの再任用職員、会計年度任用職員によるフォローを含めたサポートを実施してまいることを予定しております。複数配置につきましては、会計年度任用職員によるサポート等も検討してまいります。","id":"exchange-053"},{"speaker":"のだて委員","kind":"質問・要望","question":"ブロック長のいるすまいるスクールは複数配置にするよう求めますが、いかがでしょうか。複数配置にする際に、１人当たりの予算額を伺いたいと思います。","respondent":"上野子ども育成課長","answer":"ブロック長の職場における会計年度任用職員の配置につきましては、今後、実態に合わせて検討してまいります。会計年度任用職員１名配置による人件費になりますけれども、５２１万円となっております。","id":"exchange-054"},{"speaker":"のだて委員","kind":"質問・要望","question":"特別支援が必要な子が多いところには、すまいるスクールの実情に見合ったサポーターの配置を求めますが、いかがでしょうか。場所の確保なども必要だと思いますので、そうした施設的な改善もしてほしいと求めましたが、いかがか尋ねました。","respondent":"上野子ども育成課長","answer":"特別支援サポーターですけれども、令和７年度につきましては、令和８年度は１５か所のすまいるスクールに配置してまいる予定としております。落ち着いて遊ぶためのトイスロープなどの物品購入も予定しておりますので、引き続き、対応を進めてまいります。","id":"exchange-055"},{"speaker":"のだて委員","kind":"質問・要望","question":"それは、１５人配置ということでいいのか伺いたいのと、それがしっかり適切に実情に見合った配置になっているのか。足りないという声があるので、ぜひ増やしていただきたいと思うのですけれども、いかがか尋ねました。","respondent":"上野子ども育成課長","answer":"特別支援サポーターの配置箇所ですけれども、今年度の実態を踏まえた上での増員という形となっております。派遣期間につきましても、年間を通じた派遣という形で拡充しています。","id":"exchange-056"},{"speaker":"のだて委員","kind":"質問・要望","question":"すまいるスクールの委託料の増額をしてほしいと求めましたが、いかがでしょうか。子どもの命と安全を守っている指導員の役割をどのように捉えているのか、伺います。","respondent":"上野子ども育成課長","answer":"区では放課後児童支援員等処遇改善事業を実施しておりまして、令和３年度から処遇改善を行っている事業者に対して補助金を交付しております。そのため、区としてはこの選定過程を通じ、適切な委託内容が定められていると考えておりまして…","id":"exchange-057"},{"speaker":"のだて委員","kind":"質問・要望","question":"先日、２月の子ども若者応援セミナーに参加させていただきまして、とてもよかったです。ぜひ、それも含めてやってほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-058"},{"speaker":"こしば委員","kind":"質問","question":"私からは、２９５ページ、生活保護についてお伺いします。厚生労働省の方針に基づく追加支給というものを、まず当時の受給者に対します追加給付における品川区の対応について、ご説明ほしいと求めました。","respondent":"豊嶋生活福祉課長","answer":"１２月１９日に自治体向けの説明会を行いまして、何度か説明会が行われ、修正に至って今に至っております。夏ぐらいから支給を開始できるように、今、準備を進めているところです。","id":"exchange-059"},{"speaker":"こしば委員","kind":"質問・要望","question":"確認なのですけれども、こちらはもう間違いなく国から入ってくる。国から入ってくるという認識でいいのかということと、およそ品川区の対象となる方の人数について教えてほしいと求めました。","respondent":"豊嶋生活福祉課長","answer":"国が４分の３、自治体が４分の１となっておりますので、それに向けて準備を進めているです。それを踏まえまして計算をしたところ、品川区はおよそ７,７００世帯の方が対象ということで、現時点で計算ができております。","id":"exchange-060"},{"speaker":"こしば委員","kind":"質問・要望","question":"７,７００世帯ということで、その分の事務の負担が大変大きくなるという、また１つの課題かとも思います。ケースワーカーですと、区で今回の追加給付における課題点というのはどのように認識されているのか、教えてほしいと求めました。","respondent":"豊嶋生活福祉課長","answer":"平成２５年８月以降の受給の金額が対象となってはいるのですけれども、品川区は令和元年にシステムのリプレースを行いまして、手元にありません。皆さんのお力を借りながら、なるべく速やかに支給できるように、区としては準備を整えていきたいと考えております。","id":"exchange-061"},{"speaker":"こしば委員","kind":"質問","question":"入り口の質問にもなろうかとは思うのですけれども、窓口業務のところで大変様々なご苦労をされているという、課題があると聞いております。受給者の方々の特性や特徴といいますか、変わってきているところもあるかと思いますが、その辺の肌感覚について教えてほしいと求めました。","respondent":"豊嶋生活福祉課長","answer":"いろいろな多方面の方と連携しながら、その方にとって一番いい対応を、みんなで協力して対応しているというのが現状です。まずは職員の安全を第一に考えつつも、消防署の方を含めて連携を取りながら、適切な対応を現在取っているです。","id":"exchange-062"},{"speaker":"こしば委員","kind":"質問・要望","question":"職員の方々総出で、警察のＯＢの方のお話ということもお伺いしました。要望だけさせてほしいと求めましたけれども、生活保護のしおりというのが、区のホームページにも載っております。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-063"},{"speaker":"中塚委員","kind":"提案","question":"２５７ページの高齢者・障害者の家具転倒防止対策、２５１ページの高齢者福祉施設運営費より、介護施設の停電対策をそれぞれ伺います。昨年の予算特別委員会でも取り上げましたが、改めて提案いたしますが、いかがか尋ねました。","respondent":"山下国保医療年金課長","answer":"確かに医療や介護は、生活の基礎となる行政サービスに該当し得るものになってこようかと考えています。現在、相互扶助の観点から、その負担を分かち合う仕組みになっているものと認識しています。","id":"exchange-064"},{"speaker":"中塚委員","kind":"質問・要望","question":"相互扶助というお話もありましたけれども、今、子どもの医療費はここまで無償化が広がっているわけですから、なぜ高齢者ができないのかなと思います。ここで医療サービスと触れておりますが、高齢者医療の無償化がなぜできないのか、改めて伺いたいと思います。","respondent":"山下国保医療年金課長","answer":"できることに取り組んでいくということで、終活支援サービスなどについて、所得制限なく無償化というところを施政方針でもお示ししているところです。併せて施政方針でお伝えしておりまして、結果として、高齢者の医療・介護の負担軽減を図ってまいりたいと考えています。","id":"exchange-065"},{"speaker":"中塚委員","kind":"提案","question":"そこまで述べているわけですから、できる理由を見つけていただきたいと、強く求めておきたいと思います。なぜこの高齢者・障害者の家具転倒防止だけ、改めて改善してほしいと求めましたが、いかがか尋ねました。","respondent":"樫村高齢者地域支援課長","answer":"必要なところから、まずは２万円の上限はありますけれども、無償化に踏み切ったところです。幅広い人たちが支援を必要としていらっしゃるということは区としても認識していますので、対象の拡大について検討してまいりたいと考えています。","id":"exchange-066"},{"speaker":"中塚委員","kind":"質問・要望","question":"もしかしたら日常的だったかもしれませんけれども、ぜひみんなが対象になるように、よくご検討いただきたいと要望だけしておきたいと思います。東京都の補助もあると伺っておりますけれども、ぜひ区の独自支援、補助の上乗せなどを検討していただけないかと思いますけれども、いかがか尋ねました。","respondent":"菅野高齢者福祉課長","answer":"今後建設予定の小山台住宅跡地の高齢者施設等においては、停電時であっても、７２時間の稼働を想定した非常用電源設備の整備を予定しております。こうした制度の活用も含めて、停電・災害時等において施設機能が維持できるような取組を進めていくべきだと…","id":"exchange-067"},{"speaker":"中塚委員","kind":"質問・要望","question":"このことで、落雷や台風、暴風、停電などになるリスクも高まっていると思います。ぜひ東京都の補助制度に、区の上乗せ支援を考えていただきたいと思うのですけれども、いかがか尋ねました。","respondent":"菅野高齢者福祉課長","answer":"非常用電源については、クーラー以外にも、生命維持装置や通信、照明など、いろいろな場面もありますので、そういったことも含めて研究してまいります。","id":"exchange-068"},{"speaker":"あくつ委員","kind":"提案","question":"一般質問で、工事費込みでの自己負担のない助成というものを要望しましたが、これはできるのかどうか。相談して、見積りを確認の上、先立つものがなくても前払いでぜひこの制度をお願いしたいと思いますが、いかがか尋ねました。","respondent":"豊嶋生活福祉課長","answer":"ご協力いただける店舗があれば、そうした手法を取って進めていければと、現在考えているところです。その辺りも対象に含めるように、我々の中で今、検討を進めているです。","id":"exchange-069"},{"speaker":"あくつ委員","kind":"質問","question":"時間があまりないのですけれども、保育入園調整費ということで、お子様が３月生まれのために制度上不利になっているということを区民相談で伺います。ただ品川区民の方が困っているので、その辺りについて寄り添うような具体的な対応をお願いしたいと思うのですけれども、いかがか尋ねました。","respondent":"芝野保育入園調整課長","answer":"２点ほど、ご質問を頂きました。３月の入園受付は行っていませんというのをしっかり書かせていただいて、それプラス、そこも分かりやすい形で進めていきたいと考えております。","id":"exchange-070"},{"speaker":"吉田委員","kind":"質問・要望","question":"手話通訳者への支援を求めての質問です。ここからは要望になるのですけれども、やはり必要ではないかと思うのですけれども、その点についてお考えを伺いたいと思います。","respondent":"松山障害者支援課長","answer":"人件費、来年度から助成金額を２,５００円から４,０００円に引き上げまして、２分の１補助をしております。あくまでも予防ということですので、今のところ、治療ではなく、まずは健診の周知はしておりますが、より積極的な周知に努めたいと考えております。","id":"exchange-071"},{"speaker":"吉田委員","kind":"質問・要望","question":"品川区でもぜひというご要望が通ったのは本当によかったと考えていますが、ぜひその辺は積極的に活用されるように促してほしいと求めました。費用に差があるので、できたら高いほうに合わせていただきたいというご要望を伺ったのですけれども、その点についていかがか尋ねました。","respondent":"松山障害者支援課長","answer":"現在、聴覚障害者の方のご協力なしには、なかなか事業が進みませんので、必ずご協力は頂いているところです。そういったものの統一がされていないのは事実ですので、区の庁内関係各課、もう少し統一が図れるように調整してまいりたいと考えております。","id":"exchange-072"},{"speaker":"吉田委員","kind":"質問・要望","question":"それで、生活者ネットワークとしては、「だったら今、在宅介護支援センターという名称を、地域包括支援センターに改めるべきではないですか。そこはどうも矛盾していると思いまして、区民の方にも十分分かるように周知されるという理解でよろしいか尋ねました。","respondent":"菅野高齢者福祉課長","answer":"再三、区内２０か所の在宅介護支援センターは現在はサブセンターという位置づけとなっておりますので、ただいま在り方検討を進めております。地域に設置した際には、名称についても、地域の方が迷わずに相談できるような名称を考えてまいりたいと考えています。","id":"exchange-073"},{"speaker":"吉田委員","kind":"質問","question":"迷わないような名称ということでしたが、地域包括支援センターだというのであれば、地域包括支援センターと書かれないと迷うと思いますけれども、いかがか尋ねました。","respondent":"菅野高齢者福祉課長","answer":"地域包括支援センターのサブセンターの２枚看板となっておりまして、そして地域包括支援センターのサブセンターという名前になっております。あんしんすこやかセンターなどといった、いろいろな名前をつけているところがありますので…","id":"exchange-074"},{"speaker":"せお委員","kind":"質問・要望","question":"２６９ページ、時間がありましたら２６３ページ、すまいるスクール運営費について細々とお伺いします。まずはこの課題を知っていただくことと、今後ぜひ区としても支援を検討していただきたいのですけれども、見解を説明を求めました。","respondent":"松山障害者支援課長","answer":"私から、社会福祉協議会の紙おむつ支給事業における取扱い商品についてお答え申し上げます。現在は、取扱い商品として可能かどうかというところを、社会福祉協議会を通じて業者に確認してもらうよう働きかけてまいります。","id":"exchange-075"},{"speaker":"せお委員","kind":"提案","question":"区の職員がどのようなボランティアをしたいかを引き出したり、こういったボランティアがあると提案したりして補助してくれたと聞いております。全庁的に意見を集約して、それを子どもたちに提案できるような仕組みをつくってはいかがかと思いますが、見解を説明を求めました。","respondent":"柏木子育て応援課長","answer":"来年度は早期の周知を実施、それと申請期間を十分に確保してまいります。地域の持続的発展への自主的な貢献意識の醸成の観点から、奨学生本人が自ら探すこととはしていますが、委員の提案等も踏まえて検討してまいります。","id":"exchange-076"},{"speaker":"せお委員","kind":"質問・要望","question":"気になるご家庭など、ふだんから子どもたちやご家族に接している方からの情報提供などは現在どれくらい来ていますでしょうか。さらに、日常、子どもたちやご家族に接している方が、気になる際に連絡できる窓口というのを要望したいのですが、見解を伺います。","respondent":"吉野子ども家庭支援センター長","answer":"委員のご指摘の部分ですけれども、こちらは先ほどご答弁させていただきましたけれども、令和８年度に作成する予定でおります。学校や地域団体といったところに情報を多角的に集めて、迅速な対応につなげていきたいと考えております。","id":"exchange-077"},{"speaker":"せお委員","kind":"意見","question":"子ども家庭支援センターでの、虐待などを未然に防ぐという役割は大変重要で、喫緊の課題だとも感じています。子ども家庭支援センターの動きによって一時保護が減らせたとなるような取組といったところをどうお考えか、一言頂ければと思いますとの意見を述べました。","respondent":"吉野子ども家庭支援センター長","answer":"やはり１課だけではなかなかできない部分というのは多くありますので、それから関係機関と連携を図りまして、来年度は地域のネットワークを何とか構築していきたいと考えております。","id":"exchange-078"},{"speaker":"せお委員","kind":"質問・要望","question":"現状の３か月単位というのはどういうことなのか、具体的に教えていただきたいということと、収拾がつかない状況を毎年見ております。特にその時期への対策強化みたいなところはどのように考えているか、説明を求めました。","respondent":"上野子ども育成課長","answer":"特別支援サポーターのお問合せですけれども、特別支援サポーターを配置しまして、延長かどうかを確認して対応しているです。新１年生が入られたときの対応ですけれども、引き続き、慣れないお子様の対応については慎重に対応してまいります。","id":"exchange-079"},{"speaker":"せお委員","kind":"意見","question":"本当に４月の初めというのが、安全面も気にしながら、子どもたちの活動、思いなどにも配慮していかなくてはいけないというところで大変だとは思うのですけれども、ぜひともそこの強化なども引き続きお願いしたいと思いますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-080"},{"speaker":"大倉委員","kind":"質問・要望","question":"２７９ページ、乳児等通園支援事業利用料助成、２８１ページの保幼小ジョイント事業について伺えればと思います。私立の実施状況などが分かれば教えてほしいと求めました。","respondent":"佐藤保育事業担当課長、染谷保育施設運営課長","answer":"私から、乳児等通園支援事業についてご説明します。試行的事業を令和５年度から実施してございまして、希望が重なった場合には各園において時間等を設定していただいているという状況でございました。 私立保育園が４３園、幼稚園が１０園というような連携の実績となっておりまして、学校との関係というところでの話というのは聞いているところです。まずはどういう形で連携していくかを話し合うための協議会を設定するなどといった、今…","id":"exchange-081"},{"speaker":"大倉委員","kind":"質問・要望","question":"これはおのおの選択できるという認識でいいのでしょうかということと、区としての、これについての課題感を教えてほしいと求めました。どうしていくかという流れの中で、ぜひうまく進めていってほしいと求めましたが、何かお考えがあったら教えてほしいと求めました。","respondent":"佐藤保育事業担当課長、染谷保育施設運営課長","answer":"本格的に事業を実施されていくに当たりまして、利用ニーズというのを勘案しながら、適切な時間というのを検討していきたいと考えております。職員の採用や… 学校側としては複数園との実施をするに当たっての負担というのはやはりあるという声は聞いておりますし、やれる範囲でうまく負担感を少なくというところを、今後検討していければと考えているところです。","id":"exchange-082"},{"speaker":"大倉委員","kind":"質問・要望","question":"昨年９月からは第一子も無償化が始まって、９月以降は受入れがかなり増えてきていて、様々受入れを進めていってほしいと求めました。ぜひ。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-083"},{"speaker":"やなぎさわ委員","kind":"質問・要望","question":"議員になって、もう３年がたちまして、今まで取り上げてこなかった初めての課題をここで提起したいと思います。区内の送迎を伴う介護サービスを提供している介護事業所の数を教えていただきたいのですが、いかがか尋ねました。","respondent":"菅野高齢者福祉課長","answer":"区内で送迎のサービスを実施している介護事業所の数ということでお話がありました。ショートステイなどでサービスを提供しておりまして、約８８、９０弱というところで事業所数は認識しております。","id":"exchange-084"},{"speaker":"やなぎさわ委員","kind":"質問","question":"同じように送迎しているような障害福祉のサービスが５０施設ぐらいあるので、もっと多いということになってきます。質問なのですけれども、研修等、何か義務づけられているものがあるのかお伺いします。","respondent":"菅野高齢者福祉課長","answer":"ご質問の件につきましては、介護事業所におきましては、特にバスやタクシーのような二種免許は必要なく、普通自動車免許で運転できると認識しておりますし、特にそれに伴う研修等については、保険者等に課せられた義務はないと認識しております。","id":"exchange-085"},{"speaker":"やなぎさわ委員","kind":"質問","question":"これはなぜかといいますと、半日型の場合、送迎が３回あることになります。そこでお伺いしたいのですが、区として送迎ドライバーの方に関する助成制度や補助制度というのは現在あるのかどうか、説明を求めました。","respondent":"菅野高齢者福祉課長","answer":"区としては指定権者として、適切な安全管理体制が確保されているか確認等をしていくというふうに捉えております。そういったことを前提としていますので、委員ご指摘の安全運転教室などといったときの助成金といったサービス等は、今のところ、ございません。","id":"exchange-086"},{"speaker":"やなぎさわ委員","kind":"提案","question":"区民の命を守るための対策が、私は必要だと感じています。提案なのですけれども、ペーパードライバー研修は１回七千円、区のご見解をお伺いしますとの意見を述べました。","respondent":"菅野高齢者福祉課長","answer":"安全な送迎のための様々なご提案を頂きました。区としましては、介護人材の確保というところがすごく今大事だと考えていますので、他自治体の実態把握もしながら検討していきたいと思います。","id":"exchange-087"},{"speaker":"やなぎさわ委員","kind":"質問・要望","question":"業界用語ですけれども。そして介護業界の人手不足を解消する、そして現場の負担を減らすという意味で、ぜひともこういったことを前に進めていってほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-088"},{"speaker":"塚本委員","kind":"提案","question":"昨年の一般質問で、常に障害者の医療ショートステイということでベッドを確保できるということで、提案させていただきました。こちらの事業の活用の状況はどうなのかというところでお伺いしますとの意見を述べました。","respondent":"松山障害者支援課長","answer":"委員ご提案の東京都医療型短期入所事業所を開設支援する事業者からも医療機関に説明していただくなど、区と一緒に働きかけを行ってまいりました。一方で、区の事業としては指定を受ける必要がないため参入しやすいということで…","id":"exchange-089"},{"speaker":"塚本委員","kind":"提案","question":"やはり潜在的なニーズというのですか、なかなかうまくいかなくて使えないかなというような方もいらっしゃるということは常々伺っておりますので。１万１,０００ポイント付与してもらって、やり方がよく分からないということでの問合せをよく伺っておりますので、いかがか尋ねました。","respondent":"樫村高齢者地域支援課長","answer":"大きく２点ご質問を頂いたと認識しております。それから２点目の、区が実施しているスマホよろず相談等の中で問合せがあれば、個別に操作方法を教えるなどの支援を行っているところです。","id":"exchange-090"},{"speaker":"塚本委員","kind":"質問","question":"特に今言った２０代・３０代のあたりで大変多いということを、この事業が少しでも区民の方々の役に立てばということで、大変大事な事業だと思います。来年度、オンラインカウンセリングの部分での拡充というのはどのようになっているのか、お伺いしたいと思います。","respondent":"東野福祉計画課長","answer":"孤独に悩んでいる方に対しまして十分なサポートができるように、事業は展開していきたいと考えております。金額でいきますと、この事業では約８０万円ぐらいの増というような形となっております。","id":"exchange-091"},{"speaker":"塚本委員","kind":"意見","question":"予算の増額、ありがとうあります。若者支援コーディネーター等もありますので、こういったところとの連携なども含めて、ぜひ支援をとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-092"},{"speaker":"鈴木委員","kind":"質問・要望","question":"２４５ページの重症心身障害児（者）在宅レスパイトについてと、２５１ページの在宅介護支援センターについて伺いたいと思います。それから、在宅レスパイトを利用している障害児者それぞれの実人数と、１人当たりの月の時間数を教えてほしいと求めました。","respondent":"松山障害者支援課長","answer":"初めに無償化の関連ですけれども、無償化につきまして、この間、検討はしてまいりました。したがいまして、次年度以降に向けて、引き続き無償化について検討してまいります。","id":"exchange-093"},{"speaker":"鈴木委員","kind":"質問・要望","question":"２６か所もあるわけですから、各事業所にも確認していただいて、ぜひ取り組んでほしいと求めました。理念からして、通所サービスに続いて無償化していくべきだと私は考えますけれども、その点についても区の考え方を伺います。","respondent":"松山障害者支援課長","answer":"先ほどご説明申し上げました、それに対して区としての支援は何が必要なのかということを具体的に確認して、解決を図っていきたいと考えています。無償化という考え方としては、まずは供給の確保に、区としては全力を挙げて取り組んでまいります。","id":"exchange-094"},{"speaker":"鈴木委員","kind":"質問・要望","question":"そのためにも私は、現状の直営の地域包括支援センターの事業評価の公表を求めたいと思います。積極的に地域住民に対して公表すべきと、ぜひお願いしたいと思いますが、いかがか尋ねました。","respondent":"菅野高齢者福祉課長","answer":"直営の地域包括支援センターということになっておりますので、こちらで確認して、国に提出するというような位置づけとなっております。地域に地域包括支援センターを設置した際には、そういったことを含めて、地域包括支援センター見直しの中で図っていきたいと考えています。","id":"exchange-095"},{"speaker":"鈴木委員","kind":"質問・要望","question":"今でもそういうふうに事業評価しているというのであれば、ぜひこれを公表していただきたいのです。それは課題を明確にして次に充実させるためにも、ぜひとも必要だと思いますので、ぜひご検討ください。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-096"},{"speaker":"須貝委員","kind":"質問","question":"平凡な家族関係が崩れていますが、事業部としてはどのように対応しているのでしょうか。説明を求めました。","respondent":"吉野子ども家庭支援センター長","answer":"そういったケアラーの方の把握に努めたいと考えております。まず介護のセンターといった事業者などといったところに働きかけをしまして、潜在的な方たちの洗い出しをまず行っていきたいと考えております。","id":"exchange-097"},{"speaker":"須貝委員","kind":"質問","question":"そういう問題ではないのではないですか。緊急の対応策ということを考えないでどうするのか尋ねました。","respondent":"吉野子ども家庭支援センター長","answer":"緊急の対応策なのですけれども、まずはその方の実態というところを把握させていただいて、その方が何を求めているのかというところを、丁寧に、まずお話をさせていただいて、その方が何を必要としているのかというところも含めてヒアリングをさせていただきたいと考えています。","id":"exchange-098"},{"speaker":"須貝委員","kind":"質問・要望","question":"そういう方たちはどうすればいいのですか。必要とするのは、この方たちをどこかに預かってくれれば、ヤングケアラーでも、ワーキングケアラーの方も、みんな助かるのではないか尋ねました。","respondent":"吉野子ども家庭支援センター長","answer":"家事育児支援訪問事業を行ったり、あとチャーム・ケア・コーポレーションと協定を結びまして、支援できるような形のものも協定を結んでおります。チャーム・ケア・コーポレーションが持っております施設が区内に５か所ありますので…","id":"exchange-099"},{"speaker":"須貝委員","kind":"質問","question":"そのような仕組みをつくったらどうでしょうか。そういう対応も必要ではないのか尋ねました。","respondent":"吉野子ども家庭支援センター長、菅野高齢者福祉課長","answer":"先ほどとまた同じ答弁になってしまいますが、家事育児等の訪問の支援事業も行っております。それから、家庭支援という形での訪問介護も行っておりますので、場合によってはそちらも利用して対応していきたいと考えております。 先ほども申し上げましたが、区内には在宅介護支援センターが２０か所あります。そういう方につなげるようなことが、体制ができておりますので、ご案内していただければと思います。","id":"exchange-100"},{"speaker":"須貝委員","kind":"質問","question":"何しろ困っている方が、これからますます増えるはずですから、何とか対応するようにしてください。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-101"},{"speaker":"田中委員","kind":"質問・要望","question":"２３８ページの障害者支援費に関して、時間があれば２４８ページ、高齢者福祉費についてお伺いしたいと思います。そういう流れがある中で、確認も含めてですが、児童相談所が区に移管されました。","respondent":"柴田子ども施策連携担当課長","answer":"委員からご案内がありましたとおり、区が令和６年１０月に児童相談所を開設いたしまして、その際、複数の事務が都から移管されてまいりました。児童福祉法に基づく形で実施することとなるのですが、国が７％のように、事業者からはお話を聞いているところです。","id":"exchange-102"},{"speaker":"田中委員","kind":"質問・要望","question":"今後の計画なども伺う中で、令和１１年の完成に向けて段階的に建設が進められてまいります。定員４８名に対して、外部にグループホームというような形で施設を設けながら、段階的に建設を進めるというお話も伺いました。","respondent":"柴田子ども施策連携担当課長","answer":"その際に、近隣の一戸建ての家などを借りて開く子どもたちの居場所、生活場所になるのですけれども、こちらについては区が主体となって補助を出す。もちろん国から補助金という形で２分の１の計上もありますので、施設の、そして子どもたちのために検討を進めてまいります。","id":"exchange-103"},{"speaker":"田中委員","kind":"質問・要望","question":"そのときもいろいろ伺いましたが、そしてより身近な自治体がそれを受けるということですから、またしっかり補助も出していただいて。よりきめ細かな取組をぜひ行ってほしいと求めましたが、お考えといいますか、方針をお聞かせほしいと求めました。","respondent":"柴田子ども施策連携担当課長","answer":"地域連携棟という建物を、今、造っていくというような計画も伺っているところです。こちらは、地域の子どもたち、それから大人にも使っていただけるようなスペースをつくっていくということも検討されているようですので。","id":"exchange-104"},{"speaker":"田中委員","kind":"質問・要望","question":"これまで児童相談所の移管も含めて、里親支援ということにも区で対応されていると思いますが、里親制度においての区の移管後の実績はどうでしょうか。お伺いします。","respondent":"柴田子ども施策連携担当課長","answer":"先ほどお話ししたとおり、区に都から事務が移管される際、里親に関する事務というものも都から区に移ってまいりました。令和６年１０月の児童相談所設置後、これからも、さらにそうした方々が増えるような取組というのをしていきたいと考えています。","id":"exchange-105"},{"speaker":"田中委員","kind":"質問・要望","question":"これは令和３年以降、障害者の方のホームページに紹介されているわけで、健常者の方がなかなかそこに至らないかと思います。私は、ぜひそれは、もっと広く区民の皆さんに知ってもらうための工夫が必要だと思いますが、いかがか尋ねました。","respondent":"松山障害者支援課長","answer":"委員ご提案のヘルプマーク、ヘルプカード、ヘルプカードホルダーのホームページについてです。支援を必要とする方々の理解促進を深めるために、東京都とも連携を取りながら、ホームページの充実を図ってまいりたいと考えております。","id":"exchange-106"},{"speaker":"田中委員","kind":"提案","question":"提案がありまして、より理解してもらうためにということで、７月２０日をヘルプマークの日にしてくれないかという委員会質疑がありました。この実効性が高まるわけですから、連携するような取組をぜひ行ってほしいと求めましたが、今現在のお考えを説明を求めました。","respondent":"松山障害者支援課長","answer":"７月２０日をヘルプマークの日に定めた経緯をお伺いして、非常に感銘を受けました。区民の方に広く周知していきたいと考えていますので、ホームページの充実を図り、７月２０日のヘルプマークの日を広めていきたいと考えています。","id":"exchange-107"},{"speaker":"田中委員","kind":"質問・要望","question":"ぜひお願いしたいと思います。そういうところの通行もせざるを得ないのですが、そこはぜひ、警察・学校等との連携を持って、介護施設充実に努めてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-108"},{"speaker":"西本委員","kind":"質問・要望","question":"誰のために何を求めているのでしょうか。それで朝食支援になるのか尋ねました。","respondent":"上野子ども育成課長","answer":"特別支援児の対応としましては、特別支援の知見を有する福祉職を複数名配置しまして、対応の充実などについて検討を進めまして。児童の７％が朝食を欠食しているという国の調査を基に、朝食支援によりまして、児童の健全な成長を支援するという目的で事業を実施しているものです。","id":"exchange-109"},{"speaker":"西本委員","kind":"質問・要望","question":"仕入先がコンビニと提携していると思うのですけれども、これは継続という形で、令和８年度も同じところでやるのでしょうか。お配りして食べさせるということになると思うのですけれども、これは学校の中で起きていることなので、学校との連携はどうなっているのか尋ねました。","respondent":"上野子ども育成課長","answer":"試行実施の内容を精査しまして、令和８年度、どのように進めていくかは検討してまいります。社会全体で子育てを支えるという考えの下に実施しているものでございまして、そちらについて選択肢を提供するという考えの下に実施しているものです。","id":"exchange-110"},{"speaker":"西本委員","kind":"質問・要望","question":"この朝食支援というのは、なぜ使用しているのかというのは、これからしっかり調べていただいて、福祉的なサポートが必要であればそちらにしていただきたいし、やはり朝食は親の責任で食べさせてください。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-111"},{"speaker":"こんの委員","kind":"質問","question":"２９１ページ、５７１ページ、介護給付費等準備基金積立金をお聞きしたいと思います。今後３年ごとに見直しを、だから令和９年に見直しが図られることにはなると思うのですけれども、その辺の見解をお聞きしたいと思います。","respondent":"松山障害者支援課長、染谷保育施設運営課長、佐藤保育事業担当課長、菅野高齢者福祉課長","answer":"私からは、重度障害者等就労支援特別事業の実績と評価についてお答えいたします。そして、働く意欲のある障害者の方を日常的に支援する… 一番短い時間帯で、実施時間が１７時までのところから、一番長いところで１９時半までとなっております。それから無資格ではありますけれども子育て… 当然、どちらの園も配置していただいていると伺ってありますが、おおむね１名から２名程度は配置していただけているのではないかと認識しています。… 今後のことにつきましては、介護サービスの見込みに応じまして…","id":"exchange-112"},{"speaker":"こんの委員","kind":"質問","question":"これは、周知はどうなっているのでしょうかというところが気になっているわけなのですけれども、いわゆる周知をどこまで行っているのか。そうした社会保障の仕組みを、品川区から築いていってほしいと思いますが、いかがか尋ねました。","respondent":"松山障害者支援課長、染谷保育施設運営課長、佐藤保育事業担当課長","answer":"昨年６月に地域産業振興課と連携いたしまして、中小企業家同友会品川支部向けの説明会で、この事業について周知させていただきました。今後とも… 子育て支援員になりますと、５時間で週５日、月額１７万２,７２２円。こちらは、区の会計年度任用職員の報酬の価格設定など… 各園によって状況が違うので、区は必要経費というのをしっかりと考えながら、会計年度任用職員の費用などを参考に設定しています。","id":"exchange-113"},{"speaker":"石田（秀）委員","kind":"質問","question":"５２９ページ、介護保険について伺います。どう考えているのか説明を求めました。","respondent":"菅野高齢者福祉課長","answer":"全ての住民に影響が生じ得る物価高騰等を理由に、厚生労働大臣による是正の要求の指示の対象となり得るといった通知がございました。いわゆる減免３原則というお話もありましたが、適切な介護保険料の賦課徴収および介護保険財政の運営に努めていきたいと考えているところです。","id":"exchange-114"},{"speaker":"石田（秀）委員","kind":"意見","question":"それを高齢者に限定するかどうかとあるけれども、７０歳以上、全員に３万円でも支給すればいいのだ。それでいきなり予算にないというのは、いろいろ話をすると、これは企画経営部に答えてほしいとの意見を述べました。","respondent":"菅野高齢者福祉課長、久保田企画経営部長","answer":"私からは介護保険料の減免についてお答えします。引き続き、こういった東京都の通知等を踏まえて、介護保険料については適切な保険料を算定して、徴収することに努めてまいりたいと思います。 たしか、アンケートの内容では９割ぐらいの方がエアコンを設置されているということと、次の施策にどう活かしていくかという検討をしていると。エアコンを設置していないという家庭もありますので…","id":"exchange-115"},{"speaker":"石田（秀）委員","kind":"意見","question":"アンケートは、「どうでしたか」と５年に１回でもやればいいのだから。そこを最後、一言だけとの意見を述べました。","respondent":"久保田企画経営部長","answer":"３万円の支給については、区としては現時点では考えていません。熱中症の見守りも、次の事業としていろいろと考えていきたいと思います。","id":"exchange-116"},{"speaker":"高橋（し）委員","kind":"質問・要望","question":"研修など、安全管理が現場で回っているかという実際の状況を、指導検査時にどういうふうに確認しているでしょうか。年度途中などでも、頻度あるいはどういう指標で把握して、体制不安がある園を重点フォローしていくという仕組みをお持ちか尋ねました。","respondent":"佐藤保育事業担当課長、芝野保育入園調整課長","answer":"園または法人本部にヒアリング等を実施しておりまして、採用状況がどうなっているのかということにつきましては、しっかりと確認しています。そういう場合には… そして、公表の関係ですが、原則３０日以内に改善状況報告書の提出を求めておりまして、併せて改善済みの公表というのを行わせていただいております。ただし…","id":"exchange-117"},{"speaker":"高橋（し）委員","kind":"質問・要望","question":"基準や目的を明示する要綱の規範を、この事業についても整備していく」と言ったのですが、令和８年度中に整備されるのでしょうか。そうでなくて、もう整備するつもりはないのか尋ねました。","respondent":"染谷保育施設運営課長","answer":"保育園のほうで保育所等特別支援保育巡回相談実施要綱と、実施内容等を定めた要綱を、この４月１日付でと考えているところです。","id":"exchange-118"},{"speaker":"高橋（し）委員","kind":"質問・要望","question":"それが、介助員と呼んでいいのかどうですか、お子さんへの支援で配置されている方々の配置の仕方が異なる理由がどう整理されているのかということ。区の基本方針を伺います。","respondent":"染谷保育施設運営課長","answer":"先ほど委員がおっしゃられた話の中で、保育園については、いわゆる集団保育を実施している保育園としての考え方がそういう形になっております。幼稚園に関しては介助員が１人、児童について配置されるという考え方で、実施しているものです。","id":"exchange-119"},{"speaker":"高橋（し）委員","kind":"質問・要望","question":"別の機会でお話しさせてほしいと求めましたが、施設の種別で支援の濃淡というのでしょうか、施設によって異ならないように進めてください。別の機会にお願いします。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-120"},{"speaker":"松本委員","kind":"質問・要望","question":"私からは、２７１ページ、養育費相談支援事業、２３５ページ、民生委員活動経費について伺います。調停や審判に対して補助がないというのは、少し再検討していただきたいと思うのですが、いかがか尋ねました。","respondent":"吉野子ども家庭支援センター長","answer":"こちらに関しましては、区民の方から個別にご相談いただきましたら、個別の対応を行いたいと考えています。まだホームページ等にも記載はしていないのですけれども、こちらは記載して、修正していきたいと考えております。","id":"exchange-121"},{"speaker":"松本委員","kind":"質問・要望","question":"ただ、個人事業主や、あるいは一人社長というか、会社はもう完全に１人で株主になっているような場合というのは、いろいろな抜け穴があります。当区でもこういったニーズの変化に合わせて、強制執行の費用を補助するような取組などについて検討してほしいと求めましたが、いかがか尋ねました。","respondent":"吉野子ども家庭支援センター長","answer":"養育費の確保は、子どもの生活の安定のために極めて重要な民法の改正だったと認識しております。強制執行の申立てに関わる費用は経済負担だということも踏まえまして、世田谷区の事例などを参考に今後検討します。","id":"exchange-122"},{"speaker":"松本委員","kind":"質問","question":"今、今回の先取特権の法改正が出てきたので、離婚のときに離婚協議書を作れるかどうかというのが物すごく大事になってきます。情報の提供はしていただいているかと思うのですが、この４月からの法改正を踏まえて、ここについて今後の方針を伺えればと思います。","respondent":"吉野子ども家庭支援センター長","answer":"今後なのですけれども、改正後の離婚届に関しましては丁寧な対応が必要だと考えております。離婚届を窓口に出す戸籍住民課ですけれども、こちらは情報共有をしながら、それから併せて関連するホームページも修正していきたいと考えております。","id":"exchange-123"},{"speaker":"松本委員","kind":"質問","question":"民生委員についても少しお伺いしたいのが、民生委員はかなり成り手が不足しているというようなことがよく話題になります。この点について、当区での見直しの状況を伺えればと思います。","respondent":"東野福祉計画課長","answer":"それから、他区からのご照会などもありますので、そういったものも対応が必要となっております。令和７年度につきましては１０件ほどの件数がございましたが、こちらにつきましては区の職員が調査対応することにしております。","id":"exchange-124"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"受給者の方が入居されているアパート等が値上がっている状況がどれぐらい広がっているか、区として把握はされているでしょうか、伺います。それと、住宅扶助費の引上げがもう必要だと思うのですが、ぜひ国に求めてほしいと求めました。","respondent":"豊嶋生活福祉課長","answer":"上げないの話や、５万３,７００円の住宅扶助費を何とかしてくれという話は、直接は入ってきてはおりません。もう本当に国で考えるべきものと、こちらも考えておりまして、他区の状況を見ながら適切に対応してまいりたいと考えております。","id":"exchange-125"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"この間は求めてきたところですが、生活保護世帯への夏の電気代を支援して、命を守るエアコン利用を安心してできるようにすべきだと思います。これは区独自でできることですので、法外援護でぜひ実施していただきたいと思うのですが、いかがか尋ねました。","respondent":"豊嶋生活福祉課長","answer":"東京都等々への確認はまず１つ、いわゆる生活保護の言葉で言うと、恐らく冬季加算の相対するお考えかなと考えております。気象状況も大分変わってきておりまして、現時点で区で何かするということは考えてございませんが、国の動向を注視してまいりたいと考えています。","id":"exchange-126"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"都への確認も必要ということでしたので、ぜひ東京都にも要望しながら、区として姿勢を示していただきたいと思っています。具体的にどのサービスの所要量を示すことになるのか、またサービスの所要量をどのように検討するのか、伺いたいと思います。","respondent":"佐藤障害者施策推進課長","answer":"そういったところで進めていくというところ、新年度に向けて様々な事業を予定していますので、そこに対して着実かつ迅速に進めていくです。これは次年度予定しております障害福祉計画の策定委員会等で、関係者の方のご意見も伺いながら…","id":"exchange-127"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"所要量のところは、所要量等調査の仕方を、世田谷区を参考に、障害者施設や利用者の家族など様々関係している方に聞きながら、ぜひ進めてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-128"},{"speaker":"若林委員","kind":"質問・要望","question":"１８歳の壁とは、その方たちが生活介護延長を利用できた実績は、今年度の事業であったでしょうか。個別ケースの検討状況や今後の見通しがあれば、この時点で確認させてほしいと求めました。","respondent":"松山障害者支援課長、佐藤障害者施策推進課長","answer":"個別対応についてですけれども、就労継続支援Ｂ型以外にも、日中一時支援の新たな仕組みを活用して対応したいと思います。今後も個別に丁寧に対応してまいります。 先日の施政方針でもありましたように、予定されているところでは、丁寧に進めていきたいです。今後も継続して懇談の場を設けていって、丁寧にお声をお伺いしまして、施策の充実を図ってまいりたいと考えているところです。","id":"exchange-129"},{"speaker":"若林委員","kind":"質問・要望","question":"そこは本当に改めて確認して、まずは何よりも優先して行っていただきたいというのが１つお願いですので、何かコメントがあれば。２万５,０００円が上限でしたか、今現在で４月１日を前にいろいろ調整していますけれども、頑張ってほしいと求めました。","respondent":"佐藤障害者施策推進課長","answer":"委員がおっしゃるとおり、担当部長に関しましては、全体の連携調整というようなところで、ご意見を聞く場を大切にしたいです。様々な委員会等を含めまして、丁寧にその場を設定して様々なご意見を伺ってまいるように、こちらも調整してまいりたいと考えております。","id":"exchange-130"},{"speaker":"藤原委員","kind":"質問","question":"５５１ページ、介護認定についてお伺いしますが、まず介護認定からお伺いします。こういうことをきちんと質問して、こういう答弁をしますというふうに、調整してくれているのではないのか尋ねました。","respondent":"柏原区長室長","answer":"それに対してこういうふうに答えようというようなところで調整する会議です。こういうことは一回答弁をやめようなどというような打合せをする場ではありませんので、きちんと議論して答弁の調整をしているといった会議です。","id":"exchange-131"},{"speaker":"藤原委員","kind":"質問","question":"きちんと分析していくと言っているのですから。３か月たって、どういう分析をしてどういうふうになったか、教えていただけますか。","respondent":"菅野高齢者福祉課長","answer":"たしか要支援が３、要支援が４.５、要介護が５.５というような割合になっております。そういった対応をさせていただいたところ、全国平均とのバランスも考えながら柔軟には対応していますので、何とぞご理解いただければと思います。","id":"exchange-132"},{"speaker":"藤原委員","kind":"質問・要望","question":"何年後かに再開していただきたいと思っているのですけれども、改めてお伺いします。これから処遇改善をどういうふうに考えていくか、お伺いします。","respondent":"菅野高齢者福祉課長","answer":"令和４年度・５年度に実施した、ふれあいメッセージについて、お話ししていただいてありがとうあります。国でも臨時改定を６月に行うというところで、区だけではなく国も、区としては現場の声をしっかりと聞いて支援をしてまいりたいと思います。","id":"exchange-133"},{"speaker":"藤原委員","kind":"質問・要望","question":"生活福祉も伺うのですけれども、こしば委員が伺っていたので、もっと数があると思うのです。職員のメンタル面は、課長を中心に、どうにかきちんと保つようにしていっていただきたいと思うのですけれども、いかがか尋ねました。","respondent":"樫村高齢者地域支援課長、豊嶋生活福祉課長","answer":"やはりお困りになっていらっしゃる方が多くいらっしゃると認識しておりますので、引き続き丁寧に、寄り添った対応をしていきたいと考えています。さらにこれから高齢者人口も増えていくと認識しておりますので… なので、加算や入院している金額を一件一件読み起こす数が５,３００件あるというようなところで、これはかなり膨大な量になってまいります。もう生活福祉課、組織としてチームとして動いていって…","id":"exchange-134"},{"speaker":"藤原委員","kind":"質問","question":"生活福祉課長、本当に職員のメンタルだけは、毎回こういう質問でお願いしますが、課長が守っていってあげてください。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-135"},{"speaker":"まつざわ委員","kind":"質問","question":"私からは、２５５ページ、認知症高齢者支援事業からお伺いします。品川区として令和８年度の新規事業として助成を開始するという報告がありましたが、事業化した経緯について、簡単にポイントだけ説明を求めました。","respondent":"樫村高齢者地域支援課長","answer":"令和６年１月に施行されました、地域での居場所づくりを通じたものと、交流できる環境を整えることを目的としております。こういった経過を踏まえまして、区としては来年度より活動費用の助成を行うことといたしました。","id":"exchange-136"},{"speaker":"まつざわ委員","kind":"質問","question":"品川区として、当事者の主体の活動といったものが、地域社会にインパクトをどういうふうに与えているのか。こうした居場所が、認知症の進行の抑制やご家族の負担軽減にどのような効果をもたらしていると認識しているのか、お伺いします。","respondent":"樫村高齢者地域支援課長","answer":"そして生きがいや希望を持って暮らすことができるという何よりの好事例であって、地域社会に及ぼすインパクトも大きいと認識しております。居場所による効果についての認識ですけれども、有機的なつながりもできるとともに…","id":"exchange-137"},{"speaker":"まつざわ委員","kind":"質問","question":"昨日のみんなの中でもお話ししていたのですけれども、西大井だけで終わらせてはいけない、終わらせないでほしいという声が大半でした。令和８年、さらにこれを強化していってほしいと思いますが、見解を説明を求めました。","respondent":"樫村高齢者地域支援課長","answer":"第二、第三の「ｇｏｃｃｈａｍａｚｅ」についてです。その中で、こういった活動を西大井以外のところでも実施しやすい環境を整えるように、支援策について引き続き検討してまいりたいと考えています。","id":"exchange-138"},{"speaker":"まつざわ委員","kind":"質問・要望","question":"現在、若年性専門の窓口というのは東京で２つだけ。明確に盛り込んでほしいと求めましたけれども、区の認識、また今後の方向性を説明を求めました。","respondent":"樫村高齢者地域支援課長","answer":"一方で、委員ご認識のとおり、区は現在、地域包括支援センターの見直しにつきまして、様々な角度から議論を進めているところです。その中で、現状施策も踏まえながら、若年性認知症の方も適切にサポートできる体制についても、しっかりと検討してまいりたいと考えています。","id":"exchange-139"},{"speaker":"まつざわ委員","kind":"質問","question":"やはりお話がありました若年性認知症の方々の支援というのは、本人だけではなくて、その家族の人生を支えることにも直結します。現場の切実な声に応える、ぜひ攻めの相談支援というのを構築していただきたくお願いしまして、私の質問を終わります。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-140"}]}],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/629350?Template=document&Id=7385#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=3&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":118471,"voices":324}},{"id":"r08-20260310-3","meetingId":"r08-yosan","date":"2026年3月10日","dateIso":"2026-03-10","committee":"予算特別委員会","time":"午前 ９時３０分～午後 ４時５６分","status":"正式会議録","sourceType":"formal","overview":"予算特別委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を142件整理しています。","topics":[{"id":"topic-01","title":"令和８年度品川区一般会計予算","agenda":"令和８年度品川区一般会計予算","exchanges":[{"speaker":"澤田委員","kind":"質問・要望","question":"３３３ページ、共通商品券普及促進事業、時間があれば、３２１ページ、家庭用生ごみ処理機についてお伺いいたします。我が会派からもプレミアム率の引上げ等を要望させていただき、昨年の秋には２５％のプレミアム率や発行総額の引上げが実現されました。","respondent":"小林地域産業振興課長","answer":"都内の２３区の自治体の中には、品川区の場合は、予算の総額に合わせての売行きだったと認識しています。地域センターで、説明会も高齢者向け、店舗の経営者向けにもやっているところです。","id":"exchange-001"},{"speaker":"澤田委員","kind":"質問","question":"デジタル商品券の導入に当たり、キャッシュレス決済に慣れている若者ユーザーなど、デジタル商品券は利用者層の拡大に今回つながったのでしょうか。購入者の年代層の違い、特徴など、区でもし把握されていることがあれば説明を求めました。","respondent":"小林地域産業振興課長","answer":"７０代の割合は７％ということで、紙の商品券よりは７０代の購入割合は低い数字に、そういった意味では違いが出ているのかなと考えています。令和８年度もデジタル商品券、物価高騰対策、区内経済の活性化につなげてまいりたいと考えております。","id":"exchange-002"},{"speaker":"澤田委員","kind":"質問","question":"今お伺いしたように、保護者が買って子どもが近所のお店で使うこともできたりですとか、紙だからこその利点もあると思います。区は、どのようにお考えか尋ねました。","respondent":"小林地域産業振興課長","answer":"９９.４％がもう使い切られているですので、買っていただいた方には、それに応じた利用をしていただいた。このことは、デジタル商品券の導入目的ということもありましたので、それに沿った対応ができたかと考えております。","id":"exchange-003"},{"speaker":"澤田委員","kind":"質問・要望","question":"続きまして、以前、デジタルデバイドへの取組の拡充を要望させていただきました。きめ細かい相談体制など、令和８年度も引き続きこの取組をブラッシュアップして継続していただきたいと考えますが、区の見解を説明を求めました。","respondent":"小林地域産業振興課長","answer":"あるいは店舗の経営者向けの説明ということで申し上げますと、地域センターを含めて合計３３回、３７９件の相談対応を行っているところです。コールセンターでは４２９件といったように、こういった対応をしまして、デジタル商品券の導入拡大に努めたところです。","id":"exchange-004"},{"speaker":"山本委員","kind":"質問","question":"私からは、３３１ページのしながわ女性高度ＩＴ人材育成事業、それから３１７ページの省エネルギー対策事業について伺います。そこで、昨年度の実績と課題、そして、それを踏まえた今年度の進め方について、簡単にお伺いします。","respondent":"栗原創業・スタートアップ支援担当課長","answer":"この事業は今年度から実施しておりますので、今年度の実績ですが、８月にセミナーを実施しまして、３５名の参加がありました。ＩＴスキルを身につける講座の一部助成を区が実施するということで、そういったところまでの一連のロードマップを支援していきたいと考えております。","id":"exchange-005"},{"speaker":"山本委員","kind":"質問・要望","question":"応援をして、そしてインターン先や企業で実際に働いていただくというところまでを伴走して支援していただくことがすごく大事だと思ってあります。しっかり検証して、さらによいものにしていってほしいと求めましたので、その辺りのお考え等を最後にお聞かせほしいと求めました。","respondent":"栗原創業・スタートアップ支援担当課長","answer":"人手不足がとても課題ですので、多様な人材を採用していただく、そういったところを充実させていきたいと考えております。","id":"exchange-006"},{"speaker":"山本委員","kind":"質問・要望","question":"次に、共通商品券普及促進事業から、紙の商品券事業、デジタル商品券について伺います。本件の目的や来年度予算の概要について確認をさせていただきたいと考えています。","respondent":"小林地域産業振興課長","answer":"こういった中で、商品券事業を１つきっかけにして、区内経済での消費喚起、あるいは活性化を目的とした事業です。予算書の３３３ページに記載していますとおり、それぞれ合わせますと２４億円の発行規模ということで、過去最大の事業規模で予定しています。","id":"exchange-007"},{"speaker":"山本委員","kind":"質問・要望","question":"その中でですけれども、物価高に対する現在の認識について確認をさせてほしいと求めました。それぞれ約２万４,０００人、それから約２万人とご説明がございましたけれども、十分とお考えか尋ねました。","respondent":"小林地域産業振興課長","answer":"１つは、物価高騰に対する認識です。我々としては、そういったところも含めて、今後の物価高騰対策はしっかり考えていかなければいけないという認識です。","id":"exchange-008"},{"speaker":"山本委員","kind":"質問・要望","question":"後ほどご見解を伺います。これまで様々な質問の機会で繰り返しご答弁いただいているところもありますけれども、改めてそれぞれご見解をほしいと求めました。","respondent":"横田デジタル推進課長","answer":"デジタル地域通貨の検討がほかの事業に比べて優先順位が低いのかですが、ＰＥＳＴ分析ですとか、経営的な視点で多角的に研究を進めてまいりました。結果として、今年度、デジタル商品券事業を実施することとなりまして、これから効果検証を行っていくところであります。","id":"exchange-009"},{"speaker":"山本委員","kind":"質問・要望","question":"改めて区の独自のデジタル地域通貨導入を要望して、次の質問に移ります。検討の背景および来年度の検討内容についてお伺いいたします。","respondent":"小林地域産業振興課長","answer":"ただいま来年度の事業について、施策の再構築検討についてどう対応していくかです。こういったところで区の産業支援機能をさらに充実強化するためには、中小企業支援および創業・スタートアップ支援施策の見直し、役割。","id":"exchange-010"},{"speaker":"山本委員","kind":"質問・要望","question":"見解を伺います。併せてご見解を伺います。","respondent":"栗原創業・スタートアップ支援担当課長","answer":"現在、区内には５か所、創業支援施設があります。もちろん認識しているところではありますので、来年度、そういったところで施設の機能も含めまして検討していきたいとは考えているところです。","id":"exchange-011"},{"speaker":"ゆきた委員","kind":"質問・要望","question":"どちらも２０２３年の一般質問、昨年の決算特別委員会において求めた内容が、今回の予算案に上げられ非常に歓迎したい内容だと思っています。新たに区内６０から７０店舗の新規配備をすると伺っていますが、これまで協定したコンビニ運営会社も含めた数と考えてよろしいのか伺います。","respondent":"勝亦健康課長","answer":"来年度予算のプレスで出させていただきましたＡＥＤのコンビニの設置の拡大です。お相手があるので、ここでは断定的な言い方は差し控えしますけれども、新たにファミリーマートと協議を進めまして、設置拡大の準備をしています。","id":"exchange-012"},{"speaker":"ゆきた委員","kind":"質問","question":"新たな運営会社では、今、ファミリーマートとおっしゃいましたが、６０から７０店舗予定されていると伺っております。社会情勢を踏まえ、改めて設置店舗、未設置店舗への協定の働きかけを進めるべきだと考えますが、区の見解を伺います。","respondent":"勝亦健康課長","answer":"既存のコンビニエンスストアへの設置状況ですけれども、今、委員おっしゃったように、全ての店舗に配備ができているわけではございません。ローソンにしましても、セブン－イレブンにしましても、１００％を目指して今後も働きかけをしていきたいと考えています。","id":"exchange-013"},{"speaker":"ゆきた委員","kind":"質問","question":"１００％大手コンビニエンスストアに設置するというハードルは高いですけれども、モデルとなり、希望となっていきます。改めて、区の見解をお聞きしたいと思います。","respondent":"勝亦健康課長","answer":"ＡＥＤの設置について、ＰＲは継続していますけれども、まだまだコンビニにある認知をもっと高めていく必要があると考えています。今後、ＡＥＤの設置状況、それから、併せて救命に関する意識や知識、こういったものを普及啓発していきたいと考えています。","id":"exchange-014"},{"speaker":"ゆきた委員","kind":"質問・要望","question":"調布市で確認したところ、幾つか見積りをとったところ、コスト面では白色の三角巾とでは変わりがなかったとも聞いております。そこで、今後の検討の中で、色付三角巾について改めての要望も含めて使用方法の表示の仕方についても区の見解をお聞きしたいと思います。","respondent":"勝亦健康課長","answer":"検討状況ですけれども、こういったものがプライバシーの配慮等に有効かということで、配備の際には色つきのものを配備していきたいと考えています。併せて、こういったものは視覚的にすぐ分かるような形で全てに掲示、同封していくような形で対応したいと考えています。","id":"exchange-015"},{"speaker":"ゆきた委員","kind":"質問","question":"さらに三角巾の活用について、心肺停止でなかった場合においても、固定止血、圧迫止血にも活用できます。区が使用された三角巾のみを補填することができる体制を事前にとっておくべきと考えますが、ここについても区の見解をお聞きします。","respondent":"勝亦健康課長","answer":"使用された際には、補充につきましても区が行います。各施設、それからコンビニを含めまして、補充の作業等々ご協力いただけるよう、ご相談して現地で封入いただけるようにしています。","id":"exchange-016"},{"speaker":"ゆきた委員","kind":"質問","question":"加えてですが、ＡＥＤの使用でないとしても、そういった資機材を活用していいのか、緊急時に躊躇してしまうおそれもあると思いますが、ここについて、どう対応していくのか、区の見解をお聞きします。","respondent":"勝亦健康課長","answer":"救急キットにつきましては、ＡＥＤを使わないにしても使えるということで、こちらについても周知啓発、それから、使用方法等も含めてお伝えしていきたいと考えています。","id":"exchange-017"},{"speaker":"安藤委員","kind":"質問・要望","question":"伺いたいのですが、区は、一般家庭のＣＯ２をどう削減していく方針なのか伺います。２０３０年５０％削減、２０５０年度排出量実質ゼロの達成に向けて、家庭部門の削減の必要性については、どう考えているのか伺います。","respondent":"中西環境課長","answer":"省エネルギー家電の設置助成とか、宅配ボックスの設置助成といったような形で、設置された際の助成を行っているところです。それから、家庭部門の脱炭素化に向けた区の認識ですが、そこの部分をどのように下げていくかといったところは非常に重要な問題だと考えています。","id":"exchange-018"},{"speaker":"安藤委員","kind":"質問","question":"分かりました。今掲げたような現在の取組で、２０３０年度、そして２０５０年度の排出量実質ゼロという目標は達成できるのでしょうか、伺います。","respondent":"中西環境課長","answer":"現在の取組でカーボンハーフ、それからゼロカーボンが達成できるかといったところです。家庭部門だけのお話に限った場合であったとしても、なかなか今の状況だけでいけるかといったところは難しい部分があろうかとは考えているところです。","id":"exchange-019"},{"speaker":"安藤委員","kind":"質問","question":"基本目標１の将来推計では、家庭部門は２０１３年度の６０万ｔから２０３０年度までに３２万ｔ減らし、２８万ｔにするとなっています。それはどうやって減らすかという具体的施策として４つ掲げられているのですが、これはどのようなことを行う考えなのか伺いたいと思います。","respondent":"中西環境課長","answer":"環境基本計画にあります「環境にやさしい電気の選択」といったもので具体策をですが、基本的には、いわゆる再生可能エネルギーを導入していくといったところを考えているところです。","id":"exchange-020"},{"speaker":"安藤委員","kind":"質問・要望","question":"世田谷区では、昨年２月から区内家庭部門の脱炭素化を進めるために、一般家庭向けの再エネルギー化補助金を創設いたしましたということなのです。ぜひ導入していってほしいと求めましたけれども、いかがか尋ねました。","respondent":"中西環境課長","answer":"私どもとしても、何が一番効果的なのか、引き続き検討してまいりたいと考えています。今までは事業者向けだけだったのですが、そういったものも続けながら、また別の手だてがないかといったものも考えてまいりたいと考えています。","id":"exchange-021"},{"speaker":"安藤委員","kind":"質問・要望","question":"ですから、ぜひ区民を巻き込んだ、さらに一歩進んだＣＯ２削減の事業をぜひ進めていってほしいと求めました。最初に伺いたいでのすが、この仕様は新年度でも同様に扱うのか伺いたいと思います。","respondent":"小林地域産業振興課長","answer":"令和８年度予算のデジタル商品券の制度設計ですけれども、基本的な考え方は踏襲しておりまして、やはり世代を広げて使っていただきたいということ。Ａ券、Ｂ券という２つの券種の考え方も、基本的に維持した上で実施してまいりたいと考えています。","id":"exchange-022"},{"speaker":"安藤委員","kind":"質問・要望","question":"引き続き同様の事業が行われるのであれば、商店街加入店舗に限定した決済手数料の助成をしていただきますよう強く要望しますという声です。ぜひ、商店街加入店舗へのデジタル商品券の決済手数料への助成を行っていただきたいのですけれども、いかがか尋ねました。","respondent":"小林地域産業振興課長","answer":"クレジットカードも含めたキャッシュレス決済全般のところで、その点については、経済産業省も官民の検討会を合わせて議論されているところです。今、現状できる中で幅広く商品券を使っていただくように、そういう意味での令和８年度の事業を進めてまいりたいと考えています。","id":"exchange-023"},{"speaker":"安藤委員","kind":"質問・要望","question":"ある店では、現金で払ってくれたら５０円引きしますという、そういうランチを出す店もありました。ですから、何とかできる形で、そういった決済分の支援に当たるようなものを構築していただければと要望して終わりたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-024"},{"speaker":"せらく委員","kind":"質問","question":"産後ケア事業の予約方法や利用者が自分に合った支援サービスから施設を選びやすくする工夫について伺います。オンライン予約ができるほうが利用しやすいのではないかと感じますが、現在、予約方法の違いによって予約の埋まり方などに傾向があるのか尋ねました。","respondent":"石橋品川保健センター所長","answer":"現在、オンラインの予約システムにおいて、利用率の影響になりますが、オンラインの予約システムにおいてと、電話の予約システムにおいての利用率の差は特に出ていないと認識しております。","id":"exchange-025"},{"speaker":"せらく委員","kind":"確認","question":"そこで、利用できるケア内容をまとめて確認でき、予約までオンラインで完結できる総合的な予約システムを導入してはいかがでしょうか。利用者の利便性向上に加えて、事務負担の軽減も期待できると考えますが、区の見解を伺います。","respondent":"石橋品川保健センター所長","answer":"医療機関等、施設に聞き取りを行いましたが、なかなか区が一括して実施することは少し難しいかなというところがあります。利用者の声も把握しながら、今後、予約システムの一括化も検討してまいりたいと考えております。","id":"exchange-026"},{"speaker":"せらく委員","kind":"提案","question":"もう１点、具体的な提案としては、いずれかのページだけが表示される形になっています。区のホームページはリニューアルが予定されておりますので、そこのタイミングに合わせて改善をしてほしいと求めましたが、いかがか尋ねました。","respondent":"石橋品川保健センター所長","answer":"来年度、区のホームページをリニューアルするというタイミングに合わせまして、ホームページを所管している課と連携して、分かりやすく情報を提供できるように努めてまいりたいと考えております。","id":"exchange-027"},{"speaker":"せらく委員","kind":"確認","question":"苦情については、こちらは新規なのか、継続的な苦情なのかというところを確認させてください。地域猫活動充実に取り組む一方で、苦情が減っていない理由を、区はどのように分析していますか尋ねました。","respondent":"赤木生活衛生課長","answer":"事業開始当初と比較すると、約３０％、猫の頭数としては減ってきているところです。継続なのか、継続して何回もという部分もありますが、そういった活動の効果はあらわれているのではなかろうかと区としては認識しております。","id":"exchange-028"},{"speaker":"せらく委員","kind":"意見","question":"事務事業評価シートを見たのですが、やはりそれと併せまして、現地での苦情に対する解決型の施策も強化していく必要があるかなと思います。専門家と連携したり、調整の支援なども強化していく必要があると思いますが、こちらについて見解を説明を求めました。","respondent":"赤木生活衛生課長","answer":"……。〔時間切れにより答弁なし〕","id":"exchange-029"},{"speaker":"横山委員","kind":"質問","question":"国際的なイノベーションの舞台への挑戦を後押しする取組を強化してほしいと考えますが、区の見解をお伺いいたします。さらに、ブランディング支援や海外ポップアップなどのテストマーケティング支援を推進してほしいと考えますが、区のご見解を説明を求めました。","respondent":"栗原創業・スタートアップ支援担当課長","answer":"来年度は、ＧＸ・脱炭素経営推進支援事業を新規で実施するところでございまして、そういったものを稼ぐ力に変えていく取組について伴走支援する。それから、来年度につきましては、ギフト・ショーといいまして…","id":"exchange-030"},{"speaker":"横山委員","kind":"質問・要望","question":"画一的な月齢基準ではなく、専門機関と連携した支援体制を構築すべきと考えますが、区のご見解をお伺いいたします。さらに、偏食への支援は、保育現場とも情報共有をしながら連携して進めてほしいと求めましたが、いかがか尋ねました。","respondent":"石橋品川保健センター所長、勝亦健康課長","answer":"引き続き、栄養士を中心として、しっかりと保健センターで対応を実施してまいります。栄養士がそちらのほうで講話を実施しておりますので、引き続き、栄養士を中心に、そちらのほうも展開してまいりたいと考えております。 区では、４５歳、５５歳の方を対象に、緑内障などの早期発見・治療に向けた目的で眼科検診を行ってあります。それから女性については０.２％の発生があると認識しておりまして、学校に入ってから…","id":"exchange-031"},{"speaker":"横山委員","kind":"質問・要望","question":"偏食のほうなのですけれども、例えば、おむつ宅配とかでも家庭に伺うときがあると思うのです。要望で終わらせていただきたいと思うのですけれども、見え方の確認などができると思うのですけれども、要望で終わらせていただきます。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-032"},{"speaker":"えのした委員","kind":"提案","question":"先ほど、ゆきた委員からもご質問がありましたが、違った視点からお伺いいたします。令和７年の決算特別委員会でも様々質問、提案させていただきましたが、概要をお伺いしますとの意見を述べました。","respondent":"勝亦健康課長","answer":"コンビニ等へのＡＥＤの設置拡大です。その他に設置をしてきてありますけれども、やはり夜間ですとか休日、こういったことを目的に設置拡大を進めているところです。","id":"exchange-033"},{"speaker":"えのした委員","kind":"質問・要望","question":"設置の取組を要望し、昨年９月、実際に地元のコンビニに設置されたＡＥＤにより処置が行われ心肺停止から命が救われました。令和８年度にはコンビニ設置数が何台になるのかも説明を求めました。","respondent":"勝亦健康課長","answer":"コンビニエンスストアが若干減りまして８７台となっておりまして、合わせて３８０台、区で設置しています。設置の方向で準備しておりまして、６０から７０店舗等を見込んでおりまして、最終的にはコンビニへの設置は１５０台程度になる見込みでおります。","id":"exchange-034"},{"speaker":"えのした委員","kind":"提案","question":"教職員、年間３０から４０件の心臓突然死が発生していると報告され、学校はＡＥＤの設置が求められる施設の１つである。部活動への安全対策の強化として、屋内から屋外へ設置を要望しますが、区のご見解をお伺いしますとの意見を述べました。","respondent":"勝亦健康課長","answer":"２４時間、休日、夜間でも使えるＡＥＤ、先ほど申し上げましたけれども、８７台がコンビニに設置されてあります。今後、ボックスの設置ですとか、様々な手法を検討いたしまして、屋外への設置を考えてまいりたいと考えています。","id":"exchange-035"},{"speaker":"えのした委員","kind":"質問・要望","question":"東品川海上公園、品川区立かがやき園での設置を確認しましたが、区内には何台設置されているのか。今ある自動販売機をＡＥＤ格納型自動販売機への変更や増設について、区のご見解をお伺いします。","respondent":"勝亦健康課長","answer":"こちらのほうで確認できておりますのは、区内の公園に区が設置している自動販売機、２０台程度になると承知しています。１台もございませんで、こちらも取り入れていけることかなと思いまして、関係課と今後協議をしてまいりたいと考えています。","id":"exchange-036"},{"speaker":"えのした委員","kind":"質問・要望","question":"再度確認に伺いましたが、停電時に飲料を提供できる自動販売機の災害ベンダーで、ＡＥＤ格納型自動販売機ではありませんでした。以前から要望しておりますが、設置台数が拡大しても、迅速で的確な処置につなげるためには、ＡＥＤの使用訓練の拡充が重要だと考えます。","respondent":"勝亦健康課長","answer":"そういったものを広げていく必要があると考えておりまして、２月２３日、救命の講習を開催させていただきました。令和８年度につきましては、大井消防署と、今、ご相談させていただいているのですけれども、区民向けの救命講習を検討しています。","id":"exchange-037"},{"speaker":"えのした委員","kind":"質問・要望","question":"次に、３０７ページ、母子保健指導事業費についてお伺いします。令和８年度から新規で開催される母子保健指導事業、歯ならびモグモグ相談についてお伺いします。","respondent":"飛田荏原保健センター所長","answer":"次に、指導用教材費として１０万円、あと、従事者への研修費で９万４,０００円、あとは検査に使う器具や衛生用具等になります。対象となる人数の見込みですが、対象になるのは１６０人程度となりますが、利用人数は１００名を見込んでいるところです。","id":"exchange-038"},{"speaker":"えのした委員","kind":"確認","question":"時間がないので、これは、本事業の成果を図る指標、ＫＰＩ、相談件数以外に何を設定しているのでしょうか。将来的な医療費削減や虫歯、歯列不正の減少にどうつなげるのか、見込みをお伺いいたします。","respondent":"飛田荏原保健センター所長","answer":"医師と、またそういうところにもつなげて、早期発見というところで虫歯や不正咬合の減少にも努められるかと思います。歯科医師と管理栄養士の両面から相談体制も整備しますので、そういうところで充実させていければと考えております。","id":"exchange-039"},{"speaker":"えのした委員","kind":"質問・要望","question":"子どもの頃からの正しい口腔機能の獲得は一生の健康を支える基盤となります。切れ目のない支援で、関係機関と連携した事業推進を要望して質問を終わります。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-040"},{"speaker":"高橋（伸）委員","kind":"質問","question":"それと、３２１ページ、資源持ち去り防止対策費、時間があれば、３２５ページ、カラス対策ネット購入費についてお伺いします。そこで、まず最初に、百日咳の今年の流行について、そして、百日咳は何が問題なのか、改めて、区のご見解をお願いいたします。","respondent":"五十嵐保健予防課長","answer":"委員ご指摘のとおり、昨年の春前ぐらいから百日咳の報告が増えてまいりましたので、ホームページ等で周知を図ってまいりました。品川区もそのぐらいがピークで、東京都全体の約２％強というぐらいでしたので、少しその辺の効果もあったのかなと思っているところではあります。","id":"exchange-041"},{"speaker":"高橋（伸）委員","kind":"質問・要望","question":"そこで、今年の４月からワクチン等の販売価格の大幅な引上げによって、医療機関でもいろいろ大変な、大幅に価格が上昇する情勢であります。５歳児、１１歳児への接種費用の補助を要望いたしますけれども、区のご見解をお聞かせ願います。","respondent":"五十嵐保健予防課長","answer":"現在、国で検討されているものと考えておりますが、５歳児や１１歳児に追加で接種した状況でも。検討している部分もあると思いますので、品川区としては、現在の時点では考えていないところです。","id":"exchange-042"},{"speaker":"高橋（伸）委員","kind":"質問・要望","question":"要望で終わらせていただきます。現状も教えていただきたいのと、これから対策をもっと強く要望していきたいと思いますので、現状をお知らせほしいと求めました。","respondent":"篠田品川区清掃事務所長","answer":"通報等があれば、１台ではなくて、２台、３台という形で増やして回るというような形で対応しています。ですので、その辺をきちんと、今後どういった形で対応していくか、整理をしながら考えてまいりたいと思ってあります。","id":"exchange-043"},{"speaker":"新妻委員","kind":"質問・要望","question":"直近の受診率を令和６年度まで事前に確認させていただきましたが、令和６年度は胃がん、子宮がんが区の目標値を超えています。併せて、無償化することと、受診率が向上することとの関連をどのように捉えていらっしゃいますか尋ねました。","respondent":"勝亦健康課長","answer":"区で実施している検診の把握をしている状況でございまして、会社で実施しているもの、課題があるのかなと認識しています。そのため、無償化によりまして、約１２％の方が検診を受けられる障壁の１つは下げられるのかなと捉えてあります。","id":"exchange-044"},{"speaker":"新妻委員","kind":"提案","question":"議事録を確認いたしますと、２０１９年度厚生委員会での健康課長のご答弁では、ナッジ理論を基にした受診率向上に取り組むというご答弁がありました。このことも併せてＰＲをしていただきながら、様々な手法で受診率向上に取り組んでほしいと求めましたが、見解を伺いますとの意見を述べました。","respondent":"勝亦健康課長","answer":"人間は損失に対する感情のほうが大きいという部分がありますので、そういったものも今後、検討して働きかけを進めていきたいと考えています。東京都のポイント等との連携につきましても、併せて周知、ＰＲをしていきたいと考えています。","id":"exchange-045"},{"speaker":"新妻委員","kind":"質問","question":"続きまして、奨学金返還支援助成についてお伺いいたします。技術者の人材確保と定着ための事業ということでありますけれども、この制度を導入したいきさつや、現在の登録企業数や利用実績をお伺いいたします。","respondent":"栗原創業・スタートアップ支援担当課長","answer":"実績につきましては、令和６年度、３件のご利用がございまして、令和７年度についても３件のご利用がございました。３点目の登録企業についてですけれども、区内企業、現在、７社が登録しています。","id":"exchange-046"},{"speaker":"新妻委員","kind":"質問","question":"この周知の取組について、来年度の取組をお伺いしたいことと、区民以外の方でも多分これは使われていることと思います。区民に特定をしたインセンティブとか、そういうところもさらに上乗せをしてお願いしたいと思うのですが、見解を伺います。","respondent":"栗原創業・スタートアップ支援担当課長","answer":"雇用確保支援セミナーですとか、ホームページやＳＮＳ、そういったところでの周知を徹底していきたいと考えております。区民に対してのインセンティブ、そういったところについては、利用状況等を見ながら、いろいろ検討していきたいとは考えているところです。","id":"exchange-047"},{"speaker":"筒井委員","kind":"確認","question":"確認も含めて改めてお聞きしたいのですけれども、それぞれ発行主体はどこなのかということと、この事業の目的です。区民の物価高騰対策、経済対策と商店街支援の２つなのか、併せ持っているのかということを改めて確認したいと思います。","respondent":"小林地域産業振興課長","answer":"紙のほうは、２００３年から、こちらは商店街連合会が主体となって区が支援するという事業です。世代も広げながら、こういうところを通じて区内経済の活性化に努めていこうというところが両事業の目的です。","id":"exchange-048"},{"speaker":"筒井委員","kind":"提案","question":"今回のように物価高騰対策をやってほしいという議会からの要望に対して、区側からの提案というか、プレミアム付商品券か。その点、地域格差について、どのように区はお考えなのかお知らせくださいとの意見を述べました。","respondent":"小林地域産業振興課長","answer":"紙の商品券も秋は２月末ですけれども、これまで商連が実施しているアンケート、その買物ついでに別のところでということもあります。４０か所以上の郵便局で買えるようにしておりますので、ご近所もそうですし、商品券事業を幅広く実施しています。","id":"exchange-049"},{"speaker":"筒井委員","kind":"提案","question":"説明会も３３回、コールセンターも用意され、手厚く対策をとっておられます。提案なのですけれども、より幅広く使えるデジタル商品券の割合を段階的に多くしていくべきかなと考えているのですけれど、お考えを説明を求めました。","respondent":"小林地域産業振興課長","answer":"今後の商品券事業の展開ということでご質問をいただきました。ほぼ９５％以上、また令和８年度も引き続きやっていきますけれども、引き続き考えてまいりたいと考えています。","id":"exchange-050"},{"speaker":"筒井委員","kind":"質問","question":"区独自のデジタル地域通貨ですから、ＰａｙＰａｙのような決済手数料も要らないという、そうした問題も解消できるということもあるかと思います。改めて、区はデジタル地域通貨の導入の検討をすべきだと考えておりますけれど、いかがお考えか尋ねました。","respondent":"小林地域産業振興課長","answer":"商品券ということで、区内の店舗で買物をしていただくということで、決済というところに１つ主眼を置いた事業です。それぞれ行政目的に応じてということだと思いますけれども、そういうことも含めて、幅広く他部門とも連携して考えていきたいと考えています。","id":"exchange-051"},{"speaker":"筒井委員","kind":"質問・要望","question":"曲がるし、軽量ですし、材料の要素も、日本は世界第２位の生産国ということで、非常によくて、有利な再生可能エネルギーなのかなと考えております。令和８年度の予算で、区有施設への導入も積極的に行ってほしいと求めましたけれど、いかがお考えか尋ねました。","respondent":"中西環境課長","answer":"私どもとしても、今まで設置できなかった場所にも設置できる技術ですので、創エネの世界においては、かなり期待をしている技術です。区有施設での活用、そういったものに関してもできることがあるのではないかと思ってありますので、様々な面から検討してまいりたいと考えていま…","id":"exchange-052"},{"speaker":"筒井委員","kind":"質問","question":"ぜひよろしくお願いします。そして、エコカーについて、今まで脱炭素に対する成果というか効果はどのようなものがあったのかお知らせください。","respondent":"中西環境課長","answer":"そちらは、中小企業向けの東京都の環境保全資金を活用した際の利子の補填といった形でやっているもので、そちらは継続してまいります。自動車の部分に関しても、ガソリン車からＥＶに切り替えることは効果が非常に高いと考えておりますので…","id":"exchange-053"},{"speaker":"筒井委員","kind":"質問・要望","question":"昨今、世界的にも見直しの圧力がかかっているので、しっかりその辺りの動向を見て進めていってほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-054"},{"speaker":"中塚委員","kind":"提案","question":"そこで若干の提案なのですが、質疑応答では、当然、防災対策への質問もあり、保健所の所管ではない部分の説明が困難になっておりました。こうした取組をさらに広げていただきたいのですけれども、区民の実践につながるように事業を拡大してほしいと求めましたが、いかがか尋ねました。","respondent":"赤木生活衛生課長","answer":"今後、そういった関係所管等と連携しながら、どういった形で対応することがベストなのかというところも含めて検討していきたいと考えております。今後の講習会であったりとか、そういったところの事業の参考にさせていただきたいと考えております。","id":"exchange-055"},{"speaker":"中塚委員","kind":"質問・要望","question":"ホームページで紹介したりなど、広げる取組をしてほしいと求めましたが、いかがでしょうか。地域の中でこうした講演会を実施したりなど、区民の実践につながる取組を強化してほしいと求めましたが、改めていかがか尋ねました。","respondent":"赤木生活衛生課長","answer":"そういった部分についても、さらに検討は必要かと存じますけれども、様々な方法を用いて周知に努めてまいりたいと考えています。いろいろと内部で検討しているところではありますけれども、どういった方法が可能かどうかも含めて、引き続き検討してまいりたいと考えております。","id":"exchange-056"},{"speaker":"中塚委員","kind":"質問・要望","question":"１つが、保健所としてはどのような取組を考えているのか、この点を伺いたいと思います。災害時の栄養指導は命に直結する問題だと、この認識を持って防災課と連携してほしいと求めましたが、いかがか尋ねました。","respondent":"赤木生活衛生課長","answer":"東京都で実施するというところでございまして、その中で、発災時にしっかりと対応できる人材を育成していこうという部分についても。区でも、そういった計画的な人材育成に努めてまいるということが、予防的な措置の１つと考えているところです。","id":"exchange-057"},{"speaker":"中塚委員","kind":"提案","question":"１点、最後に提案したいのは、お弁当が続いたりということなのです。食事の問題の現状も把握していただいて、その上で様々な計画に反映してほしいと求めましたが、いかがか尋ねました。","respondent":"赤木生活衛生課長","answer":"被災地の現地へ行って、そういった部分について活かしてはどうかというご提案をいただいたかと存じます。被災状況だとか、実体験であったりとか、そういった部分の情報収集に今後も引き続き努めてまいりたいと考えております。","id":"exchange-058"},{"speaker":"せお委員","kind":"質問","question":"私からは、３０９ページ、不妊治療等支援事業、時間がありましたら、３０１ページ、健康ポイント事業についてお伺いします。これを踏まえて、今後に向けての検討状況を説明を求めました。","respondent":"勝亦健康課長","answer":"今、委員ご紹介いただきましたように、東京都が、保険適用の部分について補助を拡大するという発表が１月にございました。独自にこの保険適用の部分に補助しているのは品川と渋谷の２区だけという状況ですけれども、他区の動向も含めて検討していきたいと考えています。","id":"exchange-059"},{"speaker":"せお委員","kind":"質問","question":"４５歳までの支援としたり、回数に達してしまった方に補助するなど、このような議論はできないでしょうかということが１点。いずれも見解を伺います。","respondent":"勝亦健康課長","answer":"今後どのような形で、そういったつらい部分に寄り添っていけるか考えていきたいと考えています。今後も必要に応じて柔軟に対応できたらと考えています。","id":"exchange-060"},{"speaker":"せお委員","kind":"質問","question":"地域活性化、地域力向上にポイント事業を活用するために、ポイントがつく要件の範囲を広げられないかということをお伝えしたかったです。そこについてご見解をお聞かせほしいと求めました。","respondent":"勝亦健康課長","answer":"地域活性化につながる活動へのポイント要件の拡大です。１つ１つ内容は精査する必要はあるかと考えますけれども、精神的な健康、そういったものもしっかり中身を精査して検討していきたいと考えています。","id":"exchange-061"},{"speaker":"吉田委員","kind":"質問・要望","question":"妊娠から子育ての切れ目のない支援の政策を手がかりに、妊娠前の若年女性の望まない妊娠への対応を求めて質問をさせていただきました。昨年１０月に質問して、すぐに具体的な施策を打つことは難しいとは重々承知しておりますが、もし何か進展したことがあったら説明を求めました。","respondent":"石橋品川保健センター所長、勝亦健康課長","answer":"若年女性に対する対応についてのご質問になります。こういった相談がありましたら、適切な対応をして、関係機関ですとか専門機関につなげるように尽力しております。 望まない妊娠という部分です。２月から緊急避妊薬の店頭販売が始まってございまして、連携をとりながら、区民の方にお知らせをしていきたいと考えております。","id":"exchange-062"},{"speaker":"吉田委員","kind":"質問・要望","question":"この間、１０月の３月ですから無理なことは承知していたのですけれども、ゼロにしていきたいという思いから質問させていただきました。直接雇用を維持してほしいというご意見も伺いましたし、私もそのように考えますが、品川区としての見解を伺いたいと思います。","respondent":"篠田品川区清掃事務所長","answer":"委員からご指摘がございました災害の対応という意味では、区の正規の職員が会計年度任用職員を含めて、現場を含めて２５０人ほどで対応しています。民間に委託したから災害の対応ができないということではないのですけれども、やはり機敏な柔軟な対応は。","id":"exchange-063"},{"speaker":"吉田委員","kind":"質問・要望","question":"ぜひ直接雇用という方針を維持してほしいと求めましたし、お話を伺った中では、大分高齢化が進んでいるのかな。やはり魅力も伝えて採用していただきたいと思うのですが、そういう採用の工夫といいますか、そういうものはどうなっているか説明を求めました。","respondent":"篠田品川区清掃事務所長","answer":"基本的には、職員の採用につきましては、毎年、秋ぐらいに正規職員の採用ということで募集をかけている状況です。個別にお問合せがあれば、もちろん現場の作業の中身も含めてお答えしますけれども、そういったことも説明をしながらご理解をいただいている状況です。","id":"exchange-064"},{"speaker":"吉田委員","kind":"質問・要望","question":"それとも廃棄物と出されたプラスチックごみなのかが区別がつかないなどというような苦労もあって、本当に私も気をつけなければなと思いました。収集に当たる仕事の魅力も、ぜひこれからは工夫して伝えていってほしいと求めましたが、最後に改めてお願いします。","respondent":"篠田品川区清掃事務所長","answer":"今、イベントのお話もございました。最近、区民の皆様方にいろいろな形で接触させていただいていますので、そういう場もしっかり活用してまいりたいと考えています。","id":"exchange-065"},{"speaker":"あくつ委員","kind":"質問","question":"私からは、３１３ページ、各種がん検診から、２点について伺ってまいります。そして、その理由も説明を求めました。","respondent":"勝亦健康課長","answer":"今ご紹介いただきました１位が肺がん、２位が大腸がん、３位については膵臓がんとなっています。国の対策型がん検診の指針が、５がんに限定されておりまして、その中に現状入っていないです。","id":"exchange-066"},{"speaker":"あくつ委員","kind":"質問・要望","question":"ここからが要望というか質問なのですが、この死因第３位の膵臓がんに、ぜひ立ち向かってほしいと求めました。これは先様のある話ですから、尾道方式による品川版膵臓がん早期診断プロジェクトに着手をしていただきたいと思うのですが、いかがか尋ねました。","respondent":"勝亦健康課長","answer":"個人的なお話を許していただけるのでありましたら、私の母親も膵臓がんで１０年ほど前に亡くなってあります。連携しながら、早期発見、早期治療につながる取組を検討していきたいと考えています。","id":"exchange-067"},{"speaker":"あくつ委員","kind":"質問・要望","question":"４４機関ぐらいあるのですか、胃がん検診実施医療機関での意見を伺いながら、実施。４４機関について、こちらのご意見を伺われたのかどうか、現段階での進捗状況を説明を求めました。","respondent":"勝亦健康課長","answer":"今後、来週ですけれども、運営委員会を改めて対面で実施する予定になってあります。胃がん検診の苦しみの部分をどう解消していくか、そして安全を確保していくか、議論してまいりたいと考えています。","id":"exchange-068"},{"speaker":"あくつ委員","kind":"質問・要望","question":"どうですかね」とお伺いしたら、これは別にうそではないですけれども、大賛成ということでした。ぜひ希望する区民の選択肢をお示しいただきたい、このような成果がとれるように、ぜひご尽力ほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-069"},{"speaker":"のだて委員","kind":"質問","question":"３２０ページから始まる清掃費に関わって、３１７ページの温暖化対策事業に関わって、シェードポリシーについて伺います。区長会では、どのような議論があって、区長は何を発言したのでしょうか、伺います。","respondent":"篠田品川区清掃事務所長","answer":"区、事業者、区民が一体となって資源リサイクルなど取組を一層推進していくことが重要であると考えております。２３区一体で検討が行われていくことと認識しておりますが、導入には慎重な検討を十分重ねる必要があるものと考えているものです。","id":"exchange-070"},{"speaker":"のだて委員","kind":"質問・要望","question":"やはり物価高が続くもとで、さらなる区民負担を求めていくと、区民に求める家庭ごみの有料化はすべきでないと思います。区長会でも、ぜひ有料化すべきでないと発言してほしいと求めましたが、いかがか尋ねました。","respondent":"篠田品川区清掃事務所長","answer":"第６次の検討に当たりまして、区長会では、それが前提となっているとは聞いておるものではございません。品川区としましては、あくまで有料化につきましては、区民の負担等もありますので、慎重な検討が必要であるという認識を持っているものです。","id":"exchange-071"},{"speaker":"のだて委員","kind":"質問・要望","question":"課題になっているという中で、有料化前提ではないというお話でしたので、ぜひ品川区の区長としても、有料化すべきでないと発言していただきたいと伺ったので、お答えほしいと求めました。","respondent":"篠田品川区清掃事務所長","answer":"繰り返しの答弁になりますけれども、ごみの現状には、今後も、区、事業者、区民が一体となって取り組むことが必要であり、また、区民の負担に直結するような有料化については、２３区全体で慎重に検討を進める必要があると考えているところです。","id":"exchange-072"},{"speaker":"のだて委員","kind":"質問","question":"認識を伺います。拡大生産者責任でごみの発生抑制を進めていくことが重要だと思いますが、区の見解を伺います。","respondent":"篠田品川区清掃事務所長","answer":"繰り返しの答弁になってしまいますけれども、ごみの減量に関しましては、区や事業者、区民が一体となったリサイクルをはじめとする様々な取組を一層推進していくことが重要であると認識しています。","id":"exchange-073"},{"speaker":"のだて委員","kind":"質問","question":"には、やはりもともとの生産者のところからごみが出ないような形でやっていくということが私は一番重要だと思います。先ほど伺ったのは、ごみの有料化が生きていくことに負担を強いるものだと思わないかということで伺ったので、そこの認識も伺いたいと思います。","respondent":"篠田品川区清掃事務所長","answer":"ごみの有料化につきましては、区民の日々の生活ですとか、区民負担に直結するという認識を持っているものです。","id":"exchange-074"},{"speaker":"のだて委員","kind":"質問・要望","question":"気候変動対策として、どう寄与するものになるのか伺います。気候危機に対して、樹冠被覆率の拡大が重要ではないかと思いますが、いかがか尋ねました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-075"},{"speaker":"のだて委員","kind":"質問","question":"ご答弁ありがとうあります。環境課として、このシェードポリシーをどのように気候変動対策に活かしていきたいと考えているのか伺いたいと思います。","respondent":"中西環境課長","answer":"シェードポリシーに関しては、先ほど、都市計画課長からご説明があったとおりですが、熱中症対策というところで環境課も取り組んです。そういったものもありますので、さらに死亡者数、救急搬送の数が減るような取組につなげられればと考えています。","id":"exchange-076"},{"speaker":"大倉委員","kind":"質問","question":"３２５ページ、車両運行管理システム、３１９ページ、もったいないプロジェクト、３２９ページ、事業承継支援事業で伺えればと思います。ワークシェアですか、具体的に、この業務効率化がどのような効果があるのかという想定について教えてほしいと求めました。","respondent":"篠田品川区清掃事務所長、中西環境課長、栗原創業・スタートアップ支援担当課長","answer":"新年度から導入を予定しております収集作業の運行管理システムにおける業務効率化についてのお尋ねです。全ての車が同じ地図等を見ることができるようにな… ドギーバッグに関してのお尋ねです。昨年度から実施した事業でございまして、今年度に関しては１５店舗で３９０個といったような状況です。 現在、５年前に比べると、後継者がいないという企業は１５ポイント改善したといった状況にはあります。すぐに承継するわけではないので…","id":"exchange-077"},{"speaker":"大倉委員","kind":"提案","question":"提案で、もう少し分かりやすくというところでご提案もしていたかと思うのですが、何か進んでいくのかなというところを教えてほしいと求めました。こうした事業承継をしっかり進めていくということは重要なのだと感じておりますが、その点について、区の考え方を伺いますとの意見を述べました。","respondent":"篠田品川区清掃事務所長、中西環境課長、栗原創業・スタートアップ支援担当課長","answer":"ごみのアプリなどは、なかなかこれを私どもで独自でシステムを連携させるのは、若干難しいのかなという思いがあります。新しいシステムが入ることによって… この２年間で２００店舗ほど拡大をしてきているところでございまして、少なめの料理提供などご対応いただくお店が増えてきているところです。… 区は認識しておりまして、区から事業承継の施策をご案内するといった、そういったプッシュ型の周知もさせていただきたいと考えています。ただ…","id":"exchange-078"},{"speaker":"大倉委員","kind":"質問・要望","question":"例えば、サービスの向上というところをもう少しいろいろ検討していただければなと思っていますので、これは要望で終わります。あることを知らないというところもあったかなというところがあるので、今後また様々、食品ロスに取り組んでほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-079"},{"speaker":"やなぎさわ委員","kind":"質問","question":"２月の私の一般質問の延長戦になりますけれども、悪くてもとんとん、普通に考えると利益が下がってしまうということを心配されております。この課題とは何か、具体的に教えていただけますか尋ねました。","respondent":"栗原創業・スタートアップ支援担当課長","answer":"税率変更に伴う価格改定の検討ですとか、税務経理の処理の変更、すごくコストになってくるのかなとは考えております。それから、消費税が０％になるということで、そういったところなどが挙げられるのかなとは考えているところです。","id":"exchange-080"},{"speaker":"やなぎさわ委員","kind":"確認","question":"様々具体的に教えていただきまして、ありがとうあります。確認したいのが、食料品のみ０％というのが、これは共通認識していただいているということでよろしいか尋ねました。","respondent":"栗原創業・スタートアップ支援担当課長","answer":"可能性の話なので、確定的なことは言えないのですけれども、そういう可能性はあるというふうには認識しているところです。","id":"exchange-081"},{"speaker":"やなぎさわ委員","kind":"質問・要望","question":"区内の実態調査を一般質問で要望したところ、区として今後もその動向をしっかりと注視し、必要な支援策を実施してまいりますとご答弁いただきました。先ほどの食料品のみ０％に対する影響について、区として調査をしっかりしてほしいと今の段階で思うのですけれども、いかがか尋ねました。","respondent":"栗原創業・スタートアップ支援担当課長","answer":"創業支援施設、３つの創業支援施設にインキュベーションマネジャーがおりますので、そういったところで日々相談を受けているところです。特例措置だとか、それを区の独自の調査というか、エビデンスとして積み上げていきたいとは考えているところです。","id":"exchange-082"},{"speaker":"やなぎさわ委員","kind":"提案","question":"以前、そうやって実際に調査を実施してほしいということは、重ねて強くお願いさせてほしいと求めました。提案をしますけれども、この枠をぜひ広げていただきたいということが１点と、いかがか尋ねました。","respondent":"栗原創業・スタートアップ支援担当課長","answer":"実際に利用されている企業は１社にとどまっているところでございまして、先ほど委員がおっしゃった４種類のうち、一番安い５万円のところです。２５万円というところを果たして選択するのか、３名のところを５名にしたところが、登録している企業……。","id":"exchange-083"},{"speaker":"やなぎさわ委員","kind":"意見","question":"この制度、認知が増えれば利用者も増えると思うし、奨学金の問題も今あって、絶対社会問題になってくると思うので、そうすると、利用したいという方はさらに相乗効果で増えてくると思いますので、区としても、ぜひこの拡充について注視して調査してほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-084"},{"speaker":"こしば委員","kind":"確認","question":"３１３ページ、３１５ページ、同ページの難病について伺います。先ほどの質疑でも、１２％がこれまでは費用を負担に感じていたという話を確認いたしました。","respondent":"勝亦健康課長","answer":"バリウム検診のほう、区では昭和５０年代から実施しているものでございまして、バリウムを飲んでエックス線で読み取るというものです。受診率の伸び悩み、こういったものがあり、平成の時代になって内視鏡検診が導入されているという状況だと理解しています。","id":"exchange-085"},{"speaker":"こしば委員","kind":"質問・要望","question":"胃がんになる可能性が高まる４０代から、バリウム検査で分からない些細な病変にも対応できる、それが早期のがん発見にもつながると思います。５０代が対象となりますが、これを４０代に引き下げていくことをご検討ほしいと求めましたが、お考えを説明を求めました。","respondent":"勝亦健康課長","answer":"こちらは、国の対策型がん検診の指針の中では、５０代以上が望ましいということで定められているような状況です。４０代につきましては、区で拡充して実施しているというところで、医療機関等の意見を伺いながら検討してまいりたいと思います。","id":"exchange-086"},{"speaker":"こしば委員","kind":"質問・要望","question":"５０代以上は内視鏡検査という、４０代からの内視鏡検査を勧めているということもありますので、検討してほしいと求めました。およそ４,０００円から１万円弱となると思いますけれども、今後はぜひ検討してほしいと求めましたが、見解を教えてほしいと求めました。","respondent":"勝亦健康課長","answer":"胃がんの検診につきましては、区で検診を行っておりますので、ぜひ区の検診を受診していただけたらと考えています。","id":"exchange-087"},{"speaker":"こしば委員","kind":"質問","question":"対象年齢が５０歳から５歳刻みで７５歳までで、かつ、この検査をこれまで受けたことがない人が対象と言われております。５歳刻みでも構いません、２０歳から５歳刻みで７５歳まで、どのように考えますか尋ねました。","respondent":"勝亦健康課長","answer":"そういった中で、胃がんの部分につきましては、知識をしっかり周知いたしまして、検診を受けていくという啓発が必要だと考えています。令和６年度に終了しているような状況でございまして、それから、意識をしていただくような啓発をしていきたいと考えています。","id":"exchange-088"},{"speaker":"こしば委員","kind":"提案","question":"これまで議会質問で度々、私、ＲＳウイルスワクチンの質問、また、前向きな提案をさせていただきました。定期接種が、今度、４月以降始まることで、妊産婦への周知が必要になってまいりますが、これをどのように取り組んでいくのか、まず説明を求めました。","respondent":"五十嵐保健予防課長","answer":"今のところは、今週末ぐらいに、パンフレットも一緒に入れた予診票を送らせていただく予定になっております。３月１６日、発送させていただいて、予診票の発送をもちまして周知をする予定にしています。","id":"exchange-089"},{"speaker":"こしば委員","kind":"提案","question":"ＲＳウイルスワクチンの公的な補助を前向きに提案してきたところですけれども、去年の予算特別委員会だったのですけれども、保健予防課長から。しっかりと口頭でご説明をしていただいて、１つずつ不安解消に向けて取り組んでほしいと求めましたが…","respondent":"五十嵐保健予防課長","answer":"妊婦が打つワクチンですので、ぜひ主治医というか、通っている産婦人科のほうで丁寧な説明を受けていただければと思っているところです。","id":"exchange-090"},{"speaker":"塚本委員","kind":"確認","question":"なるべく早く、できれば４月１日からという思いでありますけれども、そこについてお伺いします。そういうことも可能なのかということでの確認をお願いいたします。","respondent":"勝亦健康課長","answer":"こちらにつきましては、早い段階で周知できるように、予算をお認めいただきましたら、速やかに周知できるよう準備を現在進めているところです。１回から生涯２回という形に変えさせていただきまして…","id":"exchange-091"},{"speaker":"塚本委員","kind":"質問・要望","question":"１２億円と１２億円、できたらお願いしたいし、いかがでしょうかということです。例えばＢ券のほうが割当が６割になっていますので、ある程度あったのかどうか、この件についてもお伺いしたいと思います。","respondent":"小林地域産業振興課長","answer":"３点目が、対応です。今後の対応というところでは、説明会で使わせていただいたりもしていますので、そういうところも一緒に協力してやっていきたいと考えています。","id":"exchange-092"},{"speaker":"塚本委員","kind":"意見","question":"狙いのよくしっかりした事業だと思っているのですけれども、なかなか実績がどうも上がっていないような、令和６年度だけの実績を見るとです。今後これを拡大というか、皆さんによく使っていただくために、どういった施策が考えられるか、お願いいたしますとの意見を述べました。","respondent":"栗原創業・スタートアップ支援担当課長","answer":"昨年度から実施して、今年は５件ということで、微増ではありますが増えてきているところです。やはりまだ認知度が増えていないのかなということと、使い勝手がいいよということを丁寧に周知していきたいと考えているところです。","id":"exchange-093"},{"speaker":"須貝委員","kind":"質問","question":"私は、３３３ページ、プレミアム付区内共通商品券発行助成についてお伺いします。８７％の方は何も恩恵を受けない状況を見ると、さらにここに弱者を生んでいる対策ではありませんか、おかしくないか尋ねました。","respondent":"小林地域産業振興課長","answer":"今、１３％というお話がございましたけれども、最大でもやはり２割いかない程度で各自治体も事業規模を考えられているのかなです。１２月補正の中で、一律５,０００円のギフトカード、区民の支援は実施されていくものであると認識しています。","id":"exchange-094"},{"speaker":"須貝委員","kind":"質問","question":"産業振興対策と言われますが、実態は、この共通商品券、各店舗で平等に公平に利用されていないのではないのですか、教えてください。弱者店を逆にたくさん生んでいると思うのですが、これもおかしくないですか、説明を求めました。","respondent":"小林地域産業振興課長","answer":"ただ、実際にそれが何店舗ぐらい使われているかという概数でいうと８５％程度、幅広く商連の加盟店舗の中でも使われているのであろうと考えています。卸売業が１つ商業のところであるわけですけれども…","id":"exchange-095"},{"speaker":"須貝委員","kind":"質問","question":"どういうお店に、どういう業種に使われている、または一般の資料で我々にもやはりそれは公表しなければまずいのではないですか。利用できる商品券を配布したらどうか尋ねました。","respondent":"小林地域産業振興課長","answer":"やはり２つ視点があると思っていまして、店舗側から見たような支援ということと、どちらからいくかということはあると思います。目的に応じて、全体としてやはり区内経済の活性化を進めていくですので、総合的に進められていくものであると認識しています。","id":"exchange-096"},{"speaker":"須貝委員","kind":"質問","question":"それだったら、多くの方に毎年６億６,０００万円ですか、配布して、その方たちに自由に使ってもらう。それを利用してもらう、そういうような循環する経済対策を私は考えるべきだと思うのですが、ご見解を説明を求めました。","respondent":"小林地域産業振興課長","answer":"令和８年度の予算の柱として、やはりこの商品券事業はかなり大きな予算で実施するところですけれども、そこはまさにそのとおりです。きちんと商店街連合会、あるいは区内店舗と力を合わせて、そういうところがＰＲできるように努めてまいりたいと考えております。","id":"exchange-097"},{"speaker":"田中委員","kind":"質問・要望","question":"３２０ページの清掃事業について、３３１ページ、地域産業振興関連について、３１１ページ、環境衛生に関してお伺いしていきたいと思います。平成１２年から去年で丸２５年、節目の年でもありますので、改めてお伺いしていきたいと思います。","respondent":"篠田品川区清掃事務所長","answer":"平成１２年に移管されましてから２５年たつということで、ふれあい収集ということで、こういったことも独自の取組としてやってまいりました。新たなものにもどんどん取り組んできて、少しでも効率的に…","id":"exchange-098"},{"speaker":"田中委員","kind":"質問・要望","question":"清掃職員が、移管時は３５０人いらっしゃったのが、今は２５０人で対応されているという話も伺いました。今後、北品川が出来上がるまでにおいて、何が必要かお聞かせほしいと求めました。","respondent":"篠田品川区清掃事務所長","answer":"こちらを閉めて、大崎の品川の事務所と北品川の分室の２つの事業所をメインに、これから収集に当たっていくということになります。今年度から新たに運行管理システムも入りますので、そちらのほうも踏まえながら、より効率的な収集にも取り組めるのかなと考えているところです。","id":"exchange-099"},{"speaker":"田中委員","kind":"質問・要望","question":"どう受け止めるかということもいろいろあるのですけれども、財調のやり取りの中で、その比率に応じた配分割合を決めて来ています。令和８年度の清掃事業費総事業費が６８億円という金額は、どういう位置づけなのか、その辺の認識はいかがか尋ねました。","respondent":"加島財政課長","answer":"申し訳ございません、令和７年度特別区財政調整交付金における清掃費の当初算定額は４２.９億円です。財調算定された、交付された金額をただ漫然と受け取って事業を行っているというわけではないということは申し上げさせていただきたいと思います。","id":"exchange-100"},{"speaker":"田中委員","kind":"質問","question":"しっかり清掃事業として、先ほど、都知事の発言のことも触れられた方がいました。当時の４４％が５２％になったときの金額に遡れば、では、もう少し上げてくださいというようなことは言えないのか尋ねました。","respondent":"加島財政課長","answer":"そのように捉えれば大変心強い言葉なのかもしれませんが、清掃費につきましても、各区の事業の実施状況等を見極めまして、財調算定の中で充実できるものがあれば充実を図ってまいるように協議してまいりたいと思います。","id":"exchange-101"},{"speaker":"田中委員","kind":"質問・要望","question":"産業振興に関してお伺いしたいのですが、もう間もなく区役所の裏のＯＩＭＡＣＨＩ ＴＲＡＣＫＳが開業いたします。それから及ぼされる影響は、特に商店街支援という視点でしっかり対応すべきだと思うのですけれども、いかが認識されていますか尋ねました。","respondent":"小林地域産業振興課長","answer":"そういった認識はありますけれども、動きは商店街の中でも認識されていて、区のほうにも申請が来ているところです。こういうような取組も支援しながら、商店街振興課の観点からも、しっかり進めてまいりたいと考えているところです。","id":"exchange-102"},{"speaker":"田中委員","kind":"質問・要望","question":"駅の施設ということから、当時は減免措置がありまして、３分の１ぐらいしかかかっていなかった。もっと地域貢献してほしいという視点でのＪＲに対する思いは、ぜひ事あるごとに伝えてほしいと求めましたが、どうか尋ねました。","respondent":"小林地域産業振興課長","answer":"新年１月下旬にですけれども、商店街ともいろいろ連携というところは都市環境部門と協力して進めていきたいと考えていますので、そういう中で応援をしてまいりたいと考えています。","id":"exchange-103"},{"speaker":"田中委員","kind":"質問・要望","question":"衛生指導の関係で少しお伺いしたいのですけれども、監視が行われていますが、その中に火葬場があります。この内容についてお聞かせほしいと求めました。","respondent":"赤木生活衛生課長","answer":"令和４年度につきましては、令和５年２月２日に監視に行っております。今年度１２月に構造設備の変更がございましたので、そちらの部分について中身の確認に、私も含めて担当と行ってまいったところです。","id":"exchange-104"},{"speaker":"田中委員","kind":"質問・要望","question":"極めて公共性の高い施設でありながら、極めて営利を求める法人になってしまったというところの課題がありますので、そこは環境衛生の視点だけではなくて、しっかりとチェックしてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-105"},{"speaker":"西本委員","kind":"質問","question":"いろいろと先ほども少し質問がありましたけれども、中小企業の中でどういう現状になっているのか、議会の中でも大分議論しています。これからどういうあり方なのかは、その中に、特にインボイスの影響についての調査を入れられるのかどうかのお考えをお聞きします。","respondent":"小林地域産業振興課長","answer":"区の産業支援機能を充実強化していくにはどういう対応が必要かということで、創業・スタートアップ支援施策の見直し再構築ですけれども、特に我々。機能は考えていかなければいけない、そういう意味でのあり方検討は…","id":"exchange-106"},{"speaker":"西本委員","kind":"質問","question":"当然、幅広くやられるのでしょうけれども、その中にインボイスに対する項目も入っているのですかという質問なので、そこをお答えください。","respondent":"小林地域産業振興課長","answer":"幅広くですので、特定の何かを今、排除してということではないので、そういったところも含めて幅広く考えてまいります。","id":"exchange-107"},{"speaker":"西本委員","kind":"質問・要望","question":"次に、３０７ページの乳幼児の各健診、それから、すくすく赤ちゃん訪問についてお聞きします。健診ですから、そして成長の過程で何か課題があれば、早期発見をして対処するということが非常に重要になってくると思っています。","respondent":"石橋品川保健センター所長","answer":"月齢に応じて健診を実施しておりますが、３歳であればこういうことができるようになる、サポートをする体制をとらせていただいております。保護者の方の気づきの場、サポートをする場として、機会を捉えて実施していきたいと考えております。","id":"exchange-108"},{"speaker":"西本委員","kind":"質問","question":"３か月、１歳半という形でなっていくと、その情報はどういう扱いになっていますでしょうか。始まったのは今年でしょうか、５歳児健診の位置づけも含めて、どういう形で今後考えていくのか尋ねました。","respondent":"石橋品川保健センター所長","answer":"５歳児健康診査におきましても、３歳児健診からのつながりをしっかりと把握して、次につなげる形で５歳児健診を実施しました。こういったものを保護者の方にもミニ講話などを実施しまして、保護者の方の気づきの場としてもしっかりと実施をさせていただきました。","id":"exchange-109"},{"speaker":"西本委員","kind":"質問","question":"どうしても、どうもこの０歳児見守りおむつ定期便事業というのは、私はどうしても違和感があって仕方ないのです。この二重事業になっているところを、やはりまとめていくべきではないかなと思いますが、いかがか尋ねました。","respondent":"石橋品川保健センター所長","answer":"見守り支援員の相談というところ、１０％以上の増加をして、かなり事業の必要性は区民の方にも認められていると評価をしているところになります。品川区が１位を取ったというところも含めまして、見守りおむつ定期便が…","id":"exchange-110"},{"speaker":"石田（秀）委員","kind":"質問","question":"あえて環境で伺うようにします。ここら辺のことは、どのように考えて、これからも強化していくかということを含めて、お考えをお聞きしたいと思います。","respondent":"中西環境課長","answer":"私どものほうにも、他自治体から、林業の関係ですとか、環境関係でお話をいただくことはありますので、積極的に取り組んでまいりたいと考えています。品川区が今連携して自治体で何ができるかというところ、我々のほうでどういう処理ができるか…","id":"exchange-111"},{"speaker":"石田（秀）委員","kind":"質問・要望","question":"そのためにも、私は、もう一段先へ進んでいただきたいと思っていて、今、都市連携も増えてきたではないですか。ヨガ、こういうことに私は一歩踏み出していくべきだろうと思っていますので、そこら辺のところの考え方を教えてほしいと求めました。","respondent":"中西環境課長、勝亦健康課長","answer":"今、総務課でも様々地方自治体との連携のお話をしておりますし、私どもも、その場に行かせていただくこともあります。調査委託の形で進めることがよいのか、実際… 個人の方のフィットネスですとか、そういった健康に関する活動の支援です。そういった中で、個人での健康づくりの活動、様々な形があるかと思いますけれども、支援について考えていきたいと思います。","id":"exchange-112"},{"speaker":"石田（秀）委員","kind":"質問・要望","question":"３,０００円ぐらい補助するとか、こういうこともぜひしてほしいと求めましたので、それはいろいろ要望にしておきます。こういうことを１回、見える形にしたほうがいいような気がするのですけれども、最後にそれを説明を求めました。","respondent":"篠田品川区清掃事務所長","answer":"灰溶融炉は、一時期かなり注目されたのですけれども、コスト等もかなりかかるということで、現実には今、動かしていないと、たしか聞いております。温度を上げるために、温度が低いとダイオキシン等の発生もありますので、ガスを入れる形で運用していると聞いているところです。","id":"exchange-113"},{"speaker":"こんの委員","kind":"確認","question":"私からは、３１５ページ、任意予防接種費で帯状疱疹について、３２９ページ、中小企業活性化事業費を伺いたいと思います。５０歳から６４歳の接種人数もお聞きしたいのと、６５歳以上の接種人数の現状、費用は今どのようになっているのか確認させてください。","respondent":"五十嵐保健予防課長","answer":"私から、帯状疱疹の接種につきまして説明します。令和７年度の分ですが、令和８年１月末現在で、５０歳から６４歳の任意接種は２.１％になっております。","id":"exchange-114"},{"speaker":"こんの委員","kind":"質問・要望","question":"そうなると、品川区としては、その補助金を使って５０歳からの接種を可能としてくださっているのですが、今後はどうなるでしょうか。品川区は中小企業をどういう方向へ向けていこうと考えているのか、改めて事業について、狙いや目的を確認させてください。","respondent":"五十嵐保健予防課長、栗原創業・スタートアップ支援担当課長","answer":"５０代から増加しまして、７０代がピークになるということもございまして、できれば定期接種で打っていただきたいという思いもあります。そして令和８年度末の年齢が６３歳以下の方、また… 事業を実施するところで、当初予定していた事業ができなくなってしまったといったところの辞退があって、やむを得ずの減額になっております。そういったところのご支援をしていくところで、付加価値をつける活動…","id":"exchange-115"},{"speaker":"こんの委員","kind":"質問・要望","question":"受けるほうがいいですか」とか、医師の認めるといったところの判断は、どういう流れになるのかといったところを確認したいと思います。そうした声をしっかり汲み上げながら施策を考えていただきたい、このように思うわけですけれども、いかがか尋ねました。","respondent":"五十嵐保健予防課長、栗原創業・スタートアップ支援担当課長","answer":"任意接種ですので、予診票をお送りするに当たりまして申請が必要になってまいります。そのときに、疾患名と状況を確認させていただいて、それで確認をさせていただこうと思っているところです。 稼ぐ力を支援しつつも、女性の人材を活用するですとか、多角的に支援を実施しています。本当に委員おっしゃるように、そういったところできちんと皆さんの先行き不透明な不安を解消できるように努めていきたいと考えております。","id":"exchange-116"},{"speaker":"高橋（し）委員","kind":"質問","question":"前年度比で３.４％増となっています。全部の予算に関する構成比は１.６％なのですけれども、その数字についての評価もお願いします。","respondent":"小林地域産業振興課長","answer":"令和７年度は、見込みとしては１,５００件程度の見込みということで、３分の２程度となっているところです。区も思い切った予算を支援しているというところで、これからの成長力、そういう支援をしっかりやっていきたいと考えているところです。","id":"exchange-117"},{"speaker":"高橋（し）委員","kind":"質問・要望","question":"やはり３％とか４％に近いところもあるので、１.６％を堅持するのではなく、状況に応じて拡大してほしいと求めました。現在のこういった景気の下振れリスク等に関する現在の区の認識を伺います。","respondent":"小林地域産業振興課長","answer":"そうなってきた場合に、輸入原油の９割以上、こういったものが政府の支援策とか区の支援策を押し下げてしまう可能性というのはあり得るです。我々として、今回の支援策をしっかり実行していく中で…","id":"exchange-118"},{"speaker":"高橋（し）委員","kind":"質問・要望","question":"支出に影響が生じる場合について、必要な施策をぜひ十分に続けて、世界情勢を注視して施策を打っていってほしいと求めました。どういった経緯でこれが予算計上をなされたかということをお話しください。","respondent":"栗原創業・スタートアップ支援担当課長","answer":"外部機関が主催する新人研修を利用することが多く、研修費用が３万円から５万円と負担が多いということが課題になっているということがありました。そういったことを踏まえまして、区で研修を実施することによって…","id":"exchange-119"},{"speaker":"高橋（し）委員","kind":"意見","question":"ほかの自治体でもそういうことが行われているのかということと、規模としてはどれぐらいか。それから、これ、実際に区が直接やるのか、それとも、どこかに委託してやっていくのかということで、いつ頃からということも含めてお願いしますとの意見を述べました。","respondent":"栗原創業・スタートアップ支援担当課長","answer":"江東区ですとか大田区が実施しているところでございまして、無料のところもあれば、２万円ぐらい負担しているところもあります。時期としては、５月２１日、２２日を予定しておりまして、募集は４月から実施していくところです。","id":"exchange-120"},{"speaker":"松本委員","kind":"質問・要望","question":"私からは、３０７ページ、母子保健指導事業費、３２１ページ、資源持ち去り防止対策費について伺います。ここはオンラインの面談も選択肢として掲載してほしいと求めましたが、いかがか尋ねました。","respondent":"石橋品川保健センター所長","answer":"妊婦のための支援給付事業の伴走支援の部分の面接になります。今後、健康課とともにやっている事業にもなりますので、そちらは健康課と調整して検討してまいりたいと考えています。","id":"exchange-121"},{"speaker":"松本委員","kind":"質問","question":"８か月よりも前に恐らくこの面談を受けることがある程度想定されているのかなと思っていて、そうすると、まだ産休にも入られていない方です。そうすると、ここは区のご認識を伺いたいのですけれども、これは有給休暇を取得して来てくださいということを想定されているのか伺います。","respondent":"石橋品川保健センター所長","answer":"特に有給休暇を取得してくださいということを促しているわけではありませんが、面談が保健センターの開所時間でお願いしているところになります。面談は助産師の資格のある保健相談員が担当して対応しておりまして、開所の９時から１６時で…","id":"exchange-122"},{"speaker":"松本委員","kind":"質問","question":"月に何回かは夜間があったりとか、土日があったりという工夫もぜひお願いしたいと思いますが、いかがか尋ねました。","respondent":"石橋品川保健センター所長","answer":"保健センターの開所時間は、保健センターだけでは決められないところもありますので、現時点ではまだ検討していないところになります。そういったところもしっかり活用していただきながら、皆さんがより使いやすくというところは、しっかりと考えていきたいと考えています。","id":"exchange-123"},{"speaker":"松本委員","kind":"質問","question":"もう１個、時間との関係で伺いたいのですけれども、妊婦向けの事業はいろいろあるかと思います。出産前に平日に３日間来てくださいというのは、なかなか厳しいように思うのですけれども、ここを何とか打開策はないか伺います。","respondent":"石橋品川保健センター所長","answer":"両親学級を土日に実施しておりますのは、以前より土日の開催で、こちらは委託で実施しているところになります。先ほどお話をした助産師資格のある保健相談員ですとか、保健師職の職員が対応しているというところで、平日の実施になります。","id":"exchange-124"},{"speaker":"松本委員","kind":"質問","question":"先ほどの所有権が誰かということは回避できるのかなと思うのですけれども、ひとまず今日は資源ごみについて、最後にお伺いしたいなと思っています。結構、資源ごみの持ち去りは問題になりつつあるのに予算が減っているというのは、これはどういうご事情なのか伺えればと思います。","respondent":"篠田品川区清掃事務所長","answer":"来年度は、パトロールカー１台のガソリン代を計上しております。２台分ということと、１年間、ガソリン代だけを計上しているものです。","id":"exchange-125"},{"speaker":"松本委員","kind":"意見","question":"パトロールカーが１台減ったというのは、もう本当に少し意見だけですけれども、品川区の場合は過料になっているかと思います。過料ではなくて罰金でやっているところもあるかと思いますので、今後は注視していただきながら、条例改正も含めてご検討ほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-126"},{"speaker":"鈴木委員","kind":"質問・要望","question":"３１５ページの人工呼吸器装着難病患者災害時停電シミュレーション、３０７ページの５歳児健診、３１３ページのがん検診について伺いたいと思います。対象者が、どのような方を、何人くらいにするのかについても教えてほしいと求めました。","respondent":"福地大井保健センター所長","answer":"訓練実施の際には、難病看護の専門家に立会いをしてもらい、個別の具体的なアドバイスをしてもらえるように準備してまいります。予定としては、５件を予定しております。","id":"exchange-127"},{"speaker":"鈴木委員","kind":"質問・要望","question":"それは全て人工呼吸器装着者、その対象になるという方に対しては１００％がつくられているのか、その点についても伺いたいと思います。４年前ぐらいから支給されることになったと思うのですけれども、お知らせがいっているのか、その点についても伺いたいと思います。","respondent":"福地大井保健センター所長","answer":"令和７年度１２月時点で、区では人工呼吸器把握件数は２６件なのですけれども、災害時個別支援計画を作成済みの方は２１件で、約８０％の作成率です。そのような方に対しましては、粘り強く丁寧に説明を続けている状況です。","id":"exchange-128"},{"speaker":"鈴木委員","kind":"質問・要望","question":"今日の款ではないので、ぜひ検討いただきたいということで、要望だけさせてほしいと求めました。どういう手順で、そのマニュアルの作成については考えがあるのか、その点についても伺います。","respondent":"福地大井保健センター所長","answer":"神経難病患者をまずやってみて、その後、どうするか検討していくという形になります。患者宅で訓練を実施した後、見直しをしていく予定です。","id":"exchange-129"},{"speaker":"鈴木委員","kind":"質問・要望","question":"それから、次に５歳児健診について伺います。その結果がどのような状況になったのかということを１点伺いたいのと、この５歳児健診は、どう考えられているのかについて伺いたいと思います。","respondent":"石橋品川保健センター所長","answer":"健診を実施するに当たりまして、医師会ですとか実施園、一緒に連携をとって意見交換をして検証を実施してまいりました。次年度につきましては、私立園、公立園にかかわらず、事後フォローの体制等の手法につきまして、オンラインで検証を実施してまいります。","id":"exchange-130"},{"speaker":"若林委員","kind":"質問・要望","question":"引き続き、この顕彰事業は継続していただきたいということで、質問を３点します。保育の部分もあるかもしれません、こういったところで、取組にどのように広げていくのか、区の今後のお考えをお聞きしたいと思います。","respondent":"高山健康推進部次長、飛田荏原保健センター所長","answer":"データの蓄積が図られたタイミングで実施することとなるのですが、検証のようなものについては毎年行っていくということで考えているところです。こうしたいわゆる歯の健康が全身の健康に関わるといった、そういった視点のもと… 歯科医師の指導のもと、ふだんのご家庭での毎日の食事についても配慮しながら、お子さんの健やかな発育を促進してまいりたいと考えています。この事業を今回やってみて、どういうふうに進めていくか…","id":"exchange-131"},{"speaker":"若林委員","kind":"提案","question":"まさに口腔発達がぐんぐん上がっている年代で、また今後、何か具体的な提案ができればと考えています。８０歳までオーラルとフレイルを見ている、８０２０をまた、しっかりと取組を期待しておりますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-132"},{"speaker":"藤原委員","kind":"質問","question":"３１７ページ、精神保健事業についてお伺いしますが、自分の質問に惚れろといつも言っています。なぜＴシャツを着ているのか尋ねました。","respondent":"栗原創業・スタートアップ支援担当課長","answer":"品川区では、昨年度より、品川スタートアップエコシステムの構築に取り組んでいるところです。これを広く周知するということで、今日、この産業経済費の場で着用させていただいたところです。","id":"exchange-133"},{"speaker":"藤原委員","kind":"質問・要望","question":"今日初めて私も質問の場で伺うので、具体的にどのような学習会か教えてください。続けて伺いますが、ここ数年の参加者の１回当たりの人数と、対象である方の年齢層を説明を求めました。","respondent":"福地大井保健センター所長","answer":"年齢層は、小学校の低学年から４０代の方をお子さんに持つ方が参加されております。特に継続して参加されているご家族は、家族全体が変わってきていて、とても幸せな家庭になっていることを強く感じます。","id":"exchange-134"},{"speaker":"藤原委員","kind":"質問","question":"でも、やはり寄り添う、その思いが、やはり私は伝わっていくと思うし、もう１つは、家族会のこういう会がよかったということで終わるのか。ひきこもりをしている方自体を、ひきこもらないようにしてあげるということを目標に持っていくのか、その辺についてはいかがか尋ねました。","respondent":"福地大井保健センター所長","answer":"地区担当保健師から個別に具体的にどのように対応していくかということを相談させていただいています。なので、そちらは連携をとってやっております。","id":"exchange-135"},{"speaker":"まつざわ委員","kind":"質問","question":"予算書の３０５ページ、あと、同ページのかかりつけ医定着推進事業についてお聞きします。令和８年度予算においても、現場のコスト増を区としてどう把握しているのか、まず説明を求めました。","respondent":"高山健康推進部次長","answer":"現場のコスト増についての区としての認識ですが、薬剤師会とは、定例的ないしは随時に会議を持たせていただいております。今後も本事業が継続可能でありますよう、引き続き薬剤師会のご意見などを伺いながら、負担の軽減に向けて適切に対応してまいります。","id":"exchange-136"},{"speaker":"まつざわ委員","kind":"質問","question":"結局、廃棄費用が前年比でも数万円増加していまして、さらにボトルの強度の確保も課題となっているとお聞きしています。ボランティア精神で支えてくれている現状に甘えることなく、区が責任を持って事業の質を担保していくべきと考えますが、区の見解を説明を求めました。","respondent":"高山健康推進部次長","answer":"そうした方々に用いられる医療性の廃棄物、こういったものを適正に安全に処理していくということが非常に大きな課題となっていると認識しています。引き続き薬剤師会の負担軽減に向けて、ご意見などを伺いながら、負担の軽減策について検討してまいります。","id":"exchange-137"},{"speaker":"まつざわ委員","kind":"質問","question":"環境部局が横断的に連携して、行政の収集ルート、そういったものを活用した一括処理システムを検討してはいかがでしょうか。このような品川区独自のモデルを構築していって、安全な処理体制を確立すべきと考えますが、ご見解を説明を求めました。","respondent":"篠田品川区清掃事務所長","answer":"リサイクルを所管する部門で、薬剤師会が集約した注射針を、八王子市が委託をした回収業者が回収して処理をしていると聞いているところです。こちらに関しましては、まずは、現状ですとかニーズの把握に努めてまいりたいと考えているところです。","id":"exchange-138"},{"speaker":"まつざわ委員","kind":"質問・要望","question":"この令和８年度の予算をそのための新たな一歩とすることを要望しまして、次の質問に移ります。本区においても、区民が自分のニーズに合ったかかりつけ医機能を主体的に選択できる環境を整えるべきと考えますが、区の見解を説明を求めました。","respondent":"高山健康推進部次長","answer":"今後のスケジュールとしましては、来月、令和８年４月以降、その結果の公表、そして分析などが行われると事前に聞いているところです。総合的に有機的に連携させながら、地区医師会とも情報交換をしながら、よりよい内容のものにしていきたいと考えているところです。","id":"exchange-139"},{"speaker":"まつざわ委員","kind":"質問","question":"本区におきましても、医師、看護師、訪問看護師、ケアマネジャーが患者の情報を共有する連携体制をさらに強化すべきだと思っています。連結としての機能を高めるために、令和８年度の予算では、どのような今以上の連携強化を講じているのか説明を求めました。","respondent":"高山健康推進部次長","answer":"高齢化の進展に伴う対応、そして、医療と介護の連携に向けた令和８年度の取組です。区と品川、荏原の両医師会とともに、さらなる在宅医療の推進を図ることを目的に実施するものです。","id":"exchange-140"},{"speaker":"まつざわ委員","kind":"質問","question":"災害時や感染症の蔓延時において、その機能を明確にして、有事の際も安心して医療を受けられる体制を平時から構築していく必要があります。予算の中でどう具現化していくのか、また、平時の連携をどう有事の力に変えていくのかお伺いいたします。","respondent":"高山健康推進部次長","answer":"災害時の医療の継続性と平時からの連携です。そうしたものをご参照いただくほか、こういったものも活用いただく中で、平時から災害時を想定した連携体制について強化してまいる考えです。","id":"exchange-141"},{"speaker":"まつざわ委員","kind":"質問・要望","question":"品川らしい医療提供体制のこれからの引き続きの確保、拡充を要望しまして、質問を終わります。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-142"}]}],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/629350?Template=document&Id=7387#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=3&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":121805,"voices":332}},{"id":"r08-20260312-3","meetingId":"r08-yosan","date":"2026年3月12日","dateIso":"2026-03-12","committee":"予算特別委員会","time":"午前 ９時３０分～午後 ４時５５分","status":"正式会議録","sourceType":"formal","overview":"予算特別委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を134件整理しています。","topics":[{"id":"topic-01","title":"委員会での質疑","agenda":"委員会での質疑","exchanges":[{"speaker":"えのした委員","kind":"質問","question":"私からは、３７５ページ、応急活動対策費、３７７ページ、街頭消火器維持管理経費についてお伺いします。マンションの方からは、「えのしたさん、そんなに大量にどうしたんですか」と挨拶にもつながり、「３.１１なので備えております」と伝えました。","respondent":"遠藤防災体制整備担当課長","answer":"照明の設置、そういった開設に必要な手順書を、開設時に主要なものを整備していくといったものになってあります。各避難所によって対応していく必要があると考えていますので、必要な掲示物などに関しましては、避難所ごとに整備していくことを計画しています。","id":"exchange-001"},{"speaker":"えのした委員","kind":"質問・要望","question":"私は、令和５年１１月の第４回定例会の一般質問において、ペット防災について要望しました。作成を要望しますが、区のご見解をお伺いします。","respondent":"遠藤防災体制整備担当課長","answer":"動物が苦手な方、また災害時に動物が行動変化をする、そういった運営上の課題ということが非常に大きいということも認識しています。あるいは東京都動物愛護推進委員などの意見なども取り入れながら、実効性の高いものを令和８年度に整備していきたいと考えています。","id":"exchange-002"},{"speaker":"えのした委員","kind":"確認","question":"その際、改めて消火器にも種類があるということを学び、地域の３つの町会を歩いて確認をしました。消火器の種類、また災害で一番多い出火原因は何でしょうか、ご説明ください。","respondent":"遠藤防災体制整備担当課長","answer":"電気火災と、一般的な火災に全て対応しておりますが、機械泡に関しては電気火災には対応していないというものになってあります。再度電気が復旧した際に、電気が流れた瞬間に発火し、着火して火災が起こるといったものになってあります。","id":"exchange-003"},{"speaker":"えのした委員","kind":"質問・要望","question":"確認が取れました。街頭消火器を電気火災に対応した消火器に統一することを要望いたしますが、区のご見解をお伺いします。","respondent":"遠藤防災体制整備担当課長","answer":"こちらは電気火災に対応していないということで、３種類の火災にきちんと対応できるようなものに更新をしてまいりますので、よろしくお願いいたします。","id":"exchange-004"},{"speaker":"山本委員","kind":"提案","question":"これまで要望していたイベント時などに混雑が見込まれるトイレの拡充については、ぜひ別途検討をお願いしたいと考えています。工事や施設開業はこれからになりますが、今回の事業を踏まえまして、区のＰａｒｋ－ＰＦＩ事業の今後の見通しについて、区のお考えをお伺いしますとの意見を述べました。","respondent":"大友公園課長","answer":"令和８年度に東品川海上公園でのＰａｒｋ－ＰＦＩの事業、施設の開業、運営が開始されるところです。区が初めて実施する、今後ほかの公園でこの手法を導入するかどうか、判断をしていきたいと考えているところです。","id":"exchange-005"},{"speaker":"山本委員","kind":"質問・要望","question":"区で初めての事業であるからこそ、今回の成果や課題を丁寧に検証し、次につなげていただきたいと考えています。そこで、事業検証に当たっての評価手法や検証時期などお教えください。","respondent":"大友公園課長","answer":"利便施設の利用状況など、にぎわいに資する評価を想定しております。令和８年度、令和９年度を想定しておりますけれども、必要に応じて令和１０年度以降も検証してまいりたいと考えているところです。","id":"exchange-006"},{"speaker":"山本委員","kind":"質問・要望","question":"民間資金と民間の知恵を活用して、より効率的でより魅力的な公園整備につなげていただくことを要望したいと考えています。区で最初のＰａｒｋ－ＰＦＩ事業となった東品川海上公園をこれからどのような公園にしていきたいのか、区のお考えや思いを説明を求めました。","respondent":"大友公園課長","answer":"Ｐａｒｋ－ＰＦＩの導入により、整備や施設だけでなくて、公園全体の環境が変化していくです。Ｐａｒｋ－ＰＦＩの事業者や公園全体を管理する事業者と連携して、より一層皆に愛される公園とするよう努めてまいりたいと考えているところです。","id":"exchange-007"},{"speaker":"山本委員","kind":"質問","question":"実際、子育て世代の皆様からも、区内で住み続けたいが費用負担が重いという声を伺っております。そこで、まず施策内容について伺います。","respondent":"川原住宅課長","answer":"そこから２万円を加算するような形で、住み替えをしてからも５年以上住み続けること、地域住民との調和を図ることなどを要件としています。そして来年度、令和８年度の予算ということで…","id":"exchange-008"},{"speaker":"山本委員","kind":"確認","question":"助成要件はどのように確認をするのでしょうか。それから、助成金の支払い方法はどのようにするのでしょうかというところです。","respondent":"川原住宅課長","answer":"２点ご質問いただきました。支払い方法につきましては、口座をお伺いして口座への現金の振込ということを予定しています。","id":"exchange-009"},{"speaker":"山本委員","kind":"質問","question":"要件のところで、５年以上住むとか、町会の活動をするなどというところは、どういった形で手当てをされるのでしょうか。説明を求めました。","respondent":"川原住宅課長","answer":"町会への加入の部分に関しては、あくまでも自己申告という形になります。ご自身で、きちんと意識を持っているかというところにチェックボックスを定めて、ご自身で申告をしていただくといった形を想定しています。","id":"exchange-010"},{"speaker":"山本委員","kind":"提案","question":"加入の確認や誓約書だけで終わらせるのではなくて、実際にそのイベントに参加してもらうことの仕組みづくりをぜひ検討してほしいと求めました。私としては、２年目以降もこういったイベント等に参加をしていただくということができるのであれば…","respondent":"川原住宅課長","answer":"民間の調査でも大体平均５年ぐらいで引っ越されるということを予定していますので、賃貸ともに進めていくことができればよいと考えているところです。ですから、こちらに関してはデジタル推進課や地域産業振興などの関係部署と連携を取りながら…","id":"exchange-011"},{"speaker":"山本委員","kind":"質問・要望","question":"それぞれどうぞ前向きなご検討を要望して質問を終わります。時間も限られておりますが、できるところまでお聞きしていくということで、次に品川子育て等空き家バンク設置等委託業務について伺います。","respondent":"川原住宅課長","answer":"事業者を選定して協議をした後に、まずはこの空き家の所有者の方に、区が仲介してこういったバンクを開始するということは初めての取組です。しっかりと周知をして、地域への貢献にも資するとして、所有者の方にもまずはご理解いただけるように周知していきたいと考えています。","id":"exchange-012"},{"speaker":"山本委員","kind":"質問・要望","question":"実際には登録してもらえる空き家をどう確保するか、利用を希望する子育て世代にどう周知するか、効果を高めていくです。ぜひそういった効率的な仕組みをつくっていただいて、進めていくことを期待して、要望いたして終わります。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-013"},{"speaker":"ゆきた委員","kind":"質問","question":"私からは、３７９ページの避難所管理費に関連して、避難所初動・受付対応、衛生環境改善事業と、３４７ページの浸水対策事業について伺います。避難所初動・受付対応、衛生環境改善事業について伺います。","respondent":"羽鳥防災課長","answer":"この際、マイナンバーカード連携のメリットといたしましては、マイナンバーカードを読み取れば個人情報が自動的に反映されるというところです。そういった被害状況も登録していただくと、そういった情報を基に…","id":"exchange-014"},{"speaker":"ゆきた委員","kind":"確認","question":"例えば横浜市では、マンションの代表者や理事会の理事長を通じて、在宅避難者に分配する取組が行われていると横浜市からも伺っています。在宅避難者支援の１つの方法として、段階的に広げていくということについて、区の認識を伺いたいと思います。","respondent":"羽鳥防災課長","answer":"マンション防災、在宅避難を進める上で、管理組合や理事会が中心となって支援物資を受け取るような体制という体制構築は重要であると考えています。しながわ防災学校のマンション防災コースやマンション防災アドバイザー派遣、こういった事業を通じて…","id":"exchange-015"},{"speaker":"ゆきた委員","kind":"質問","question":"同じくこちらも横浜市から伺っていますが、誰が在宅避難しているのかを把握し、必要な物資や支援につなげる仕組みが運用されております。ＬＩＮＥを活用したデジタルでの把握と併せて、こうしたアナログでの把握も組み合わせていく必要があると考えますが、改めて区の認識を伺います。","respondent":"羽鳥防災課長","answer":"こちら在宅避難者の把握というところで、アナログでどのように把握するかというところはまだ検討中ではあります。今後もアナログをしっかり活用した情報発信や連携、こちらについては検討してまいりたいと考えています。","id":"exchange-016"},{"speaker":"ゆきた委員","kind":"質問","question":"続いて、浸水対策事業について伺います。そこで、まず制度の見直しが実施されてからの申請件数と、簡易止水板の実績についてお聞きします。","respondent":"関根河川下水道課長","answer":"ここ近年の平均と比べて１０倍ほど、過去最多の申請ということで、非常に多くのご利用をいただいているものと考えております。そのうち簡易型止水板につきましては、２件のご申請をいただいております。","id":"exchange-017"},{"speaker":"ゆきた委員","kind":"質問・要望","question":"昨年の決算特別委員会の場でも確認させていただきましたが、令和７年度局地的集中豪雨以前の時点で２件、令和６年度も２件という状況でした。昨年９月の集中豪雨で浸水ハザードマップが示されていなかった箇所に被害があったことから、緊急に更新していくことを求めました。","respondent":"羽鳥防災課長","answer":"こちらは、現在予定しているものは、６月１日に風水害の特集ページを広報しながわで出しますので、そちらには掲載予定です。そちらを基に、雨水出水のハザードマップというものを来年度作成をして、こちらも早い段階で公表できるように取組を進めてまいります。","id":"exchange-018"},{"speaker":"ゆきた委員","kind":"質問・要望","question":"昨年１１月の建設委員会にて、このことについて再度改めて求めた際、現状はホームページの掲載にとどまっております。そこで、制度をより活用していただくためにも、区民が具体的にイメージのできる周知の工夫について、区の見解をお聞きします。","respondent":"関根河川下水道課長","answer":"ご指摘もあります、やはり特定の製品のＰＲにならないように、慎重に検討する必要があるかと考えております。設置状況の写真につきましては、そういった設置状況の写真を撮影し、こういったことは検討してまいりたいと考えています。","id":"exchange-019"},{"speaker":"ゆきた委員","kind":"質問","question":"止水板助成制度については、令和８年度末までが期限となっています。令和９年度以降も区民の自助による浸水対策を継続的に支援する制度として位置づけていくべきと考えますが、区の認識を伺いたいと思います。","respondent":"関根河川下水道課長","answer":"令和９年度以降につきましては、新たに東京都が区市町村に対する止水板設置の補助制度を開始したことなどや、来年度の動向等を踏まえて、改めて検討させていただければと考えております。","id":"exchange-020"},{"speaker":"安藤委員","kind":"質問","question":"伺いますが、こちらの方は当時、何年から何年まで何年間、都市整備部長を務めたのでしょうか。伺います。","respondent":"高梨都市計画課長","answer":"現在品川区都市計画審議会の委員、会長を務めていただいている方は、平成５年から平成１２年までの７年間、品川区の都市整備部長をされた方です。","id":"exchange-021"},{"speaker":"安藤委員","kind":"提案","question":"公募区民枠も設けてはいかがでしょうか、伺います。伺いますが、委員に案内を出すことは必要ではないでしょうか、伺いますとの意見を述べました。","respondent":"高梨都市計画課長","answer":"説明会の案内についてですが、今まで説明会を行ってきた履歴や、委員の方々にご判断いただいているところではあります。事務局からの説明会の案内といったところは、委員のご意見を伺いながら、今後も検討してまいりたいと考えています。","id":"exchange-022"},{"speaker":"安藤委員","kind":"質問・要望","question":"区の担当部署は準備組合のどのような会合にどの程度の頻度で足を運んでいるのか、伺います。大崎西口駅前地区再開発を心配する会の打合せや会合、総会などには足を運んだことが一度でもあるのでしょうか、伺います。","respondent":"中道都市開発課長","answer":"そういった意見を踏まえて、また、区が持っています上位計画等に適合しているのかどうかといったところで検討しているところです。区にご意見等を申したいというときには、区としてはそこは拒むことなく、常に受け入れているというような状況です。","id":"exchange-023"},{"speaker":"安藤委員","kind":"質問","question":"今来たらお話を伺っていますということですけれども、心配する会の方々は、来たら対応するけれども自分から行かないということです。それは少し不公平なのではないですかと思うのですけれども、総会などに足を運んだことが一度でもあるのかと伺ったので、もう一度お答えください。","respondent":"中道都市開発課長","answer":"準備組合の総会等、年に１回、もしくは臨時総会があったら年に２回といった形で、そういったところには時間が合えば参加はしております。","id":"exchange-024"},{"speaker":"せらく委員","kind":"質問・要望","question":"段階に合った交通安全啓発が求められますが、幼児やその保護者に対する現在の啓発や教室の取組と、その目的をお聞きします。環境負荷の低減や健康増進などを進める自転車推進計画がある中で、品川区としてはどのように受け止めをされますか、伺います。","respondent":"山下交通安全担当課長","answer":"保護者に対する安全教育を実施したいということで提案して、品川区としても、ぜひ参加させていただきたいということで手を挙げているところです。なかなかそのような機会がない方に対しては注目しながら、安全教育をやっていく必要性はあるのかと認識しています。","id":"exchange-025"},{"speaker":"せらく委員","kind":"質問","question":"そこでお伺いします。文庫の森のこちらの看板を立てた経緯もお聞きします。","respondent":"大友公園課長","answer":"やむを得ず文庫の森については細かな規定を設けて、禁止看板として設置して、現在は禁止をしているところになってあります。加えて、東品川公園としながわ区民公園では自転車の貸出しも行ってあります。","id":"exchange-026"},{"speaker":"せらく委員","kind":"質問","question":"状況を教えてくださり、ありがとうあります。禁止の看板ルールを設けたということなのですけれども、禁止する前に注意喚起の看板などは立てられたのか、こちらも説明を求めました。","respondent":"大友公園課長","answer":"こちら段階を踏んで、この看板にたどり着いたという過程です。地域と公園ご利用者のご意見等々、トラブルをなくすという目的で、今回やむを得ずこのような細かな記載の看板を設置しています。","id":"exchange-027"},{"speaker":"せらく委員","kind":"質問・要望","question":"成長発達というところはお考えいただきたいのですけれども、はい、分かりました。一般質問でお聞きしたボール遊びができる環境の整備について、こちらの取組の状況、お聞かせほしいと求めました。","respondent":"大友公園課長","answer":"そのような周知等々、各学校にもお配りをするなど、いろいろな形での周知啓発を図ってまいりたいと考えております。その後、各公園の状況に応じた看板の見直し等々に入っていければなというところで考えているところです。","id":"exchange-028"},{"speaker":"せらく委員","kind":"質問・要望","question":"順次進めてくださっていること、ありがとうあります。ぜひ保護者の見守り体制の注意というところも、幼児向けにもしっかりと啓発をしていってほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-029"},{"speaker":"横山委員","kind":"質問・要望","question":"屋根１個分でも、貯水タンク１個分でも、ゆっくりと雨水を流すことが重要とのお話を伺いました。大崎駅東口第４地区まちづくりガイドライン改訂版の１４ページに、風の道とはどのような考え方でしょうか、ご説明をお願いいたします。","respondent":"関根河川下水道課長、森道路課長、高梨都市計画課長","answer":"ゆっくり流すことが重要とのご指摘は、まさしく重要な観点だと認識しております。河川下水道課におきまして、その周知啓発を通じて… 近隣区の目黒区、ご紹介いただきましたものは目黒区のエレベーターですけれども、非常に復旧まで時間がかかっているというように聞いております。… 涼しさとにぎわいのあふれるシンボルロードとして、何か暑さ対策も含めた内容で取組ができないかといったところで考えているところです。…","id":"exchange-030"},{"speaker":"横山委員","kind":"質問・要望","question":"街路樹の連続化や公開空地の緑化により、風を増やすクールシェアスポットをネットワーク化していただきたいと要望いたします。涼しく歩きたくなるまち品川を実現してほしいと思っているのですけれども、区の見解をお伺いいたします。","respondent":"中道都市開発課長、高梨都市計画課長","answer":"はその緑をより多くしてクールスポットを設けていきたいといった考えで今までも取り組んできて、まちづくりを進めてきたところです。今後、事業者等との協議の中で… 私からは、計画についてお答えをいたします。可視化等々につきましても、来年度、暑熱対策について考えていく中で検討してまいりたいと考えています。","id":"exchange-031"},{"speaker":"横山委員","kind":"質問・要望","question":"区民の方のアンケートというか、体感というものもあるかと思いますので、ぜひその辺も力を入れてほしいと求めました。要望で終わります。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-032"},{"speaker":"澤田委員","kind":"質問","question":"本日は３７５ページ、防災普及教育費、同ページ、事業者向け防災啓発事業についてお伺いします。区民の生活を支えるインフラの中で、電気は大変重要であると思いますが、報告書の結果を踏まえ、区内の被害想定についてご見解を説明を求めました。","respondent":"羽鳥防災課長","answer":"これにより、停電対策の強化が示されたというように認識しています。その数字ですと、区内の停電率は２１.３％になってあります。","id":"exchange-033"},{"speaker":"澤田委員","kind":"質問","question":"復旧までに３日程度かかると言われている中、酷暑や寒さの厳しい冬では、体調を崩してしまうことも考えられます。酷暑や冬季の地震を想定した場合、区はどのような対応をお考えか尋ねました。","respondent":"遠藤防災体制整備担当課長","answer":"停電時の在宅避難についてですが、その方の状況というところもみて、対応方法は、その方の状況によって対応方法は様々変わってくると考えています。は災害時協力協定を締結している事業者の支援によって…","id":"exchange-034"},{"speaker":"澤田委員","kind":"質問・要望","question":"ガラス飛散フィルムなど、安心安全に在宅避難ができるグッズの重要性について、引き続き機を見て啓発してほしいと求めました。在宅避難の備蓄のあり方についてのご見解を説明を求めました。","respondent":"羽鳥防災課長","answer":"しっかりと周知をしてまいりたいと考えています。様々な支援が考えられると思いますので、そうしたところは関係各課と連携して体制を整えてまいりたいと考えています。","id":"exchange-035"},{"speaker":"澤田委員","kind":"質問・要望","question":"今、デジタルリテラシーについて、区としてはどのようにお考えでしょうか。ご見解を伺います。","respondent":"羽鳥防災課長","answer":"そちらで区としての公式な情報を発信していくという体制を取ったところです。様々な手法があるかと思いますので、委員ご提案の内容も含めて、どのような手法が効果的か検討してまいりたいと思います。","id":"exchange-036"},{"speaker":"澤田委員","kind":"質問","question":"ぜひ子どもたちの件も、教育委員会と連携してお考えいただけたらなと思います。多くの企業等において、ＢＣＰの策定や非常用電源の確保が進んできておりますが、区内のＢＣＰ作成率はどのくらいなのでしょうか、説明を求めました。","respondent":"遠藤防災体制整備担当課長","answer":"そしてもう１点が、区内の事業者全体の作成状況といったところは、区として把握できていないという状況です。これを参考にいたしますと、大企業で約７６％、中堅企業で約４５％がＢＣＰを作成しているという状況です。","id":"exchange-037"},{"speaker":"澤田委員","kind":"質問・要望","question":"その辺の情報もお伝えするなど、相談支援の充実と策定の重要性を改めて周知することも大切であると思います。その辺り要望して終わらせていただきます。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-038"},{"speaker":"筒井委員","kind":"質問・要望","question":"ベイエリア３区がしっかり連携して、まさにベイですから、さらなる拡充を図っていただきたいと考えております。それはどういった内容だったのか、またはその感想というか、今後どのようにお考えになっているのかを少し簡潔にお答えいただけると幸いです。","respondent":"関根河川下水道課長","answer":"２月に実施されました東京都知事とベイエリア３区長の意見交換ですけれども、ＥＶ船に乗船していただいたほか、各区の水辺利活用の取組の情報の共有、また、東京都も含めて、水辺利活用、舟運の今後の将来像の意見交換等を行ったものです。","id":"exchange-039"},{"speaker":"筒井委員","kind":"提案","question":"私が提案、要望してきておりまして、提案をさせていただいたのですが。こうした利活用は、東京都の潮風公園マネジメントプランにも沿っているものだと考えておりますので、ぜひその辺りのお考えを説明を求めました。","respondent":"関根河川下水道課長","answer":"東京アクアシンフォニーとの連携、観覧イベントの実施ですけれども、区内の観光など、そういった関連部署等含め、それから東京都ほか他自治体とも連携して進めていきたいと考えています。","id":"exchange-040"},{"speaker":"筒井委員","kind":"提案","question":"回遊性を高めたいというようなお考えのようですから、この辺は品川区とＪＲ東日本、Ｗｉｎ・Ｗｉｎな関係になるかなと考えております。ですから、共に品川区の発展を進めていってほしいと求めましたけれども、お考えはいかがか尋ねました。","respondent":"中道都市開発課長","answer":"今月、ＯＩＭＡＣＨＩ ＴＲＡＣＫＳが開業するというところで、品川区もＪＲ東日本と様々な協議を今進めているです。は地域、こちらはまちづくり方針でも記載していますけれども、しっかりと連携した取組を今後も進めていきたいと考えています。","id":"exchange-041"},{"speaker":"筒井委員","kind":"質問・要望","question":"区の考え、エレベーターが６基ぐらいあるのに、結局もらったエレベーターチェア１台をそのマンションのエレベーター６基のうち１基しか置かない。エレベーターチェアをお配りしてからどうなりましたかというような状況確認、意識確認をしていただいて、その点いかがお考えか尋ねました。","respondent":"羽鳥防災課長","answer":"令和６年度から３か年事業ということで、来年度まで実施するものです。そういったところの周知というものも行ってまいりたいと考えています。","id":"exchange-042"},{"speaker":"筒井委員","kind":"質問・要望","question":"東京都の事業ですけれども、東京とどまるマンションという事業のご案内など、そうしたものにつなげていってほしいと求めました。都民ファーストの会としても都議会で要望をさせていただいて、ぜひこれを活用していっていただきたいのですけれども、その点いかがお考えか尋ねました。","respondent":"羽鳥防災課長","answer":"こちらは区だけではなく、都とも連携してしっかり周知してまいりたいと考えています。支援が受けられるというようなものもありますので、様々な関係するところと連携をして、周知を深めてまいりたいと考えています。","id":"exchange-043"},{"speaker":"筒井委員","kind":"質問・要望","question":"命を守っていただくということが大事ですので、そうした意識でもって、今後も進めていってほしいと求めました。ぜひよろしくお願い申し上げます。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-044"},{"speaker":"高橋（伸）委員","kind":"質問・要望","question":"３６３ページ、公衆便所費、荏原町駅前公衆便所改修工事設計委託、３５９ページ、公園における防災設備整備事業についてお伺いをいたします。最初に、３６３ページ、荏原町駅前公衆便所改修工事設計委託に関連してお尋ねをしたいと思います。","respondent":"大友公園課長","answer":"約８m2と非常に狭小な床面積でありまして、利便性の向上を図る目的として、決定したところです。","id":"exchange-045"},{"speaker":"高橋（伸）委員","kind":"質問・要望","question":"地域の要望を酌み取って、検討していくという説明があったのですが、これ地域の要望をどのように酌み取ったのでしょうか。例えば公衆便所の再整備の要望がありましたなど、これまでの状況というのですか、経過をお知らせほしいと求めました。","respondent":"大友公園課長","answer":"町会長会議で説明し、説明会を開催するなど、地元に丁寧に説明していきたいと考えているところです。地域の声を丁寧に聴きながら、誰もが利用しやすい公衆便所の実現に向けて設計を進めてまいりたいと考えているところです。","id":"exchange-046"},{"speaker":"高橋（伸）委員","kind":"質問・要望","question":"その会議体にしっかりと丁寧に説明していただきたいのですが、もう１回、すみません。今の説明について、。","respondent":"大友公園課長","answer":"そうですね。経緯等々も踏まえて、町会長会議や説明会というような場を設けまして、説明を図って声を聴いていきたいと思ってあります。","id":"exchange-047"},{"speaker":"高橋（伸）委員","kind":"質問・要望","question":"続いて３５９ページ、公園における防災設備整備事業についてお伺いいたします。この公園を活用したマンホールトイレ等の整備に至った背景と、目的を教えてほしいと求めました。","respondent":"大友公園課長","answer":"そちらで、災害時トイレ空白エリアが存在していることが明らかになったことから、公園へのマンホールトイレの整備を進めていくものです。生活用水確保のための井戸、非常用電源も整備をすることで、地域の防災性を向上させることを目的に実施する事業です。","id":"exchange-048"},{"speaker":"高橋（伸）委員","kind":"質問・要望","question":"分かりました。これ大変なことになるので、地域が行う防災訓練などで実際に使ってみることはできるのかどうか、教えてほしいと求めました。","respondent":"大友公園課長","answer":"公園に設置されたマンホールトイレ等々の防災設備を使用して防災訓練をする際には、まず防災課に相談していただければと考えているところです。防災課と公園課連携して、防災訓練等への支援をしてまいりたいと考えているところです。","id":"exchange-049"},{"speaker":"高橋（伸）委員","kind":"質問・要望","question":"広場公園２か所は、それは私からの要望なのですが、今後についてどのように考えておられるのか。今、現状と今後のことについてお尋ねしたいと思います。","respondent":"大友公園課長","answer":"現在も電源を設置されているところはありますけれども、分電盤であって、少し一定の工事等々が発生する形になるかと思います。広くここにこのようなものがあるのだということはご理解いただくような取組に資するものとしていければと考えているところです。","id":"exchange-050"},{"speaker":"高橋（伸）委員","kind":"質問・要望","question":"分かりました。そのことについては、要望として、ぜひ今後すぐ使えるような状態にしてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-051"},{"speaker":"新妻委員","kind":"質問・要望","question":"３６１ページ、３７１ページ、４点順番に伺ってまいります。続けて、２番目のバスについても伺います。","respondent":"山下交通安全担当課長、櫻木地域交通政策課長","answer":"直近では３月２６日に、４警察署と区で合同で、きゅりあんにおきまして、品川区交通安全区民の集いといったものを開催する予定です。そういった大規模なイベント等でも、しっかりと周知を図ってまいりたいと考えているところです。 東急バスにつきましては、五反田駅から川崎駅に向かう路線を含む２系統が減便、休止が品川駅を通過する３系統となっております。なお、都営バスに関しましては、令和６年度末に品川駅・八潮パークタウン間…","id":"exchange-052"},{"speaker":"新妻委員","kind":"質問・要望","question":"もう１点は、都との情報共有を綿密に、連携強化をしていただきたいと考えています。あわせて見解を伺います。","respondent":"山下交通安全担当課長、櫻木地域交通政策課長、大友公園課長","answer":"令和７年度からは、先日、しながわ中央公園において実施したところです。来年度、そちらにもしっかりと電動キックボード等のモビリティに対する安全利用に… 今後についても、交通施策の展開については都と連携するとともに、きちんと、地域の声を届けてまいりたいと考えています。… そのため、水族館利用者の貸切りで運行する必要があるものです。事業形態が異なるものでありますので、しながわ水族館で運行している無料送迎バスの地域開…","id":"exchange-053"},{"speaker":"新妻委員","kind":"質問・要望","question":"私２０１６年から、この決算特別委員会から始まって１０年がたちますが、ここの公園の中の公衆便所の移設について要望を続けてまいりました。区が居住支援法人に求めることは何か、この２法人が区が求める内容をしっかりと受けていただける法人なのかということをお伺いいたします。","respondent":"大友公園課長、川原住宅課長","answer":"新浜川公園は前回の大規模改修から３５年以上経過しており、施設の老朽化が進んでいるため、公園の改修を実施するものです。引き続き新浜川公園をより魅力のある公園としていくため、努めてまいります。 様々な入居に関する相談、個別対応が必要なもの、区がなかなか手を出せない事例などにも実施をしていただけるということで求めているところです。今後の居住支援協議会、もしくは重層的な支援体制…","id":"exchange-054"},{"speaker":"新妻委員","kind":"質問・要望","question":"トイレの件ですけれども、より運河側に移設をしてほしいという、住民の声があります。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-055"},{"speaker":"鈴木委員","kind":"質問・要望","question":"事業所や店舗等に対しても、港区のように火災の場合でも見舞金を出す制度にしていただきたいと思うのですけれども、いかがでしょうか。この額もぜひ引き上げてほしいと求めましたけれども、それぞれご答弁をお願いしたいと思います。","respondent":"星災害対策担当課長","answer":"今ご質問いただきました見舞金について説明をします。その増額につきましても、水害に対する支援策の分析等々含めさせていただきまして、今後考えていきたいと考えております。","id":"exchange-056"},{"speaker":"鈴木委員","kind":"質問・要望","question":"区民の不安や懸念の払拭、改めて再度一斉説明会を求めてほしいと求めましたが、区としてどのような対応をされているのかを伺いたいと思います。私は区としても、ＪＲ東海のこのような説明で納得しているのかということも伺いたいと思います。","respondent":"大石まちづくり立体化担当課長","answer":"責任を持って対応すべきものと考えているため、引き続きＪＲ東海に対し、様々な手法を用いて説明を行うよう求めてまいりたいと考えているところです。原因分析、事業主でありますＪＲ東海が責任を持って対応すべきものと考えているところであり…","id":"exchange-057"},{"speaker":"鈴木委員","kind":"質問・要望","question":"このまま住み続けることができるのだろうかとか、引っ越すとしても資産価値が下がってしまうなど、様々な不安の声が出されました。再度の説明会をせずに工事再開は絶対駄目だよという立場で、ＪＲ東海に対応してほしいと求めましたが、いかがか尋ねました。","respondent":"大石まちづくり立体化担当課長","answer":"繰り返しになりますが、事業者ですＪＲ東海が責任を持って対応し、説明することが重要と考えているところです。ＪＲ東海に対しましてそういった声を直接届け、丁寧な対応を図るよう、改めて求めてまいります。","id":"exchange-058"},{"speaker":"鈴木委員","kind":"質問・要望","question":"絶対にこのまま強行するということはさせないように、区としても対応してほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-059"},{"speaker":"こしば委員","kind":"提案","question":"私からは３７５ページ、防災体制整備費について、３３７ページ、地域公共交通検討経費のコミュニティバスについて伺います。これまでも井戸の活用が災害時における区民の生活を守るなど、提案や質問をさせていただきましたとの意見を述べました。","respondent":"遠藤防災体制整備担当課長","answer":"井戸の新設に関する補助と維持修繕に関する補助、合わせまして、合計５件の申請があるといったところです。維持修繕に関しましては、ポンプの一部の部品を修繕するといったようなことで、補助を申請されているという状況です。","id":"exchange-060"},{"speaker":"こしば委員","kind":"質問","question":"そのうちの新設が１件と、このポンプの部品の交換等の修繕があったと認識をしております。区のお考えについてと、今後の民間井戸の活用について、将来的な見通しについてお伺いをしたいと思います。","respondent":"遠藤防災体制整備担当課長","answer":"やはり在宅避難者も含めて、やはり給水ステーションや、例えば区民避難所の井戸などの補完的なものということで考えてあります。まずは事業の実施の効果といったところをよく実証を積みながら、今後どういった補助が有効なのかといったところを検討していきたいと考えています。","id":"exchange-061"},{"speaker":"こしば委員","kind":"質問・要望","question":"そうしますと、例えば高齢者の方が、井戸から自宅まで１００Ｌの水を持ち運ぶということは、大変これはこれで課題ではないかなと思います。そういったことに対しても、品川区でこの購入補助もぜひ検討をしていただきたいと考えておりますが、ご見解について説明を求めました。","respondent":"遠藤防災体制整備担当課長","answer":"井戸の水を運搬する支援がないかといったところのお尋ねかと思います。こういった補助も幅広く利用していただけることで、またその災害対策用井戸の活用範囲というものも広がるのではないかと考えています。","id":"exchange-062"},{"speaker":"こしば委員","kind":"提案","question":"去年の一般質問で、平成２５年から３年の間、これの提案をさせていただきました。東京都に無償で貸与してもらうよう要望していくということを検討していきたい、その後、進捗についても教えてほしいと求めました。","respondent":"遠藤防災体制整備担当課長","answer":"東京都からは、応急給水手段としまして、消火栓から給水するための資機材について、現在、各区民避難所に提供を受けているといったところです。東京都と意見交換する場では、非常時の応急給水活動については…","id":"exchange-063"},{"speaker":"こしば委員","kind":"質問・要望","question":"ぜひ今後もこちらの応急給水器の無償貸与、引き続きもう少し数を増やしていただくよう、都に要望してほしいと求めました。品川区のこの災害計画、様々ありますけれども、その計画にはこの防災公園をどのように位置づけていき、今後活用していくのか説明を求めました。","respondent":"羽鳥防災課長","answer":"今も様々な防災の資機材が設置されておりますので、そういったものを活用しながら訓練を実施いただきまして、そのようなことを認識していただく。それぞれ訓練で練度を高めていただいて、地域の防災力向上を努めていただきたいと考えています。","id":"exchange-064"},{"speaker":"こしば委員","kind":"質問・要望","question":"こういった井戸を使うのは地域の方々ですので、ぜひこの認知度を高めていただくよう取り組んでいただきたいと要望いたしまして、次の質問に移ります。そういった相談や、廃止に至る経緯について、また改めて教えてほしいと求めました。","respondent":"櫻木地域交通政策課長","answer":"時期は未定であるが将来的な検討を進めているという話がありまして、区としましてはその場で、その話は受け入れることはできないと。その後事業者でご検討いただきましたが、改めて再検討を申し入れるとともに、しなバス等の調整を図り始めたという経緯です。","id":"exchange-065"},{"speaker":"こしば委員","kind":"質問・要望","question":"どうにかしてもらいたい。地域の方々がどの程度お困りになっているのかをつぶさに聞いていって、このアンケートを早急に実施してほしいと求めましたが、見解を伺います。","respondent":"櫻木地域交通政策課長","answer":"区としましては、公共サービス圏域外の解消に尽力します。今後の検討の中で区民のご意見をしっかり伺いながら、検討を進めていきたいと考えております。","id":"exchange-066"},{"speaker":"中塚委員","kind":"質問","question":"３５５ページの市街地整備事業費より、西大井駅周辺の再開発について伺いたいと思います。新たに上位計画を定めるものなのか、そして品川区まちづくりマスタープランの改定を見通したものなのか伺いたいと思います。","respondent":"中道都市開発課長","answer":"回答者につきましても、１０代の方から７０代まで均等にいただいたというところを把握しています。ビジョン策定またはその再開発ありきで実施したものはないというところで、こういった西大井のまちづくりに関連する予算は計上しないです。","id":"exchange-067"},{"speaker":"中塚委員","kind":"質問","question":"私もその１人ですが、人も車も地元の人しか通らないので、とても静かですと。やはり念頭にあり、つなげたいという考えがそこにあると、住民を困らせるような計画はやめてほしいと思いますが、いかがか尋ねました。","respondent":"中道都市開発課長","answer":"これまで進められてきました市街地再開発事業については、反対の声も含めて、様々な声が来ているというところは事実です。こうした声にきちんと対応したいという考えでございまして、制度の課題であったり、今後のまちづくりについてあり方を考えていきたいと考えています。","id":"exchange-068"},{"speaker":"中塚委員","kind":"質問・要望","question":"検証・分析のところですけれども、予算の初日にも伺いましたが、今年度は要綱を変えてなどの検証と述べておりました。なぜ住民が追い出される、そして公表を求めたいと思いますが、いかがか尋ねました。","respondent":"中道都市開発課長","answer":"この事業を進めることができるとされているものですけれども、３分の１の反対者がいても事業を進めることができるということになってあります。事業者に対して指導するとともに、区もより多くの方が理解し、同意したまちづくりを目指していきたいと考えています。","id":"exchange-069"},{"speaker":"中塚委員","kind":"質問","question":"新年度はどのような検証・分析を行うのかと伺いました。今のご説明ということか尋ねました。","respondent":"中道都市開発課長","answer":"新年度の取組については、具体的に考えていきたいと考えていますが、やはり反対の声が上がっているというところは事実ですので、そういった状況、そういったことをきちんと区としても受け止めて、中立な立場で対応していきたいと考えています。","id":"exchange-070"},{"speaker":"松永委員","kind":"質問・要望","question":"そうしたアンケートの中でどういった要望が多かったのかということをお聞きしたいのと、その中で、浜川砲台についてもどのように変わるのでしょうか。先ほど、そうしたご要望等も含めて、区としてどういった形で検討されているのかを伺いたいと思います。","respondent":"大友公園課長","answer":"こちら、町会、近隣の居住者、近隣住民のアンケート、また公園利用者のヒアリング、関係者ヒアリングと様々実施しています。その利用者の自転車が多く駐輪されているという一方で、近隣住民としても貴重な球技ができる場所としての認識があり、残存を望む声が多くあります。","id":"exchange-071"},{"speaker":"松永委員","kind":"質問","question":"そうしたところも含めての改修工事になるのでしょうか。それの広域な改修工事の範囲というのはどういった形になるのか、伺いたいと思います。","respondent":"大友公園課長","answer":"範囲ですけれども、多分、委員のおっしゃられたところ、道路を挟んで北側の部分になるのかと思います。そちらの場所も含めての改修工事となる予定です。","id":"exchange-072"},{"speaker":"松永委員","kind":"質問","question":"続きまして、喫煙所の保守・管理について伺いたいと思います。お願いします。","respondent":"大友公園課長","answer":"この地域課題等々を踏まえて、再度オープンさせるかどうかというところを検討していたところです。いただいている声等々を集めて、地域活動課とも連携して、どうしていくとかという方針については早めに決定をしていきたいと考えているところです。","id":"exchange-073"},{"speaker":"松永委員","kind":"質問・要望","question":"もう少しパーティションをつくるのであれば、煙が少しでも出ないようなつくりにしてほしいという要望が何件か届いております。パーティションを広くすると書いてあるのですけれども、あれからどのぐらい、要するに喫煙スペースが増えるのかということを伺いたいと思います。","respondent":"大友公園課長","answer":"大井町駅周辺の少し公園となかなか認識されにくいところにはあるのですけれども、大井駅前公園に設置されている喫煙所の件かと思われます。我々としても広げるというところで認識をしているのですけれども、詳細まで把握ができていないというところがございまして、すみません。","id":"exchange-074"},{"speaker":"松永委員","kind":"質問・要望","question":"そうしたところで、今後、区民の声をしっかりくみ上げてほしいと求めました。品川区はどう対応していかれるのかということも踏まえて、喫煙所ということを設置も含めまして、要望して終わりたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-075"},{"speaker":"あくつ委員","kind":"提案","question":"令和７年６月の一般質問において、森澤区長からご提案の仮称「しながわ防災区民憲章」について、ようやく７年越しでの実現となりました。各避難所ごとのマニュアルに合わせてカスタマイズしなければいけないからどうなのでしょうかということだったのですが、ぜひ…","respondent":"羽鳥防災課長、遠藤防災体制整備担当課長、櫻木地域交通政策課長","answer":"こちらも新たに災害が起きて、新たな教訓を得られるということであれば、こちらの内容も更新することは考えてあります。細かな行動指針につきましては… 令和８年度から入札手続を開始しまして、その後、区内一斉防災訓練までの間に作成するのは非常にスケジュールがタイトという状況になっております。… 住民説明会におきましては、横断歩道が難しい場合はエレベーターをきちんと設置してほしいというお声をいただいております。…","id":"exchange-076"},{"speaker":"あくつ委員","kind":"質問・要望","question":"２点目の避難所開設キットの件、お聞きするだけでも非常に厳しい日程だと思うのですけれども、ぜひよろしくお願いいたします。これは令和３年から国に要望してつくっていただいていますが、たしか４回か５回、もう既にやっていると思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-077"},{"speaker":"吉田委員","kind":"質問・要望","question":"ご意見があれば受け入れているというご答弁がありましたが、ここで求めたいのは、その点について伺いたいと思います。まだであるなら、この国土交通大臣のご発言を受けて設置を検討していただきたいと考えますが、その点についても伺いたいと思います。","respondent":"中道都市開発課長","answer":"ご意見いただきました、そういった移転に対する対応を気軽に相談できるように相談窓口を設置するよう、準備組合にお願いをしています。準備組合が入った相談窓口ということではなくて、専門家、コンサルタントが対応できるような形で設置するという回答をいただいているところで…","id":"exchange-078"},{"speaker":"吉田委員","kind":"質問・要望","question":"私がこういう質問をした意図は、やはり国土交通大臣が自治体に対してそういうことをきちんと求めていくというご答弁だったと理解しております。ぜひ、困ったらここに相談しに来ていいという積極的な広報をお願いしたいと思っての質問なのですが、いかがか尋ねました。","respondent":"中道都市開発課長","answer":"区民からやはり品川区から、まず、区が発行する「まちづくりニュース」をエリアを拡大してお知らせするような取組をしていきたいと考えています。委員からいただいた、行政に相談しやすいようにといった内容も記載して、まずはその周知を図りたいと考えています。","id":"exchange-079"},{"speaker":"吉田委員","kind":"質問・要望","question":"今のご答弁の中で少し気になったのが、品川区の「まちづくりニュース」の発行の仕方というか内容なのです。下手に再開発を推進する側に使われてしまわないような表現を求めたいと思いますが、その点についていかがか尋ねました。","respondent":"中道都市開発課長","answer":"いわゆる区の立場、要するに中立的な立場で、今のまちづくり状況を知りたいという声もいただいているところです。区が発行することによって誤解を生まないかというところもやはり一つあるかと考えていますので、今後、深く検討して発行したいと考えています。","id":"exchange-080"},{"speaker":"吉田委員","kind":"質問・要望","question":"１分ありますので、次の公園・児童遊園維持管理費についても伺います。２月の半ばぐらい、いつこれは直るのですかというお問合せをしたのですけれども、いつ直る予定ですとかいう表示も何もありません。","respondent":"大友公園課長","answer":"修繕に一定、時間がかかるもの等々については、適切な形で区民の分かる形の表記等もしていきたいと考えています。速やかな修繕に努めてまいります。","id":"exchange-081"},{"speaker":"せお委員","kind":"質問・要望","question":"そしてできれば個人にもなのですけれども、通知を出すなどの取組を求めたいですが、見解をお聞かせください。今までの経験から課題解決を諦めるのではなく、改めて解決方法を検討してみる、そのような仕組みを求めますが、見解を説明を求めました。","respondent":"山下交通安全担当課長","answer":"その都度その都度で速やかな対応をとっているところでございまして、できるだけ速やかな対応をとっていけるように、これからも努力してまいります。来月実施します交通安全運動の中でも、歩行者は優先なのだというところの重点も掲げる。","id":"exchange-082"},{"speaker":"せお委員","kind":"質問・要望","question":"ぜひそれぞれご検討いただきたいと思っています。そこで、今回はどのような進め方をして、利用者の声はどのように反映されるのか、改めて説明を求めました。","respondent":"大友公園課長","answer":"改修を実施するものですが、特別支援学校、そのアイデアブックを活用してインクルーシブな公園として整備してまいるものです。","id":"exchange-083"},{"speaker":"大倉委員","kind":"質問","question":"今、品川区の防災認定マンションみたいなのを進めていくというのもできるのではないかと思っているので、どうでしょうかということです。例えば１００枚、カラーコーンを１０個回収したとかというのを見える化していったり、この点についてお考えを伺います。","respondent":"川原住宅課長、羽鳥防災課長、川崎土木管理課長","answer":"１点目にお尋ねの子育て世帯への住まいへの支援というところで。全体の地域力の向上というところにも資する施策としても… 昨年の８月末時点では１９件、今年の２月１日時点では３２件ということで、登録件数は増えてきているのかとは認識しています。ＡＥＤの設置につきましては… 区としても今後、美化に努めていただく方の声をお聞きしながら、表現していただけるかというのは工夫のところだと考えています。…","id":"exchange-084"},{"speaker":"大倉委員","kind":"質問","question":"加入した後、どうなるか分からないというところで、やはり区の思いをしっかりと酌み取ってもらうというのが大事かと思っています。そうすると地域にも還元できるというところで、この商品券の活用というのはどうか尋ねました。","respondent":"川原住宅課長","answer":"商品券の活用というところでは、現在のところ、予定はしてございませんが、こういった施策は引き続き研究をしてまいりたいと思います。","id":"exchange-085"},{"speaker":"大倉委員","kind":"意見","question":"商品券だとその地域で使うしかないので、地域のことをよく知れると思います。こういったことも含めて、使いやすいのは現金だと思いますけれども、せっかく補助するので、そういったことも考えてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-086"},{"speaker":"やなぎさわ委員","kind":"質問・要望","question":"その上で、さらに助成を拡大していただきたいと考えておりまして、品川区で生まれ育った若者が区内で転居する際も対象を広げてほしいという要望です。今後、さらにこういった状況は加速していくと思いますので、ぜひ、このような状況を解消する支援策拡充を求めたいのですが、いかがか尋ねました。","respondent":"川原住宅課長","answer":"住宅課の居住支援事業の中でも、令和３年度からこれまでに５３人の若者に、入居の入り口の部分のあっ旋というところは実施をしています。今後もこういった若者をはじめとした住まいの大きな支援策は、まずは子育て世帯への住まいの支援をやってまいりたいと考えています。","id":"exchange-087"},{"speaker":"やなぎさわ委員","kind":"質問","question":"これに関連して、次の質問なのですけれども、賃貸契約の更新のときに、１.５倍とか２倍とかのかなりの額の値上げを要求される。区としてこういった相談というのは今、現在どれぐらい寄せられていますか。","respondent":"川原住宅課長","answer":"住宅課では住まいの相談窓口を今年度５月から開設したところですが、住宅課の窓口として相談に来た件数としては１件のみでございました。宅地建物取引士であるとか、弁護士などの専門家の相談へつないで、そういったご案内を丁寧にさせていただいているところです。","id":"exchange-088"},{"speaker":"やなぎさわ委員","kind":"質問・要望","question":"区民負担の軽減につながる具体的な方策の提示と、その実施を早期に行うことを求める」と要望されました。港区といった他の区長の方と連携して、国への要望をしていただきたいと考えておりますが、いかがか尋ねました。","respondent":"高梨都市計画課長","answer":"区長が２度にわたり、国が応えて、海上ルートの実現に向けた検討の方向性等が示されたところです。こちらに区は毎回参加をしてございまして、そういった連絡会の場を用いて、関係区とは連携を引き続き図ってまいりたいと考えております。","id":"exchange-089"},{"speaker":"やなぎさわ委員","kind":"質問","question":"一番、先頭に立ってこういった音頭をとっていただけると、非常に区民としても心強いのかと思います。そして、課長レベルでの連携や情報交換といったものは、現在のところいかがか尋ねました。","respondent":"高梨都市計画課長","answer":"課長レベルでの連携といったところですが、先ほどご案内させていただきました連絡会でのネットワーク、顔を見る関係で会議で顔を合わせておりますので、そういった中で、隣接自治体とは課長級でも必要に応じて密に連携をとらせていただいているという状況です。","id":"exchange-090"},{"speaker":"やなぎさわ委員","kind":"質問・要望","question":"最後、時間がないので要望だけ。こういったこともぜひ検討して、研究してほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-091"},{"speaker":"塚本委員","kind":"質問","question":"３７７ページ、それから３５１ページ、暑熱対策都市戦略「（仮称）シェードポリシー」の策定検討等業務委託について伺っていきたいと思います。これについてお伺いいたします。","respondent":"遠藤防災体制整備担当課長","answer":"こちらにつきましては、国で、抽出した自治体に対して国費で支援をするという方針を固めました。区民の手続の煩雑さ、あるいは設置費用の負担軽減が図れるといったところで、事業の適正な実施をこういう形で図っているものです。","id":"exchange-092"},{"speaker":"塚本委員","kind":"質問","question":"日頃付き合いのあるというか、よく知っている電気工事の関係の業者の方にこういうのがあるからお願いしたいのだけれどもと。この件に関して、なぜそのような形になっているのか、また改善する余地はないのかについてお伺いしたいと思います。","respondent":"遠藤防災体制整備担当課長","answer":"組合に幅広くご協力いただくといったところが、区の感震ブレーカー普及を進めていく上でも非常に重要なことということは認識しています。課題解決を進めるよう、感震ブレーカーの普及・促進できるよう環境づくりに向けて取り組んでまいりますので、よろしくお願いいたします。","id":"exchange-093"},{"speaker":"塚本委員","kind":"質問","question":"そういったところから、区としての方針の転換みたいな方向が見受けられると思いますけれども、この考えについての区の見解をお伺いします。こういったことに対して、このシェードポリシーを進めていく上で、課題解決策としてどういう考えをお持ちか、最後にお伺いいたします。","respondent":"高梨都市計画課長","answer":"熱中症対策と両輪で進めてまいりたいと考えています。海外事例等をしっかりと研究をして、提供できるような内容について、来年度しっかりと考えてまいりたいと考えています。","id":"exchange-094"},{"speaker":"のだて委員","kind":"提案","question":"品川区としても、このバス停の占用料の減免を検討してほしいと求めましたが、いかがでしょうか。全額免除をした際に必要な額が分かれば伺いたいと思いますとの意見を述べました。","respondent":"川崎土木管理課長","answer":"行政による財政支援は難しく、また新たにバス停を設置した際の道路工事に係る部分の支援は難しい状況ではあるのですけれども、費用面も含め。全体で、民間事業者含め都バスも含めになりますけれども、７７基とこちらでは認識はしております。","id":"exchange-095"},{"speaker":"のだて委員","kind":"質問・要望","question":"３つ目の支援を求めたいと思いますが、バス停へのベンチと屋根の設置です。品川区としてこのバス停へのベンチと屋根の設置への支援をしてほしいと求めましたが、いかがか尋ねました。","respondent":"櫻木地域交通政策課長","answer":"占用基準がございまして、円滑な通行の障害とならない道路幅員２.５ｍ以上がある場所でならないと設置できないということになっております。ご要望と個別のご相談に応じて、設置できる場所についてはお休み石を設置することは可能かと思いますので…","id":"exchange-096"},{"speaker":"のだて委員","kind":"質問・要望","question":"伺います。区としてはどのように考えているのかというのと、区としてこの樹冠被覆率の調査をしてほしいと求めましたが、いかがか尋ねました。","respondent":"高梨都市計画課長","answer":"ご提案いただきました樹冠被覆率ですけれども、光の効果を強化するための指標として有用であると認識しています。一方で測定するには一定の期間と費用もかかることから、シェードポリシーの適用については、来年度しっかりと検討してまいりたいと考えています。","id":"exchange-097"},{"speaker":"須貝委員","kind":"質問","question":"私は３５１ページ、都市防災まちづくり事業費についてお聞きしたいと思います。こういうことを考えると、独自に戸別配達をやはりやるべきだと思うのですが、広報について、ご見解を説明を求めました。","respondent":"羽鳥防災課長","answer":"防災課としては、「しながわ防災ハンドブック」でも周知しておりますし、あとしながわ防災学校ということで、対面での研修の場でも周知をしています。引き続き、様々なメディアを通じて機会を捉えて周知してまいりたいと考えています。","id":"exchange-098"},{"speaker":"須貝委員","kind":"質問","question":"私は年に４回ぐらい、私はせっかく防災課でこれだけのことをやっているのですから、協力してくださいという姿勢は大事ではないかと思うのです。防災訓練を見ても、どれだけの人が参加しているのか尋ねました。","respondent":"羽鳥防災課長","answer":"しながわ防災区民憲章を活用しながら、区民の皆様の日々の活動の中にこの憲章に触れる機会を増やして、意識の啓発は努めてまいりたいと考えています。そのような様々な取組を現在進めているところです。","id":"exchange-099"},{"speaker":"田中委員","kind":"確認","question":"時間が余りましたら、余った時間に応じて質問をしていきたいと思います。この公園の名前はどのような形で決められていくのか、まず確認したいと思います。","respondent":"大友公園課長","answer":"地域が親しみの持てる名称であることや、願望、イメージを園名とするときには、規模、内容、地域性を考慮すること。土地の名所旧跡、町名、歴史的命名をする場合については、古地図や旧町名、区市など十分検討の上、命名することなどに留意して決定しています。","id":"exchange-100"},{"speaker":"田中委員","kind":"質問","question":"その上でですが、一旦、では決められた公園の名前を変更するということは可能なのでしょうか。変更するに当たって、どのような手続が必要なのでしょうか、お伺いします。","respondent":"大友公園課長","answer":"公園の名称の変更は、まずできるかできないかというと、できないものではございません。長年にわたり、また、地域として変更することが望ましいという意見であることが欠かせない条件になってくるのかというところで考えてあります。","id":"exchange-101"},{"speaker":"田中委員","kind":"提案","question":"その上で、提案も含め、質問しますが、現在、西大井六丁目に伊藤博文公のお墓があります。長くなりましたが、伊藤公公園なり伊藤公園なりにしてほしいと求めましたが、いかがか尋ねました。","respondent":"大友公園課長","answer":"ご提案いただきました西大井緑地公園の公園名の変更に当たってなのですけれども、やはり地域の意見がとても重要になると考えているところです。地域として名前の変更が望ましいという機運が高まっていることなどが、名称変更の契機になると認識しております。","id":"exchange-102"},{"speaker":"田中委員","kind":"質問・要望","question":"二度とそういう水害を起こさないでほしいという思いから、防水板の設置助成の議決をして、予算が決定されているわけです。助成が受けられないということは、私は納得できないのですけれども、納得できる回答をほしいと求めました。","respondent":"関根河川下水道課長","answer":"この止水板設置等助成につきましては、取り外しまたは移動が可能なものであったり、一定の要件を定めてあります。事前にご相談、ご申請をいただいた上でお支払いをするという形をとらせていただいております。","id":"exchange-103"},{"speaker":"田中委員","kind":"質問","question":"１軒、そのときになぜそういう制度がある、そこまでなぜ説明しなかったのか。そこに瑕疵があると思いますが、いかがか尋ねました。","respondent":"関根河川下水道課長","answer":"助成を期待して設置をしたが、もし事後申請を可能とした場合に生じる可能性があると考えておりまして、事前申請という形でお願いをしています。今後、そうした制度の周知については、さらに徹底をしていきたいと考えています。","id":"exchange-104"},{"speaker":"田中委員","kind":"質問","question":"最後、もう時間がないのですけれども、ここは予算執行権の問題だと思います。私は区長のご決断があれば、この件に対しては対応してもらえるのではないか、解決できるのではないかと考えていますが、いかがか尋ねました。","respondent":"関根河川下水道課長","answer":"こちらは、やはり先ほど申し上げたような形で、区民にとっても、行政にとっても、しっかりとした望ましい形で助成するために、事前申請は必要だと考えております。","id":"exchange-105"},{"speaker":"西本委員","kind":"質問","question":"気になるのは日中、夜間、土日など、やっぱり環境によって協力し合うということが変わってくると思うのですが、どういう形になっていますでしょうか。いつまでやるのか尋ねました。","respondent":"中道都市開発課長、遠藤防災体制整備担当課長、櫻木地域交通政策課長、大友公園課長","answer":"実施内容ですけれども、または空きスペースで子どもが道路で遊べるような空間をつくったりとか、ランチコンサートを実施したところです。… 土日を問わず、行き場のない帰宅困難者に関しまして、ＯＩＭＡＣＨＩ ＴＲＡＣＫＳで約３,０００人を受け入れることになってあります。… 福祉という観点もございましたが、例えば荏原地区でのデマンド交通につきましては、一定福祉の観点も入れた上での事業に取り組んでいるところです。… 区内に残された数少ない大木…","id":"exchange-106"},{"speaker":"西本委員","kind":"質問・要望","question":"だけど、要望が多いということで今回延びましたよね。これは要望といたしますが、ＯＩＭＡＣＨＩ ＴＲＡＣＫＳの件だけお願いいたします。","respondent":"遠藤防災体制整備担当課長","answer":"災害時に延焼火災があった場合、こちらは広域避難場所として一体的に指定される予定になってあります。実効性のある訓練といったところにつきましては、帰宅困難者対策協議会というものがございまして、こちらの中で帰宅困難者訓練を行っている状況です。","id":"exchange-107"},{"speaker":"こんの委員","kind":"提案","question":"大森貝塚発掘１５０周年事業、３７７ページ、感震ブレーカー普及事業からお伺いしたいと思います。木質系であれば木造だし、こうした住宅もエリアの中でそうした建物があった場合には対象になるのでしょうか、お聞きしたいと思いますとの意見を述べました。","respondent":"大友公園課長、遠藤防災体制整備担当課長","answer":"令和７年３月に策定いたしました品川区災害時トイレ確保・管理計画により、公園へのマンホールトイレの整備を進めていくものです。庭園を全面リニューアルするのではなくて、今ある説明板や展示ブース… 防災区民組織が組立て訓練等を実施しておりますので、災害時には主に防災区民組織が主体で活用するといったところを想定しています。家屋の種別を問わずに対象とするという方針を現在示しているところですので、木造…","id":"exchange-108"},{"speaker":"こんの委員","kind":"質問・要望","question":"今後この金網ではない素材で抜本的な改善をしていったほうがいいと思いますけれども、いかがでしょうか。国で構造を限定しないですので、来年度は限定されていますが、今後は区内全域に広がるように要望したいと思いますが、いかがか尋ねました。","respondent":"大友公園課長","answer":"最終的には今１６か所程度の整備を予定しているところではありますけれども。抜本的な解決に当たりましては、その課題解決に向けて今後検討してまいりたいと考えています。","id":"exchange-109"},{"speaker":"石田（秀）委員","kind":"質問","question":"我々の会派のこしば委員が先ほど大分質問をして、すごくいいことを言っていたのだけれども、答弁がどうもかみ合わないと思ったので改めて伺います。それは何か所あって、３分以内だったら１８０か所、どうやって持っていくと考えているか、それを教えてほしい。","respondent":"遠藤防災体制整備担当課長","answer":"そのほかでも相談をいただいていますので、不確定な数字ではありますが、１００か所以上は区内に存在しているのかなと認識しています。今後整備を進めていく上で、区全域で見た上で２００ｍといったところを解消していくような形で取り組んでいきたいと考えております。","id":"exchange-110"},{"speaker":"石田（秀）委員","kind":"意見","question":"どんどん増やしてほしい、お金が入ってくるのだから、７０万円ぐらい。ぜひそういうことをやってほしいと思うので、その貸切りの話をしてほしいとの意見を述べました。","respondent":"大友公園課長、遠藤防災体制整備担当課長","answer":"現在、水族館で実施しております夜間の貸切り営業ですけれども、会場料金は２２万円からとなっております。水族館で実施しているこの夜間貸切り営業の実績は、今年度だけでも既に２８件、１,８００万円程度売上げております。 来年度速やかに実施していきながら、２００ｍ以内に届かないといったところを区としても状況を把握していきますので、よろしくお願いいたします。","id":"exchange-111"},{"speaker":"石田（秀）委員","kind":"意見","question":"ぜひそれは、もっと営業してほしい。そうするのだったら、それまでの間に一生懸命いろいろやってほしいと思いますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-112"},{"speaker":"高橋（し）委員","kind":"質問・要望","question":"私もご要望をお届けしましたが、どのような地域の声があった成果なのでしょうか、お尋ねします。ほかの委員の方の質問もありましたが、樋門というのでしょうか、完成時との一体性の構想はどのようになっているのか尋ねました。","respondent":"櫻木地域交通政策課長、大友公園課長、羽鳥防災課長","answer":"バス停の件です。もしくはいすゞ病院を使いたいというお声に十分答えられていなかった状況でございまして、そのようなお声が届いていたところです。 暑熱対策としての個々の取組を実施するだけでは限界があることから、一旦立ち止まって暑熱対策のあり方を検討することとしたためです。… 私からは、防災課から発送いたしました誤送付についてご説明をします。リリースの文案につきましては、所管と連携を取りながら作成したものです。","id":"exchange-113"},{"speaker":"高橋（し）委員","kind":"確認","question":"そして、全て回収ができたのかどうか、発送作業は区の職員の方が行ったのか、それとも委託の方が行ったのかについてお尋ねします。その点はいかがか尋ねました。","respondent":"羽鳥防災課長","answer":"現在、引き続き回収の作業を進めておりまして、約６割は回収済みという状況です。誰がですけれども、今回は区の職員が印刷をしています。","id":"exchange-114"},{"speaker":"高橋（し）委員","kind":"確認","question":"ホームページの公開情報だと、単なる確認不足ではなく、まず一つ、その事案の重さが見えなかったということが問題だと思います。そして、今回は単なる確認不足ではなく、事故発生時の説明責任を含める区役所のコンプライアンスの問題だと考えます。","respondent":"羽鳥防災課長","answer":"公表につきましては、所管と連携を取って公表させていただいたです。今後の対応といたしましては、職員が印刷作業を今後も行うのかどうかというところも含めて、検討を行ってまいりたいと思います。","id":"exchange-115"},{"speaker":"松本委員","kind":"質問・要望","question":"公営住宅法を見ると３か月以上の滞納者には明け渡しを求める、滞納３か月で停止条件付の契約解除通知を発行している自治体もあります。むしろ区民住宅だからこそ法的措置滞納者への移行というのが６か月というのは少し長いように思うのですけれども、いかがか尋ねました。","respondent":"川原住宅課長","answer":"６か月以上の滞納というところで今回判断をいたしましたが、こういった区の呼出しにも応じないということも処分の大きなきっかけになったところです。適切に、基本は６か月という形にはなるのですけれども…","id":"exchange-116"},{"speaker":"松本委員","kind":"質問","question":"今回の事項別の明詳書を拝見すると、報酬として１０２万円というのが計上されていて、あと相談料として７９万２,０００円が計上されています。この手数料というのは何を意味するのか尋ねました。","respondent":"川原住宅課長","answer":"手数料というものは裁判所に提起をする際の印紙などの証明手数料などです。事務的な手数料という形です。","id":"exchange-117"},{"speaker":"松本委員","kind":"質問","question":"審議会のいろいろな附属機関の委員とか、こういうところについてはどうなのかなというところも出てくるのではないかと思います。ここで削減した予算をほかで使っていただく、ＡＩも使いつつやっていただくというのも一つの考え方ではないかと思いますが、いかがか尋ねました。","respondent":"川原住宅課長","answer":"ご提案いただきまして、ありがとうございました。今後そういった形で滞納整理を進められるかというところは研究してまいりたいと考えています。","id":"exchange-118"},{"speaker":"松本委員","kind":"意見","question":"ただ品川区も、先ほど申し上げたようにＡＩを活用していろいろな業務を代替するというふうなチャレンジングなことをやっていただいています。多分訴状は本当にそんなに難しくないというか、ぜひこれまでの枠組みにとらわれない執行のあり方、運営のあり方を考えてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-119"},{"speaker":"石田（ち）委員","kind":"質問","question":"新年度予算には、品川浦周辺地区情報発信等支援業務委託で６４０万円になっているのですけれども、これは何を委託するのか伺います。いつ頃の策定を予定しているのか伺いたいと思います。","respondent":"大石まちづくり立体化担当課長","answer":"同様に意見交換会の開催、またはアンケート等を実施して、まちづくりのガイドラインの策定を今後検討していきたいと考えているところです。なお、令和８年度につきましては、ガイドラインの策定は予定してございません。","id":"exchange-120"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"それと、このアンケート等も実施していくということなのですけれども、このアンケートの目的は何か伺いたいと思います。アンケートの対象について、計画地区内だけではなく、少し広げていただきたいと思うのですけれども、いかがか尋ねました。","respondent":"大石まちづくり立体化担当課長","answer":"その観点から、説明会方式で意見を伺うことも一定検討はさせていただいたのですが、ワークショップにしたです。アンケートをどういうふうにやっていくかというところはまだ検討中でございまして、今後検討してまいりたいと、このように考えているところです。","id":"exchange-121"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"代表質問で、まちづくりガイドラインは再開発を前提にしているのかと聞きましたけれども、区は再開発を前提にしたものではないと答弁していました。不安との声が出されたと思いますけれども、区は再開発事業ではないまちづくりを進めていくということになるのか伺いたいと思います。","respondent":"大石まちづくり立体化担当課長","answer":"地域資源です歴史と水辺を活かした、後世まで残るまちの将来像や防災面などを踏まえたまちづくりの方向性を示す計画を予定しています。例えば策定後には個別の建て替えの相談において、こういった側面もありますので…","id":"exchange-122"},{"speaker":"石田（ち）委員","kind":"質問","question":"でも、そこに区としても補助金を出す考えもないしということですから、再開発は大分難しくなってきたのではないかなと思うのです。再開発を誘導する上位計画そのものを変える必要があるのではないかと思うのですが、いかがか尋ねました。","respondent":"大石まちづくり立体化担当課長","answer":"品川駅南地域のまちづくりビジョン、このようなもので上位計画を基に今地域ではまちづくりの検討が進められているところです。直ちに上位計画等を改定する予定はございませんが、そのような意見を踏まえながら検討してまいりたいと、このように考えているところです。","id":"exchange-123"},{"speaker":"石田（ち）委員","kind":"意見","question":"環境の面からも逆行するし、防災面でも脆弱性が指摘をされております。この超高層再開発を誘導する区の方針は考え直すべきだと思いますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-124"},{"speaker":"若林委員","kind":"提案","question":"区としても関係機関と連携し、訓練参加が円滑に行われるように支援をしてほしいと求めましたが、区のお考えをお聞きします。今後も議会の提案、またこういった地域の実践者の知恵が防災に限らず、区民サービスの充実となるように期待をいたしますとの意見を述べました。","respondent":"星災害対策担当課長、遠藤防災体制整備担当課長、森道路課長、山下交通安全担当課長","answer":"本年３月に東京都がモバイルファーマシーを導入し、東京都薬剤師会と連携して運用し、区市町村への連携訓練を進めるというところは聞いております。… 製作に関しましては、現在計画しているところは、マニュアルに記載する手順書等の検討に約半年、キットの製作に２か月程度を当初想定しています。… 植え替えや診断の長期的な考え方ですけれども、約４,０００本の街路樹のうち、２,３００本強を診断対象としております。桜につきましては… 他の商店街等でも実施しているのですけれども…","id":"exchange-125"},{"speaker":"若林委員","kind":"質問・要望","question":"それぞれ前向きなお話を伺えたと思います。しっかりと力強く前進してほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-126"},{"speaker":"藤原委員","kind":"質問・要望","question":"私は、また令和８年度からの５年延長という話を毎回要望してきましたけれども、どうなっているか教えてください。だから一日も早く駐輪場を造っていただきたいと思うのですけれども、いかがか尋ねました。","respondent":"堀越副区長、藤村総務課長、森建築課長、森道路課長、高梨都市計画課長、川原住宅課長、小川木密整備推進課長、山下交通安全担当課長、櫻木地域交通政策課長","answer":"実際に遭遇した大きな体験を今後の地震の防災対策、電力以外の場合も含めて、しながわ防災区民憲章、昨日発表もありました。… こちらの事業は平成１８年度から実施しているもので、今まで平成１８年度から始まって以来、震災ですとか様々な危機事象がございました。… 細街路拡幅整備工事の始まる前の協議段階で、土地所有者等に対して電柱の移設についてご理解を求めているところです。仮に断られた場合でも… 狭くても区道においてはしっかりと無電柱化を進めていくべきだとは思いますけれども…","id":"exchange-127"},{"speaker":"藤原委員","kind":"質問・要望","question":"ずっと品川区にいていただきたいですが、同じ公務員ですから働いていただきたいと思うのですが、その辺はいかがでしょうか。その辺についてお伺いします。","respondent":"柏原区長室長、鴇田都市整備推進担当部長、加島財政課長、鈴木都市環境部長","answer":"私からは、危機管理宿直についてお答えいたします。区としての危機管理に対する姿勢というところは変わるところはありませんので… あくまで本日時点で都への帰任を聞いているわけではありませんが、この２年間私なりに再開発関連をはじめ、私なりに一生懸命取り組んでまいりました… 都市計画交付金につきましては、委員からもございましたように交付金の規模が特別区の実施状況に合っていないという状況にあります。… 大井町Ｗａｌｋｅｒということですので、くしくも今月…","id":"exchange-128"},{"speaker":"まつざわ委員","kind":"意見","question":"東京都の令和８年度の予算案を見ますと、暑さ対策の推進経費には約３０億円、東京都には相当大きな予算がついています。このシェードポリシーを世界に誇れるクールシティ品川の礎とすべきではないかと考えますが、まずは区の意気込みを聞かせてくださいとの意見を述べました。","respondent":"高梨都市計画課長","answer":"公園内のミスト設置などの取組を行ってまいりましたが、海外事例などを参考に、より厳しくなる気候変動に対応した都市モデルを構築することを目指し。来年度予算についても確認をしておりまして、軌を一にする事業を洗い出し…","id":"exchange-129"},{"speaker":"まつざわ委員","kind":"質問","question":"容積率の緩和であったりとか、都のスマートシティ推進予算等を活用した補助金など、インセンティブを設計するべきだと考えています。こういう実効性のある仕組みをぜひ検討するべきだと思いますが、ご見解を説明を求めました。","respondent":"高梨都市計画課長","answer":"まち全体として日差しや暑さへの対策を行っていく上で、民間の建築物等の取組を誘導し、協力を得ていくことは重要であると認識をしています。委員ご提案の内容、より実効性のある取組について、東京都を含めて来年度の検討の中で考えてまいります。","id":"exchange-130"},{"speaker":"まつざわ委員","kind":"確認","question":"品川区中高層建築物等の建設に関する開発環境指導要綱の中でインセンティブを考えているということで確認しました。これを品川区のブランディングにどうつなげていくのか、区の戦略的なものを説明を求めました。","respondent":"高梨都市計画課長","answer":"事業者の協力も得ながら、実証や検証を行うことも一つの可能性として考えてあります。本戦略が、品川区に来られる方々にとっても魅力と感じることができるようなものになるようにしっかりと取り組んでまいりたいと考えています。","id":"exchange-131"},{"speaker":"まつざわ委員","kind":"質問・要望","question":"データのお話を前回させていただきましたけれども、しっかりとしたこの人流の技術というのですか、ＡＩを活用してほしいと求めました。従来の受付業務がこのＤＸを入れたことによって、どういうふうに改善されて、どんな期待をしているのか、区の考えを説明を求めました。","respondent":"羽鳥防災課長","answer":"本システムの構築に関しましては、区の職員が実施をしております。例えば、区民の方からいろいろなアドバイスをいただいた、そういったご意見を柔軟に反映することができるといった効果も見込んでいるところです。","id":"exchange-132"},{"speaker":"まつざわ委員","kind":"質問・要望","question":"マイナンバーカードというのは要らないかもしれないですけれども、また、そこら辺の確認をさせてください。カード未登録の携帯でも窓口のタブレットで即座に本人確認ができるような品川区独自のバックアップ体制、ご見解を説明を求めました。","respondent":"羽鳥防災課長","answer":"マイナンバーカードがないと連携ができないという仕様になってあります。これは他課が実施しているものですけれども、そういった他課の事業とも連携しながら普及啓発に努めてまいりたいと考えています。","id":"exchange-133"},{"speaker":"まつざわ委員","kind":"質問・要望","question":"よいしょとカードを持っていく、カードがないときにどうするかというのもいろいろ考えていかなければいけない課題なのかなと思っていました。品川区がシステムで集約しました在宅避難者のニーズデータ、実効性のある支援、こういったものにつなげる計画があるのか説明を求めました。","respondent":"羽鳥防災課長、遠藤防災体制整備担当課長","answer":"被害状況といたしましては、上水道の断水、下水道の断水、停電、ガス停止、その他の中から複数選んでいただいてご回答いただく。その情報に応じて支援を届けるという流れになってあります。 このため、区では、平時から区内全域をカバーしている郵便局などの事業者と連携して検討しています。区としましては、在宅避難者のニーズを実効性のある支援につなげるためにも、在宅避難者支援について引き続き検討を進めてまいります。","id":"exchange-134"}]}],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/629350?Template=document&Id=7389#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=3&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":124415,"voices":325}},{"id":"r08-20260316-3","meetingId":"r08-yosan","date":"2026年3月16日","dateIso":"2026-03-16","committee":"予算特別委員会","time":"午前 ９時３０分～午後 ４時５０分","status":"正式会議録","sourceType":"formal","overview":"予算特別委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を170件整理しています。","topics":[{"id":"topic-01","title":"令和８年度品川区一般会計予算","agenda":"令和８年度品川区一般会計予算","exchanges":[{"speaker":"澤田委員","kind":"質問","question":"３８９ページ、４０７ページ、保健運営費についてお伺いいたします。現在の実施状況や効果について説明を求めました。","respondent":"酒川指導課長","answer":"現在、小学校１校において６年生でオンラインレッスンを実施しております。それが伝わる喜びといったものが非常に効果として現れており、コミュニケーションの意欲の向上につながっていると考えております。","id":"exchange-001"},{"speaker":"澤田委員","kind":"質問","question":"そして、それはその先の英語教育への好奇心へとつながるものであると思っています。ぜひ全校への拡充という展開を期待しておりますけれども、今後のご予定をお伺いいたします。","respondent":"酒川指導課長","answer":"他の施策との予算的バランスを踏まえて、１校で実施している効果を検証しながら、段階的な拡充というものは今後も検討していきたいと考えております。","id":"exchange-002"},{"speaker":"澤田委員","kind":"提案","question":"令和５年度にはＡ評価の学校がなかったものが、令和６年度のＡＩ英会話導入後には２校がＡ評価、一定の効果を感じられているとのお話を伺いました。ぜひ品川区でもＡＩ英会話アプリの導入をご検討いただきたいと要望いたしますが、見解を説明を求めました。","respondent":"酒川指導課長","answer":"現在、企業が提供するＡＩ英会話アプリのトライアルについて、希望する学校への導入・効果検証について検討しているところです。中学校で実施しているオンラインレッスンのリハーサル的な活用なども考えられるかと思っているところです。","id":"exchange-003"},{"speaker":"澤田委員","kind":"質問","question":"現在、区ではアントレプレナーシップ教育は行われているのでしょうか。探求学習の重要性について、区のお考えを説明を求めました。","respondent":"唐澤教育施策推進担当課長","answer":"改めて今年度の教育課程説明会において示しているところでありまして、次年度の教育課程に反映し、探究的な学習の推進を引き続き図っております。区で実施しているスチューデント・シティやファイナンス・パークなど、リアルな体験活動を引き続き充実させ…","id":"exchange-004"},{"speaker":"澤田委員","kind":"意見","question":"そういった意味では、新たな機会の創出、既存の授業カリキュラムの中にアントレプレナーシップ教育の視点を持つことも大切であると思います。併せて、先生方への研修など、フォロー体制も行っていただければ、より手厚いと考えますが、ご見解を説明を求めました。","respondent":"唐澤教育施策推進担当課長","answer":"アントレプレナーシップをはじめ、様々な教育活動が持続可能な取組となるように体制整備を図ることは重要であると認識しています。今後も、学校の教育活動、先生の指導、子どもたちの学びがより充実していくように、研修をはじめ、よりよい環境を整えてまいります。","id":"exchange-005"},{"speaker":"澤田委員","kind":"質問","question":"学校公開に伺った際も、小学校低学年なのに０.１以下の視力で心配だという保護者からの声もお聞きします。子どもたちの目を守るために、区としてはどのような取組を行っていますか尋ねました。","respondent":"丸谷教育総合支援センター長","answer":"その中で、タブレットを使用する際の姿勢や、例えば３０分使用したら２０分遠くを見詰めるというような指導も行っております。授業時間の半分程度の使用ということで、指導者側からも配慮を行っているところです。","id":"exchange-006"},{"speaker":"澤田委員","kind":"質問・要望","question":"先生に教えてもらったことなら正しいこととして聞きやすいという側面もあるかと思いますので、ＩＣＴ教育の拡充とセットで、要望で終わります。どうぞ。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-007"},{"speaker":"山本委員","kind":"質問","question":"３８１ページのＰＴＡ活動支援、３８９ページの、４０５ページの給食運営費について伺います。そこで伺います。","respondent":"酒川指導課長","answer":"主に業務委託のお話を頂いたかと考えていますけれども、業務委託を実施した校長、９割満足という数値です。もう一つ、種目数については、来年度以降、最大５部活動と考えております。","id":"exchange-008"},{"speaker":"山本委員","kind":"質問","question":"最大で５種目と言っておりますけれども、当初は全て５種目ということで聞いていましたし、当初立てた計画よりも下回っていたのかなと思っています。以前も文教委員会などで質問してまいりましたけれども、民間委託については予算上の問題、それぞれ区の見解を伺います。","respondent":"酒川指導課長、丸谷教育総合支援センター長","answer":"原則４部活動、最大５部活動としておりますけれども、柔軟な対応もできるところです。それで充足を図っていこうと考えております。 各校５部活、全体で７５名の任用を予定しているところですけれども、現時点で４５名の部活動指導員を任用しております。は部活動指導員が見つかるかどうかというところのバランスで、現状、このようになっているです。","id":"exchange-009"},{"speaker":"山本委員","kind":"質問・要望","question":"いかがでしょうか。こういったところに対しての支援等をすることで、成り手になりやすくするというところも必要かと思うのですけれども、それぞれ区のご見解を伺います。","respondent":"酒川指導課長","answer":"一方、審判の資格取得のための補助については教育課程外となります。現在のところは検討しておりませんけれども、ご意見として承りたいと思います。","id":"exchange-010"},{"speaker":"山本委員","kind":"質問・要望","question":"でそれで任せきりにはならず、指導者と生徒の間に問題がないか、こういった状況の確認や支援を教育委員会としてお願いしたいと考えています。これまでもご要望しておりますが、令和８年度からの新たなロードマップでは、ぜひ追加の検討を頂きたいと思います。","respondent":"酒川指導課長","answer":"品川区の地域資源を活用した活動ということで、意義のある活動だと思っていますので、継続していきたいと考えているところです。まず子どもたちのニーズ第一、それから地域にどのような資源があるかということを踏まえて検討していきたいと考えております。","id":"exchange-011"},{"speaker":"山本委員","kind":"提案","question":"本事業について、来年度も同様に進めるという方針か、確認させてください。それから配布方法について、ご提案させていただいたとおり電子クーポンにより配布となりましたとの意見を述べました。","respondent":"石井学務課長","answer":"これを紙で実施した場合は、電子によって集計できることは非常に職員の負担軽減に資するものであると考えております。代理受領方式の施策については、まず学務課内で横展開を図りながら、より工夫を活かした事業展開を進めていきたいと考えているところです。","id":"exchange-012"},{"speaker":"山本委員","kind":"質問・要望","question":"電子クーポンによって、事務負担軽減、それから転売防止という大きな成果があるということが確認できました。この点、区の企画としていつもお伺いしておりますけれども、一言頂ければと思います。","respondent":"久保田企画経営部長","answer":"共通プラットフォームのご質問ですけれども、私どもとしましては、現時点ではそういったものを導入する考えはございませんので、引き続き調査・研究を行っていきたいと考えております。","id":"exchange-013"},{"speaker":"山本委員","kind":"質問・要望","question":"学校から保護者への連絡手段について、複数の学校ＰＴＡや保護者の皆様、学校現場からも強い要望があり、先日の代表質問で質問いたしました。それから、学校支援教育費に関連して、支援員の充実についてもお伺いします。","respondent":"石井学務課長、丸谷教育総合支援センター長、新井特別支援教育担当課長","answer":"学校の職員が利用する校務支援システムについては、連携等の問題や、これまで進めてまいりました。なるべく早期に導入できるのではないかという形で、今… 昨年度から導入しているいじめ調査ツールについて、学校風土が区全体では高まっているという認識です。調査結果を各校に共有することと併せて… 先ほどご紹介いただきました学校生活支援員についてなのですが、基本的には支援員が継続して張りついて支援させていただいているという認識です。…","id":"exchange-014"},{"speaker":"山本委員","kind":"質問・要望","question":"週は５日間ありますので、ぜひ少しでも行き届いた支援ができるように、引き続き要望したいと思います。給食費やＰＴＡ支援、それから、しながわ教育推進事業については、またの機会にご質問したいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-015"},{"speaker":"ゆきた委員","kind":"質問","question":"私からは、３９５ページの図書館運営費に関連して視覚障害者の啓発について伺います。区立学校でこれまで令和６年度および令和７年度に、どれだけの学校で手話体験講座が実施されてきたかについてお聞きします。","respondent":"酒川指導課長","answer":"区立全校において、手話の何らかの体験を教育課程に位置づけるようにと、教育委員会からは学校に案内し、学校が取り組んでいるところです。指導課が実施します、これは、ポイントを絞って手話に限って外部講師を招聘した授業などを行っている学校が合計１０校あるという状況です。","id":"exchange-016"},{"speaker":"ゆきた委員","kind":"質問","question":"年度ごとで、もう一度お聞きできればと思います。すみません。","respondent":"酒川指導課長","answer":"申し訳ございません。今、年度ごとの情報がないところです。","id":"exchange-017"},{"speaker":"ゆきた委員","kind":"質問","question":"現金で対応する場合、さらには金額の違いなどもあり、学校によって扱いが異なるとのお声も伺っています。講師の方々が安心して協力できる環境を整える観点からも、一定の整理が必要ではないかと考えますが、区としてどのようにお考えかお聞きします。","respondent":"酒川指導課長","answer":"まちの人に学ぶ授業というものによる実施の場合は商品券による支払いということで、一定、差が生じているということについては課題があります。これの整理が必要だという認識はあります。","id":"exchange-018"},{"speaker":"ゆきた委員","kind":"質問","question":"手話については、市民科の学習の中で教育課程に位置づけられており、どの学校でも何らかの形で触れることになっていると伺っています。学校における取組の紹介や情報提供などを通じて、区としても後押ししていくことが大切であると考えますが、区の見解をお聞きします。","respondent":"丸谷教育総合支援センター長","answer":"手話について体験的に学ぶということは非常に大切な機会であるという認識です。学校でも実施したいという広がりを持てるといいと考えておりまして、そういった学校での体験活動に波及できるように支援してまいります。","id":"exchange-019"},{"speaker":"ゆきた委員","kind":"質問・要望","question":"荏原図書館では区内図書館の職員、品川学園では５年生に、障害者理解を促進する講習も行われてきたと伺っています。区立図書館は現在１１館ありますが、区立図書館全体の取組として広げていくことについて、区の見解をお聞きします。","respondent":"三ツ橋品川図書館長","answer":"視覚障害の当事者の方からの取組ですけれども、現在、荏原図書館を中心に、令和６年度に視覚障害者の当事者の方が講座を行いました。視覚障害者の方へのご対応をしっかりとしていくために、当事者の方のお声を聞きながら対応してまいりたいと考えています。","id":"exchange-020"},{"speaker":"ゆきた委員","kind":"質問","question":"さらに進めてほしいと求めました。視覚障害への理解を深める、学びを広げていくことについて、区の見解についてお聞きします。","respondent":"唐澤教育施策推進担当課長","answer":"多様性理解をはじめ、市民科の中でこうした人権教育を含めまして、今、系統的な指導を展開しておりますので、そうした外部人材の活用も含めて学校と検討していければと思います。","id":"exchange-021"},{"speaker":"安藤委員","kind":"質問","question":"３８９ページ、探究的な学習への支援、３９１ページ、不登校対策事業費で伺います。区内４か所のマイスクールに通う人数をそれぞれ伺います。","respondent":"丸谷教育総合支援センター長","answer":"令和６年度の不登校児童数は３９７名、生徒数は４１５名でございました。令和６年度８名、令和７年度１３名ということで、今年度は年末の数字です。","id":"exchange-022"},{"speaker":"安藤委員","kind":"質問・要望","question":"なかなか８００人もの不登校の児童・生徒を、行き先をどうするかというのは、本当に大変な深刻な問題なのだと思います。マイスクールを、低学年の不登校児も通えるように拡充してほしいとの要望も出ておりますが、区の考えを伺います。","respondent":"丸谷教育総合支援センター長","answer":"低学年のマイスクール利用についてですけれども、まず学校には校内別室を全校で設置しておりまして、そこが１つ、学びの場となっているということ、また通室には距離等のこともありますので、そうした保護者の方の送迎も考えますと、現在のスタイルがよいと考えているところです。","id":"exchange-023"},{"speaker":"安藤委員","kind":"質問・要望","question":"その後どうなったのかということと、区のポータルサイトやパンフレットなどにも情報を載せてほしいと思いますが、いかがでしょうか。特別支援学校の児童・生徒にしているように、無償化相当の実費の支援を検討していただきたいのですけれども、いかがか尋ねました。","respondent":"丸谷教育総合支援センター長","answer":"関係部署と連携して、今後も進めてまいります。今年度の実績を踏まえまして、この取組を４教室に拡充できればということで、現在検討を進めているところです。","id":"exchange-024"},{"speaker":"安藤委員","kind":"質問・要望","question":"伺いたいのですけれども、一応、文部科学省推薦ということなのですけれども、区教育委員会はこの映画をご存じでしょうか。もしご存じでしたら、感想や、品川区で活かすべき点はどこだと感じているのか伺います。","respondent":"唐澤教育施策推進担当課長","answer":"アクティブラーニングを３０年前から続ける、各学校の探求学習の進め方を楽しく感動的に疑似体験できるドキュメンタリー映画だと認識しています。市民科「一貫プラン」の中で探究的な学習を進めていますので、各学校の取組をますます推進していくことが重要であると認識していま…","id":"exchange-025"},{"speaker":"安藤委員","kind":"質問","question":"伺いますけれども、区教育委員会は探求的な学びの意義というのをどのように評価しているのか伺います。こうした実践を今後どう広げていくお考えなのか伺います。","respondent":"唐澤教育施策推進担当課長","answer":"自分の考えをまとめ、発表する活動を繰り返しながら、達成感や自信といったものを子どもたちが成果として得てまいります。引き続き、各学校において探究的な学習を推進してまいりますよう、教育委員会として必要な支援に努めてまいりたいと考えています。","id":"exchange-026"},{"speaker":"安藤委員","kind":"質問・要望","question":"週１時間、年間３５時間だったと思うのですけれども、枠を使って行われているという位置づけなのです。だから、市民科を見直して、もともとの総合的な学習や学級活動、道徳を統合した時間に見直してほしいという要望でした。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-027"},{"speaker":"せらく委員","kind":"質問","question":"４０５ページ、校務費、４１１ページ、学校改築備品等整備費から学校の備品の整備について伺っていきます。比較的大型の備品については、どのような基準で更新や買い替えを行っているのか、更新周期などがあれば説明を求めました。","respondent":"石井学務課長","answer":"こちらで購入するときに、その予算編成に合わせて業者による調査を行って老朽度合いを判定しながら、必要に応じて更新しているというところです。やはりそういったものは、限りある予算の中で適切に更新を行っていくという方向で進めているところです。","id":"exchange-028"},{"speaker":"せらく委員","kind":"質問・要望","question":"学校からの要望があった場合に、予算が不足する場合には、次年度の予算でというふうになっていくのでしょうか。説明を求めました。","respondent":"石井学務課長","answer":"我々学務課には、各学校から様々なご相談が寄せられてきます。そういった中で、例えば次年度の予算要求に、どの学校のどういうものを想定していくかといったことも議論することになるかと考えております。","id":"exchange-029"},{"speaker":"せらく委員","kind":"質問・要望","question":"そこでお聞きします。併せて、学校と事業者の契約や取引について、区としてどのような形でチェックや確認を行っていますか尋ねました。","respondent":"石井学務課長","answer":"そもそも保護者から徴収しないというところですので、依然として私費会計の中で、迅速にかつ実施していかなければならないようなものもあります。先ほど申したような校外教授などは引き続き私費会計で実施しているものなのですけれども…","id":"exchange-030"},{"speaker":"せらく委員","kind":"質問","question":"いろいろお聞きしようと思ったのですけれども、引き続きいろいろ質問をして議論していきたいと考えていますので、引き続きよろしくお願いいたします。区として将来的な公会計化の検討も含めて、現在のスタンスを教えてほしいと求めました。","respondent":"石井学務課長","answer":"私費会計なのですけれども、教育活動の柔軟性や保護者の納得性、現場の迅速性を担保するのに不可欠な仕組みであるとも一方で考えております。完全に私費会計を廃止するかどうかについては様々慎重に検討しなければならないところがありますので…","id":"exchange-031"},{"speaker":"せらく委員","kind":"質問","question":"きちんと教えてくださいまして、こちらについては私も受け止めて、引き続き、取り組んでまいりたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-032"},{"speaker":"横山委員","kind":"質問・要望","question":"私からは、３８７ページ、学校支援費、３８９ページ、しながわ教育推進事業、３９１ページ、不登校対策事業費についてお伺いいたします。１点目に不登校対策事業費についてお伺いいたします。","respondent":"丸谷教育総合支援センター長","answer":"個別支援の計画を立て、見通しを持って支援していくことは、重要な事項だと認識しております。国が示す方向性についても注視しながら支援の充実につながるよう努めてまいります。","id":"exchange-033"},{"speaker":"横山委員","kind":"質問・要望","question":"学校と教師の業務の３分類について、現在どこまで整理が進んでいますでしょうか。そこで、現在の状況と、今後どのように実効性のある取組にしていくお考えなのか、区教育委員会のご見解をお伺いいたします。","respondent":"丸谷教育総合支援センター長、酒川指導課長","answer":"その１つの方策が、担当部門とも連携して、検討していければよいかと考えております。次に読書についてですけれども、読書率や家庭の蔵書と学力には、弱から中程度の正の相関があるという認識です。 人的支援、勤務時間の管理、部活動の適正化などを進めてまいりました。新たに保護者対応専用の窓口の設置なども予定しておりまして、この３分類を踏まえた、品川区ならではの負担軽減に取り組んでいく所存です。","id":"exchange-034"},{"speaker":"横山委員","kind":"提案","question":"品川区でそういった形をぜひ模索していただきたいと、私の願いとして思っておりますので、要望させてほしいと求めました。総務費でも、総務課長ですか、子どもたちからの提案があったというようなご答弁がありましたとの意見を述べました。","respondent":"唐澤教育施策推進担当課長","answer":"現在、探究的な学習を取り扱っています市民科については、検討委員会で進めているところですので、ご指摘の連携などにつきましても、その協議の中で触れていければと考えています。","id":"exchange-035"},{"speaker":"横山委員","kind":"質問・要望","question":"品川区はもう、全体を通して子ども・若者の支援を充実していくということで、最近行われているかと思います。それを、どうやって子どもたちの才能を開花させるというところにつなげていくのかという、ぜひ考えていってほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-036"},{"speaker":"えのした委員","kind":"質問","question":"しながわ部活動改革実行ビジョン２０３１において、部活動の地域展開、民間委託を進める最大の意義は何でしょうか。令和７年度までの改革推進期間における進捗と結果の分析、民間委託も含めてお伺いいたします。","respondent":"酒川指導課長","answer":"１つは子どもたちの活動機会の確保、もう一つは教員の負担軽減ということの二本柱と認識しております。学校部活動におきましては、部活動指導員、業務委託、そして指導を希望する３割の教員で１００％指導を充足できるように努力してきたところです。","id":"exchange-037"},{"speaker":"えのした委員","kind":"質問","question":"私は令和６年度予算特別委員会でも伺いましたが、ラグビーやホッケーなど、１校では人数がそろわない種目の存続が課題だと考えます。令和７年３月に品川区教育振興基本計画、令和９年３月に特別支援教育推進計画の策定をしますが、障害者の方の部活動参加はできていますか尋ねました。","respondent":"酒川指導課長","answer":"障害のある子どもたちは部活動に参加しておりますし、地域部活動にも参加しております。国が示すような、地域に子どもたちの活動場所を移すというようなことも、現在やっている品川モデルと併せて考えていく必要があると考えております。","id":"exchange-038"},{"speaker":"えのした委員","kind":"確認","question":"単に場所を１つにするだけではなくて、令和８年１月から新たに、いかがでしょうか。子どもたちの活動機会の創出に、文化部活動の質も向上させる取組について、区のご見解をお伺いします。","respondent":"酒川指導課長","answer":"それから子どものニーズによっては、合同化、それからそれにまつわる移動の安全確保といったものは併せて検討していかなければならないと思いますし。そういったことの実現に向けて進めてまいりたいと考えています。","id":"exchange-039"},{"speaker":"えのした委員","kind":"提案","question":"そしてこちらはご提案ですが、熊本県のアーティストビレッジ阿蘇０９６区、公立高校初のマンガ学科を設立させた高森高等学校の視察に伺ってきました。子どもたちの明るい未来に向けた取組はいかがか尋ねました。","respondent":"酒川指導課長","answer":"アニメ、個別に中学校それぞれ設置可能なところは、漫画やイラスト部というのは設置していると承知しております。まずは子どものニーズ、それから地域にどのような指導資源があるかということを踏まえて、今後も検討していきたいと考えています。","id":"exchange-040"},{"speaker":"えのした委員","kind":"質問・要望","question":"指導の完全分離や共通認識など、現場の人間関係にも配慮した仕組みが必要ではないでしょうか。ご見解をお伺いします。","respondent":"酒川指導課長","answer":"当然ながら、指導に従事したいという教員は、教育委員会としても大事にしたい、支援していきたいと考えております。そういった教員が学校の中で何か偏見を持たれたり差別を受けたりということがないように、校長等と連携して配慮してまいりたいと思います。","id":"exchange-041"},{"speaker":"えのした委員","kind":"質問","question":"令和７年度品川区教育委員会事務事業の点検および評価の報告書には、どのような指導観で子どもと向き合っているのかは明らかではない。技術指導だけでなく、中学生を適切に指導できる人員をどう集め、質をどう担保するのか、区のご見解をお伺いします。","respondent":"酒川指導課長","answer":"部活動指導員については、区教育委員会が研修し、質・能力を高めております。その情報については教育委員会と情報共有しておりますので、今後も連携を深めて、質の担保に努めていきたいと思います。","id":"exchange-042"},{"speaker":"新妻委員","kind":"質問・要望","question":"ラーケーションの区の認識をお聞きし、導入に向けての検討を要望いたしますが、見解を伺います。予算特別委員会の２日目の歳入でも確認いたしましたが、改めて伺ってまいります。","respondent":"丸谷教育総合支援センター長、酒川指導課長","answer":"開設予定の１年前が目途となっておりまして、令和９年２月に設置に向けた調査が行われる予定となっておりますので、そのときまでには。併せて令和８年度中に検討を進めてまいりたいと考えております。 スタートカリキュラムについてですけれども、小学校の英語学習と中学校の英語学習のスタートの円滑な接続が重要と考え、実施しております。教育委員会作成の読み書きに関するテストを実施しまして…","id":"exchange-043"},{"speaker":"新妻委員","kind":"質問・要望","question":"課題面もあるということも確認していますが、こういう制度があることで、休みを取っていいのだと思われる保護者も少なくないと思います。場所の設定を早くしていただきまして、それの周知をしていただくということを重ねて要望させてほしいと求めました。","respondent":"丸谷教育総合支援センター長、酒川指導課長","answer":"続いて学びの多様化学校についてですけれども、新しい学校の建物を設置ということではなくて、現在、分教室型ということを検討しております。こちらも場所というのは大事な要素かと思いますので… 英語学習をさせているわけですけれども、英語というものを中心にコミュニケーション能力の向上というところを目指して、今後も様々な交流や取組、どんなことができるか検討していきたいと考えております。","id":"exchange-044"},{"speaker":"高橋（伸）委員","kind":"質問・要望","question":"４０７ページ、保健運営費、４０９ページ、学校施設建設費、源氏前小学校、時間があれば３８１ページ、８３運動経費についてお伺いします。初めに４０７ページ、学校管理費、保健運営費から、食物アレルギーの対応についてお尋ねさせてほしいと求めました。","respondent":"石井学務課長","answer":"食物アレルギーの対応薬であるエピペンの使用ですけれども、令和７年度については、発生は今のところ報告は上がっておりません。昨年度、おうちからアレルギー対応食を持ってきたにもかかわらずアナフィラキシーショックが起こったために、事例としては把握しています。","id":"exchange-045"},{"speaker":"高橋（伸）委員","kind":"確認","question":"１件という報告ということで確認させていただきました。食物アレルギーに対する理解と、学校における食物アレルギー対応は現在、研修も含めてどのように対応されているのかお伺いしたいと思います。","respondent":"石井学務課長","answer":"栄養職員、給食員関係の事務、そして調理員により構成される食物アレルギー対応委員会というものを設置しております。その中で、全体的な各学校におけるアレルギー対応の方向性を決定するとともに、そういったものを含む各種アレルギー対応の研修を実施しております。","id":"exchange-046"},{"speaker":"高橋（伸）委員","kind":"質問","question":"それで、プールの共同利用についてお尋ねします。源氏前小学校は現在、調整中になっているかと思うのですけれども、どういうふうに調整しているのかというのを説明を求めました。","respondent":"荒木学校施設担当課長","answer":"こちらは開閉式屋根つきで、安定した授業実施ができるという理由です。移動につきましては、暑さ対策と時間短縮の両面から、鈴ケ森小学校、城南第二小学校と同じくバスを借り上げることを検討しているところです。","id":"exchange-047"},{"speaker":"高橋（伸）委員","kind":"質問・要望","question":"続いて、３８１ページ、８３運動経費についてお尋ねします。本当は道徳だと私は思っていますので、要望というか当たり前のことなのですけれども、その辺についてお尋ねさせてほしいと求めました。","respondent":"酒川指導課長","answer":"顔を認識している相手には当然のことながら、地域を大事にするという意味でも挨拶をすべきだと思っています。こういった辺り、ご意見があったということを、校長連絡会等を通じて啓発していきたいと考えています。","id":"exchange-048"},{"speaker":"筒井委員","kind":"質問・要望","question":"戸越八幡神社のケンポナシの木についてお伺いいたしますけれども、議会としても、このケンポナシの木をしっかり守っていくべきだという意思です。この規定は、確認として、まず文化財所有者と所有者以外の第三者にも適用されるということでよろしいか尋ねました。","respondent":"舩木庶務課長","answer":"委員がご指摘の条文につきましては、所有者が、隣地というか周辺の公益に関わる方々の、協議の上で合意を取った上で、指定の現状変更届という手続を踏むというような規定になってあります。","id":"exchange-049"},{"speaker":"筒井委員","kind":"質問","question":"合意して、そうした調整があって、その上で教育委員会にかけて許可を受けるという理解でよろしいか尋ねました。","respondent":"舩木庶務課長","answer":"そのようなご認識で差し支えございません。","id":"exchange-050"},{"speaker":"筒井委員","kind":"質問","question":"では今回、ケンポナシの木の件は、枝が切られることが軽微だという解釈を取って、第１４条第１項ただし書を適用して、教育委員会の許可を受けなくていいという判断をされたということではないということでよろしいのか尋ねました。","respondent":"舩木庶務課長","answer":"令和３年から非常に調整が継続的なものになっているという事案ではありますけれども、本当に樹木の継続的なものに支障がない範囲で措置を取ったというところですので、正式な形で現状変更届が出された上での措置ということではございません。","id":"exchange-051"},{"speaker":"筒井委員","kind":"質問","question":"ケンポナシの木に限らず、条例第３条第４項で調整を図らなくてはいけないということで、非常に切られやすくなるという状況ではあると考えております。区の条例もそろそろ改正を検討すべきかなと考えておりますけれども、その点、いかがお考えか尋ねました。","respondent":"舩木庶務課長","answer":"この点につきましては、今後も引き続き丁寧に現状把握に努めながら、必要となる調整に努めてまいりたいです。今ご指摘の２０２３年の民法の改正というところにつきましては、民法というのは、今お話がございましたような改正があったと認識しております。","id":"exchange-052"},{"speaker":"筒井委員","kind":"質問・要望","question":"文化財保護法が上回るということでしたら、より一層強く、品川区として文化財を守っていくという姿勢をぜひ見せていただきたいと考えております。現状、そちらの文化財がどうなっているのかという状況確認をするべきかと考えておるのですけれども、その点はいかがお考えか尋ねました。","respondent":"舩木庶務課長","answer":"今回の事例に関しましては、まだ調整が継続的なものですので、現時点での周知というか共有というところは予定してございません。そして区の生活安全担当などとも協議をしながら、例えば防犯カメラの設置、警告文の設置やパトロールの強化といったところに努めているところです。","id":"exchange-053"},{"speaker":"筒井委員","kind":"質問・要望","question":"それを受けて、令和５年６月２６日に区長の諮問があり、品川区いじめ問題調査委員会が調査し、答申として調査報告書が出されているわけです。昨年１１月２６日の文教委員会の報告でも、現状、いじめの認知件数について品川区がどのように捉えているのか説明を求めました。","respondent":"丸谷教育総合支援センター長","answer":"認知件数は区全体でも９７４件という形で、令和４年度は１４２件でしたので、大幅に認知は増加しているという現状があります。生徒は４２.６人のところ、区では３０.７人ということで、校長会を通じて周知したところです。","id":"exchange-054"},{"speaker":"筒井委員","kind":"質問・要望","question":"いじめ重大事態につながる大きなものを防ぐという大切な面があると思いますので、ぜひ認知件数を増やしていっていただきたいと存じます。いじめ重大事態に対する理解がそもそも不足している、その点の課題の解消というのはもうなされたと、区としてはお考えなのか尋ねました。","respondent":"丸谷教育総合支援センター長","answer":"いじめ防止の基本方針の見直しを図りまして、認定のフローについても作成したところです。こちらのフローに基づいて、このフローについて学校にも示しながら、重大事態に当たるか否かというところの判断のよりどころにしているものです。","id":"exchange-055"},{"speaker":"筒井委員","kind":"質問","question":"その点は課題が解消されているということは、一定理解いたしました。そして、いじめ相談対策室との、いじめ対応についての方針の違いなどといったことはあるのか尋ねました。","respondent":"丸谷教育総合支援センター長","answer":"教育委員会と学校といじめ相談対策室の三者が連携して、方針をしっかりと築きながら、いじめ対応に当たっているところです。方針、考え方が若干、学校と違うときについても、ここでしっかり情報共有をしながら、すり合わせをして、いじめ対応に当たっているという段階です。","id":"exchange-056"},{"speaker":"筒井委員","kind":"質問・要望","question":"いじめが根絶するということなので、ぜひしっかりと区で全力を挙げて、いじめ根絶に取り組んでほしいと求めました。続いてＳＮＳ規制について伺いますけれども、このような海外での規制の受け止め、区としてはどのようにお考えになっているのかお知らせください。","respondent":"丸谷教育総合支援センター長","answer":"年が明けてから大きく報道されているような暴力はございませんけれども、いつ起こってもおかしくないという危機感は持っているところです。欧米諸国で現在、ＳＮＳの年齢制限がされているということで認識はしておりますけれども…","id":"exchange-057"},{"speaker":"筒井委員","kind":"質問・要望","question":"ぜひ国の議論を見て、しっかり考えていってほしいと求めました。情報として提供すべきかと思いますので、ぜひその辺りをよろしくお願いしたいと思うのですけれども、その点はいかがお考えか尋ねました。","respondent":"丸谷教育総合支援センター長","answer":"ＳＮＳの利用について、保護者への啓発というものも大切なことだと捉えております。学校だよりや保健だより、それから保護者会等の機会を捉えまして、保護者の皆様にも啓発を進めていければと考えております。","id":"exchange-058"},{"speaker":"中塚委員","kind":"質問","question":"４０５ページの給食運営費より、災害時の炊き出しについて、給食室の活用や学校給食の調理師の協力を伺いたいと思います。その上で、炊き出しについて調理師の参加・協力について、その後、防災部局との協議はどこまで進んでいるのか、具体的に伺いたいと思います。","respondent":"石井学務課長","answer":"それに対してどういう形で説明を施すのかということについて課題があったのですけれども、給食費については無償化で、公費で購入しているものです。現在、防災部局とは、そういった形で議論をしています。","id":"exchange-059"},{"speaker":"中塚委員","kind":"質問","question":"いつ起きてもおかしくないと、繰り返し強調される中、災害関連死を防ぐ対策も強調されております。ぜひ学校給食の調理師について、炊き出しに参加・協力できる契約や体制を一刻も早く進めてほしいと思いますが、いかがか尋ねました。","respondent":"石井学務課長","answer":"労働条件の変更や、受託事業の業務範囲の拡大、何かが生じたときの費用補償みたいなものも考えていく必要があるのだと考えています。慎重に検討を重ねながら、持てる力を総発揮ということがどのような形で可能なのかというのは、考えていきたいと考えています。","id":"exchange-060"},{"speaker":"中塚委員","kind":"質問","question":"給食の提供が一旦中止になった場合は、調理師というのは自宅待機ということになるのか、つまりその際のお給料というのはどうなるのか。調理師の給与といいますか身分といいますか、これは保障されていると思うのですけれども、現状はどのようになっているのか尋ねました。","respondent":"石井学務課長","answer":"その中で雇用関係において、かくかくしかじかの場合はどうするという、各調理会社との契約関係まで縛っているというのは現状ではございません。ですので、各調理会社によって異なると考えているところです。","id":"exchange-061"},{"speaker":"中塚委員","kind":"質問","question":"今の説明だと、されない場合もあるということなのでしょうか。伺いたいと思います。","respondent":"石井学務課長","answer":"基本的には、災害等やむを得ないような事情の中で契約を変更する場合や、その取扱いについて決めることが定められております。調理の事業者が労働に対する対価としてどのように報酬を支払うかという問題になりますので、そこまで区で現状は縛ってはいないという状況です。","id":"exchange-062"},{"speaker":"中塚委員","kind":"質問・要望","question":"例えばワカメも豆腐もなくてもいいけれども、温かいみそ汁を１杯飲めれば力が湧いてくるのだという声を、様々な場所で伺っております。様々みんなの力を結集することが必要ですから、それは職員の方のほうがよほど詳しいとは思いますけれども、最後にいかがか尋ねました。","respondent":"石井学務課長","answer":"これも１つの持てる力だと考えています。引き続きどのような形が可能か、これについてはしっかりと考えてまいりたいと考えています。","id":"exchange-063"},{"speaker":"中塚委員","kind":"質問・要望","question":"ぜひ具体的に検討を進めていただきたいと、強く要望しておきたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-064"},{"speaker":"あくつ委員","kind":"質問","question":"私からは、教育費全般と、３８３ページ、就学事務費、４０１ページ、学校システム運営費、校務支援システム等更改作業委託について伺ってまいります。１５年前のことですから、２０１１年生まれの子がちょうど中学３年生。","respondent":"伊崎教育長","answer":"こういった児童・生徒を通じた防災教育が、学校内だけでの取組ではなく、会場においでいただいている皆様のお顔を拝見しながら考えていたところです。そのような視点で取り組んでいきたいと考えております。","id":"exchange-065"},{"speaker":"あくつ委員","kind":"質問・要望","question":"そして、先ほどの質疑でもありましたけれども、前倒しというのはどういう意図で、いつ前倒しで導入されるのか、お伺いします。例えば希望される学校側に打診して、それが可能かどうか、前向きに検討するような形で協議をするような立てつけにしてはいかがでしょうかということ。","respondent":"石井学務課長","answer":"なので、そういった課題を捉えながら、９月までには利用開始ができるように進めていきたいと考えています。現状のところ、総合的に勘案した結果、３週間以上継続して通学することというふうなものに対して一定程度の合理性は感じているところです。","id":"exchange-066"},{"speaker":"あくつ委員","kind":"質問・要望","question":"裁量をしている根拠をまず伺いたいのと、受入れ校の負担を軽減するために、これは体験入学ではありません。そういったことも考えて、ぜひそこはもう一度考えていただきたいと思うのですが、ご答弁をお願いいたします。","respondent":"石井学務課長","answer":"日本に例えばすごく短期間来ている場合や滞在期間が短い場合については、受け入れる必要はないと考えられるという形で東京都は見解を示しています。先ほど申しました教育の継続性などといった中で、今のところは３週間というものを１つの目安として考えているところです。","id":"exchange-067"},{"speaker":"あくつ委員","kind":"意見","question":"先ほどのご答弁だと、東京都のＱ＆Ａには、短ければというようなところでのご判断が示されているということがありました。僅か１０日程度の通学であったとしても、児童・生徒の学ぶ権利の一環として、ぜひこれは柔軟な対応をまた検討してほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-068"},{"speaker":"のだて委員","kind":"質問・要望","question":"６年生・７年生の移動教室と５年生の林間学園の自己負担額を学年別に伺います。無償化した場合に必要な額を伺います。","respondent":"石井学務課長","answer":"そういったところから、７年生につきましても約２,０００万円程度、もし無償化した場合についてはかかるものと承知しております。なお、この費用につきましては、例えば現地での食事代や、あとは体験をする際の体験の入館料などといった実費が含まれているものです。","id":"exchange-069"},{"speaker":"のだて委員","kind":"質問","question":"林間学園について伺ったので、お答えほしいと求めました。","respondent":"石井学務課長","answer":"５年生の林間学園につきましては、およそ１人当たり１万６,０００円の負担となっております。こちらを同様に無償化した場合については、約４,８００万円を見込んでいるところです。","id":"exchange-070"},{"speaker":"のだて委員","kind":"質問・要望","question":"林間学園については、これは別に私費でないといけないということはないのではないかと思うのですけれども、理由があるのか伺いたいと思います。どちらもぜひ無償化してほしいと求めましたが、いかがか尋ねました。","respondent":"石井学務課長","answer":"まず移動教室と林間学園の差というものは、移動教室は教育課程内で実施されるものであるということ、そして林間学園は教育課程外で実施されるもの。今後もベーシックサービスの考えの下、その中で優先順位を一つ一つつけながら…","id":"exchange-071"},{"speaker":"のだて委員","kind":"質問・要望","question":"ですので、ぜひこれはやはり、どちらも無償化してほしいと求めましたけれども、何か実施できない、法律上などの課題はあるのでしょうか。伺いたいと思います。","respondent":"石井学務課長","answer":"そして、そういう意味では、かなりベーシックサービスの考え方がすごく広く根づいたのではないかと考えております。教育の中で何が必要とされるのか、教育のあり方といったものも含めながら、総合的に勘案していかなければならないと考えているところです。","id":"exchange-072"},{"speaker":"のだて委員","kind":"質問・要望","question":"林間学園も無償化してほしいと求めましたし、さらに加えて、体操服と卒業アルバムの無償化を求めたいと思います。それぞれ無償化した場合に必要な額を伺います。","respondent":"石井学務課長","answer":"なお、卒業アルバムにつきましては、ＰＴＡが実施する卒業対策委員会の中で実施されるものと承知しております。現在のところ、その両方について、教育の機会をきちんと担保していくことはすごく大事なことであると考えております。","id":"exchange-073"},{"speaker":"のだて委員","kind":"質問・要望","question":"卒業アルバムも、それぞれ１万円ぐらいかかるということですので、６年生で約３,０００万円、９年生で１,６００万円、必要になるかと思います。区の増収状況を今見れば、十分、無償化は可能だと思いますので、ぜひ無償化してほしいと求めましたが、いかがか尋ねました。","respondent":"石井学務課長","answer":"現状においても様々、教育活動においては保護者負担が生じているということについては承知しております。今後総合的に、もちろん限りある財源ですので、そういう中も含めて総合的に検討してまいりたいと考えております。","id":"exchange-074"},{"speaker":"のだて委員","kind":"質問・要望","question":"ぜひ検討を進めていただいて、完全な義務教育の無償化に向けて進めていって、品川区から発信していってほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-075"},{"speaker":"吉田委員","kind":"提案","question":"ＣＡＰプログラムの拡充を求めて質問いたします。こども性暴力防止法施行に向けて学校に求められる、性暴力を防ぐための取組の一環として、ＣＡＰを拡充するべきと考えますが、見解を伺いますとの意見を述べました。","respondent":"丸谷教育総合支援センター長","answer":"学校でのＣＡＰプログラムの実施についてですが、現在、３年生で年に１回行ってあります。令和８年度においても、この事業は継続していく予定です。","id":"exchange-076"},{"speaker":"吉田委員","kind":"質問・要望","question":"子どもたち向けのプログラムの充実を改めて求めますが、教員向けのＣＡＰの拡充も求めますが、見解を伺います。教育委員会から区長部局に呼びかけて、それぞれの事業に合わせたＣＡＰプログラムの実施を検討してほしいと求めましたが、見解を伺います。","respondent":"丸谷教育総合支援センター長","answer":"現状、３年生で実施しておりますが、その後の学校生活や日常生活に活かすことが大切だとは考えているところです。それぞれの部署で、所属の職員への啓発等も進めていただくものと捉えておりまして、関係部門と連携して進めていければと捉えております。","id":"exchange-077"},{"speaker":"吉田委員","kind":"質問","question":"これをいろいろな事業に広げていくということについては、特に何か支障があるようには思えません。やはり事業者としての、事業者側からの対策と、その点について改めて伺います。","respondent":"丸谷教育総合支援センター長","answer":"ＳＯＳの出し方に関する教育や「生命の安全教育」、またいじめ予防事業など、子どもが自分の身を守る学習は様々な場面で実施しています。学校での取組、またそれを家庭へも、また地域へも波及させていくことは大切だと考えております。","id":"exchange-078"},{"speaker":"吉田委員","kind":"質問・要望","question":"いよいよこれから子どもの権利条例が制定されるという状況に来て、この権利教育を拡充しなくてどうするのですかという思いで今質問をしております。ぜひ、子どもの権利条例制定に向けてもＣＡＰの拡充は必要ではないかと思いますが、その点についても見解を伺います。","respondent":"丸谷教育総合支援センター長","answer":"ＣＡＰに限らず、様々な場面で、子どもの権利について学ぶ機会を持つということは大切だと捉えてありますので、社会科や市民科その他、様々な教育活動の中で、子どもの権利について学ぶ機会というものを創出できればと考えております。","id":"exchange-079"},{"speaker":"吉田委員","kind":"質問・要望","question":"ですから、いろいろな場面の創出については全然反対しておりません。改めて、最後にご見解を伺いたいと思います。","respondent":"丸谷教育総合支援センター長","answer":"ＣＡＰプログラムも非常に有用なプログラムだという認識は持ってありますので、次年度は継続してまいります。それ以外に様々な場面で、子どもたちの権利については学ぶ機会を生み出していきたいと考えております。","id":"exchange-080"},{"speaker":"こしば委員","kind":"質問","question":"私からは、４０１ページ、学校図書館経費で読書について、３８７ページの帰国児童・生徒等支援費について伺います。まずこの意見に対しまして、区の認識、見解について説明を求めました。","respondent":"石井学務課長","answer":"学校図書館の図書整備につきましては、生徒数などといった基準に基づき、必要な数が定められているところです。教育委員会としては、一部まだ達成していないところがあるというところで、引き続き学校図書館の蔵書整備について進めていきたいと考えております。","id":"exchange-081"},{"speaker":"こしば委員","kind":"質問","question":"決まった算定基準に基づいて予算配備、予算を整えているということだと思うのですけれども、具体的な中学校の図書館整備だと、蔵書の充実に充てている具体的な予算について、また、これまでの直近の推移も含めて教えてほしいと求めました。","respondent":"石井学務課長","answer":"中学校につきましては約６６０万円、義務教育学校の後期については約４３０万円ということで、大体１,０００万円の公費が投入されているところです。過去の推移につきましては今、手元に数字を持ち合わせていないのですけれども、ほぼ同様の形で推移しているような形です。","id":"exchange-082"},{"speaker":"こしば委員","kind":"質問","question":"１,０００万円近くの予算を入れているということを認識いたしました。学校の図書館整備費以外の項目で、読書率の向上に向けての予算というのはどのように割り当てられているのか、教えてほしいと求めました。","respondent":"石井学務課長","answer":"学校図書館の予算の割り振りという形といいますと、各学校において当然、先ほど申し上げたような基準に基づいて購入しているようなところです。","id":"exchange-083"},{"speaker":"こしば委員","kind":"質問","question":"学校図書館整備費ではないところで読書率を向上させていく取組の予算というのは計上されておるのかという質問だったのです。","respondent":"丸谷教育総合支援センター長","answer":"特段、予算という形での計上はございませんけれども、例えば休み時間に図書館を開館する、教室に図書を置いておくなどといった、予算のかからない範囲で各校がそれぞれ取組の工夫をしています。","id":"exchange-084"},{"speaker":"こしば委員","kind":"質問","question":"お聞きしますけれども、本区で読書を中学校の授業の一環として、取り組んでいるのかどうか。もしそういった取組がありましたら、どのような学校がどのぐらいの数あるのか、分かる範囲で取組の内容についても教えてほしいと求めました。","respondent":"丸谷教育総合支援センター長","answer":"実際の授業の中で、読書の時間という形では設けてはいないのですけれども、読書が進むような取組というものは教科書ベースで行っております。例えば調べ学習で図書館を活用する、市民科の探求学習の中で図書館を活用するなど、そういった取組で読書が進むような工夫をしています。","id":"exchange-085"},{"speaker":"こしば委員","kind":"質問","question":"要は中学校の蔵書を増やしてもらいたい、それが課題であるということを先ほどお話をさせていただきました。この蔵書率というのは、そういった数値目標などといったものがありましたら、教えてほしいと求めました。","respondent":"石井学務課長","answer":"令和６年度末での蔵書数で考えますと、中学校・義務教育学校（後期課程）については９７.８％という状況で、開きがあります。取組として必要であると思いますけれども、まず基準どおりの蔵書が確保できるような形で努めてまいりたいと考えております。","id":"exchange-086"},{"speaker":"こしば委員","kind":"質問・要望","question":"ぜひ基準値に向けて取り組んでほしいと求めました。ぜひ検討してほしいと求めましたが、もし既に取り組んでいるものがあれば、その取組の内容についても教えてほしいと求めました。","respondent":"丸谷教育総合支援センター長","answer":"キャリア教育に明確に、読書を通じて、目標にできる人物を見つけるということは非常に大切だと考えております。そうした有用な本との出会いというものを大切にできるように、蔵書も含めて、学校の司書と共に取り組んでいけたらと考えております。","id":"exchange-087"},{"speaker":"こしば委員","kind":"質問・要望","question":"ぜひそういった推薦の図書など、広く展開していただきたいと願いまして、次に３８７ページ、帰国児童・生徒等支援費について伺います。実際に指導を受けている児童・生徒数は何人で、また一方で指導未実施の児童・生徒数が何人なのか、具体的に教えてほしいと求めました。","respondent":"丸谷教育総合支援センター長","answer":"日本語指導が必要な児童・生徒数です。基礎を学ぶコースに通ったお子さんが８２名、それから教科書を読めるようにするＪＳＬ２に通ったお子さんが６９名という実績でございました。","id":"exchange-088"},{"speaker":"こしば委員","kind":"質問","question":"実際に外国籍の方がそもそも日本語の能力があるかどうかという判断をすることが難しい状況から始まっていると思いますので、日本語指導が必要な生徒かどうかというのを、その辺りの見解について教えてほしいと求めました。","respondent":"石井学務課長、丸谷教育総合支援センター長","answer":"数については把握しており、話せない方につきましては、教育総合支援センターの授業でフォローしています。必ず、そういったところでは届出をしておりますので、数字としては把握しながら… 日本語指導が必要かどうかというものを、保護者とやり取りして申請していますので、必要なお子さんには支援できていると捉えております。","id":"exchange-089"},{"speaker":"こしば委員","kind":"質問・要望","question":"一緒に聞きたかったのですけれども、予算書では外国籍と帰国子女の児童・生徒と書かれておったのですけれども、日本に帰化された方というのはこの中に入っているのかどうか、お答えほしいと求めました。","respondent":"石井学務課長","answer":"重国籍という形で、それぞれの教育を受けることができる状況にある方もいらっしゃるので、それはなかなか一概に言うことはできないのです。それで、帰化しているかどうかというところまでは詳細には把握してございません。","id":"exchange-090"},{"speaker":"こしば委員","kind":"質問・要望","question":"なぜそれを聞くかといいますと、母国語といいますか外国語を通じて生徒同士で教え合っているという話を教員の方からお聞きしたことがありました。そういったことも踏まえて、教育委員会でそういった状況が起こっているのか、また起こっていたのかも含めて教えてほしいと求めました。","respondent":"丸谷教育総合支援センター長","answer":"日本語指導教室に毎日通室するというのはなかなか難しい状況がございまして、それ以外の場面は各学校の中での生活という形になりますので、そういう場面も想定されるところではありますけれども、しっかりフォローはしていきたいと考えております。","id":"exchange-091"},{"speaker":"こしば委員","kind":"質問・要望","question":"都内全体でも今もう、日本語指導が必要な児童・生徒数というのは、これは令和６年度の数字ですけれども５,３７３人。その一方で、時間がないので要望にしますけれども、周辺の学校も含めてオンラインにも取り組んでほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-092"},{"speaker":"松永委員","kind":"質問","question":"３８１ページの家庭教育学級、３８３ページのクラブ・部活動等経費、および３８７ページのいじめ防止対策費について伺いたいと思います。併せて、こうした状況を正常化して、親としての責任を果たすための、実効性のある啓発活動の現状について伺います。","respondent":"舩木庶務課長","answer":"こうしたところを通じまして、学校の教育の役割と家庭の教育の役割というものを密接に連携させることが重要であると考えております。学校トラブル相談ということで窓口を設置しておりますので、五十件ぐらいありますので、実績としてはそのような形になっております。","id":"exchange-093"},{"speaker":"松永委員","kind":"確認","question":"ここで１点確認させてください。教育委員会として、何を基準に役割の線引きの判断をされているのか、その根拠を伺いたいと思います。","respondent":"酒川指導課長","answer":"しつけに関する「普通」の定義ですけれども、これについては明確な定義づけはしておりません。いずれにしましても、家庭と学校、教員は、子どもたちを育てるパートナーとして共通理解を図っていくということで、協力関係にあると捉えております。","id":"exchange-094"},{"speaker":"松永委員","kind":"意見","question":"パートナーとして共にやっていくということでございましたけれども、共に育てるというようなことが、そうしたロードマップであると思います。３８１ページにあります教職員の健康管理についてなのですけれども、原因となるものについて、もし分かっていればお知らせくださいとの意見を述べました。","respondent":"舩木庶務課長","answer":"令和６年度が５３件というところでございまして、まだ１２月末時点のものではありますけれども４３件と、少し減少傾向が認められております。ただ、依然として病気休職、病気休暇にかかわらず…","id":"exchange-095"},{"speaker":"松永委員","kind":"意見","question":"学年主任の方々や管理職の方が、チームとしてその方をサポートする体制ということで、予算面でどう裏づけているのか。１人ではないということを思える環境づくりについて、どうやって行っているのかお知らせくださいとの意見を述べました。","respondent":"酒川指導課長","answer":"若手の教員については、３年前ぐらいからメンター制度というのができまして、そんな体制をつくっているところです。ちなみに、これは東京都の事業です。","id":"exchange-096"},{"speaker":"松永委員","kind":"質問","question":"その中で、クラブ活動・部活動のところで伺いたいと思います。この地域教育の再生の場とするべきと私は考えますが、本区としてこの基本的な認識をどのように考えていらっしゃるのかお知らせください。","respondent":"酒川指導課長","answer":"それから指導に携わりたいと望んでいる教員によって１００％充足しているところですが、現在の状況を維持するとともに、その先の地域との連携のあり方というのも模索していくところです。","id":"exchange-097"},{"speaker":"松永委員","kind":"質問・要望","question":"３８７ページ、いじめ防止対策費について伺いたいと思っていたのですが、他者の痛みを知るということがとても肝腎であると考えています。そうしたところは教育委員会と区長部局でしっかりと対応してほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-098"},{"speaker":"やなぎさわ委員","kind":"質問","question":"３つ目が、校内の一部のトイレで悪臭が何年も前からしていて、児童が使うのにちゅうちょしているという問題があります。初めにお伺いしたいのは、これらの状況把握または改善の予定をお伺いいたしますが、いかがか尋ねました。","respondent":"荒木学校施設担当課長","answer":"１点目の体育館の雨漏りにつきましては、今回の予算書にも記載のとおり、来年度、屋上防水改修の中で実施していく予定です。３点目のトイレの悪臭に関しましては、こちらについても学校と状況を確認して、必要な対応を行っていこうと考えています。","id":"exchange-099"},{"speaker":"やなぎさわ委員","kind":"質問","question":"雨漏りとプールに関しては予算をつけていただいたということで、ありがとうあります。不衛生なトイレが与える子どもたちへの影響について、区としてはどのような認識かをまずお伺いしたいのですが、いかがか尋ねました。","respondent":"荒木学校施設担当課長","answer":"やはり不衛生な環境になりますと、どうしても子どもたちがトイレの使用をちゅうちょするといった問題が出てくると思います。４０３ページの予算書に載っていない改修費用というのを別途確保していますので、そこに合わせて迅速な対応を進めていきたいと考えております。","id":"exchange-100"},{"speaker":"やなぎさわ委員","kind":"質問・要望","question":"１つ、３分の１とか４分の１のトイレが悪臭がするという話なのですが、トイレ以外でもそういったことが起きていることも含めて要望したいと思います。お伺いしたいのは、公立学校で職員室の広さの決まりというのか、ガイドラインみたいなものは制定されていらっしゃるのか尋ねました。","respondent":"荒木学校施設担当課長","answer":"そういったものもしっかり参考にしながら、今後、改築や改修を進めてまいりたいと考えております。","id":"exchange-101"},{"speaker":"やなぎさわ委員","kind":"質問・要望","question":"ＩＣＴ化を進めるという意味でも、やはり教職員の働く環境スペースをしっかりと整えていただきたいと、改めて要望いたします。なるべくこれは調査していただいて、早急に対策をと思うのですが、いかがか尋ねました。","respondent":"荒木学校施設担当課長","answer":"今回、学校のＩＣＴ化と連携して、やはり進めていくべきだろうとは考えてあります。施設面と、あとソフトウエアといいますか、ＩＣＴのソフトウエアの環境の面と併せて進めてまいりたいと考えています。","id":"exchange-102"},{"speaker":"やなぎさわ委員","kind":"質問","question":"そのまま続けて立会小学校の改築についても少しお伺いいたします。築５０年以上たっていて、現状、区として把握している立会小学校の改築についての状況を説明を求めました。","respondent":"荒木学校施設担当課長","answer":"今後も引き続き、建物の老朽度や就学人口動向、地域バランスなどを踏まえて総合的に検討し、決定してまいります。いずれにしましても、来年度実施します改築困難校基本構想策定を進めていく中で、その検討で得られた知見・ノウハウといったものは。","id":"exchange-103"},{"speaker":"やなぎさわ委員","kind":"意見","question":"改築困難校のせいで老朽化がほっておかれているのかというのを心配していますので、ぜひ今後とも、そういった点をしっかりと注視してほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-104"},{"speaker":"塚本委員","kind":"質問","question":"お伺いしたいのは、合同部活動という話とマッチするのかどうか分かりませんが、他校では盛んにやっていると。これを、こういう子がそこに参加して一緒に部活をするという話というのはどうなのかというのをお伺いしたいと思います。","respondent":"丸谷教育総合支援センター長、酒川指導課長","answer":"それから拠点校になったところに行きたい子どもたちがいるかどうかというマッチングの部分で、今年度の実績としては０校、０部活という状況です。大切な視点ではありますので、今後も事業は継続していこうと考えております。 指導できる教員がいるかいないかにかかわらず指導できるように、部活動の指導員、それから業務委託というものを実施しています。","id":"exchange-105"},{"speaker":"塚本委員","kind":"意見","question":"自分の学校にはなくて、そこに行きたいのだけどみたいな話というのを、例えば学校部活動コーディネート経費というのが出ています。やはりそういうのはなかなか課題があるのかどうか、できないのかどうか、もう一度ご答弁をお願いしたいと思いますとの意見を述べました。","respondent":"酒川指導課長","answer":"三校あって、例えばコンクールに出られたりという状況が生まれてくることが今後あれば、そういった合同のあり方もあるかなと考えています。学校と部活動指導員、将来的にニーズがあれば、そういった調整も行う窓口になるかなと思っています。","id":"exchange-106"},{"speaker":"塚本委員","kind":"質問","question":"２０３０年に向けて昨年か、主体的・対話的で深い学びというのが、大きな方向性の１つのテーマとして掲げられています。生徒にこういう教育をしようとする、目的みたいなものが同じという形で理解していいのかというところを説明を求めました。","respondent":"唐澤教育施策推進担当課長","answer":"全ての教科について、子どもたちがやはり主体的・対話的な深い学びを実装できるように、授業改善を教師が進めながらやっていくものと認識しています。各教科で身につけた内容をまた探究的な学習で活かしながら、そうした往還の中で進めていくものと認識しております。","id":"exchange-107"},{"speaker":"塚本委員","kind":"質問","question":"もう一回お伺いしたいのと、まず来年の令和８年度の市民科検討委員会での主な取組内容については、どのようなことを考えていらっしゃるのか説明を求めました。","respondent":"唐澤教育施策推進担当課長","answer":"令和８年度につきましては、その調査結果に基づきながら、改めて今後の市民科について検討していく。ここが大きな１つの内容と認識しています。","id":"exchange-108"},{"speaker":"塚本委員","kind":"質問","question":"学びの個別最適化というのですか、どちらが正しいのか分からないですけれども、こういったことも深い関連がある話だと思います。こういった学びの個別最適化ということについての品川区としての取組を最後にお知らせほしいと求めました。","respondent":"唐澤教育施策推進担当課長","answer":"教育振興基本計画のところでも、今後の学習環境の整備というところで挙げていますが、授業改善が大きな肝だと考えています。それに至っては、子どもから考えることと、やはり教師から考えること、そして今、検討委員会でもやっている学習内容の３つが大事だと考えています。","id":"exchange-109"},{"speaker":"鈴木委員","kind":"質問・要望","question":"今から６年前から、特別支援教育を充実させるためには推進計画をつくるべきではないかと、求めてきました。なぜこれまでつくらないとしてきた推進計画を策定することになったのか、その理由を伺いたいと思います。","respondent":"新井特別支援教育担当課長","answer":"アクションプランの中では、特別支援教育の計画的、また体系的な推進といったところの必要性というのが示されているところです。策定の委員会を設立する予定でございまして、基本的には、それ以外の推進計画の策定の支援といったところで一部業務委託を予定していまして。","id":"exchange-110"},{"speaker":"鈴木委員","kind":"質問","question":"今後、特別支援教育の対応が必要な子どもが増えるのではないかと思うのですけれども、区の認識はいかがでしょうか。昨年の決算特別委員会で、特別支援学級等教室に通う子どもの人数とパーセンテージを伺ったのですけれども、加えて。","respondent":"新井特別支援教育担当課長","answer":"２点ご質問を頂きまして、まず１点目の、５歳児健診の実施に伴って、特別支援教育の対応が必要なお子さんが増えるのではないかといったところです。目安となるのが、私どもで実施している就学相談といったところで…","id":"exchange-111"},{"speaker":"鈴木委員","kind":"質問・要望","question":"区の方針としても、ぜひとも説明会を行っていただきたいと思うのですけれども、この点についても伺いたいと思います。これをさらに充実させていくということにもつながっていくと思いますので、ぜひ説明会を位置づけていただきたいと思うのですが、いかがか尋ねました。","respondent":"新井特別支援教育担当課長","answer":"大きく３点、まず１点目のご意見のところ、実施していくこともあり得るかと考えています。説明会といったところは１つの手法として考えてございまして、その点をまずは引き続き、鋭意努めていきたいと考えています。","id":"exchange-112"},{"speaker":"鈴木委員","kind":"質問・要望","question":"説明会は本当にとても大事な計画だと思いますので、ぜひ位置づけてほしいと求めました。当事者の意見もぜひとも反映するようにお願いします。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-113"},{"speaker":"須貝委員","kind":"質問","question":"こんなことでいいのですか。これについてどのようにお考えか尋ねました。","respondent":"酒川指導課長","answer":"一つ一つの教育課題には真摯に向き合わせていただきたいと考えているのと、こういった点で、以前よりも対応を多大に要しているのかなと思っています。こういったものに一つ一つ真摯に向き合っていきたいと考えております。","id":"exchange-114"},{"speaker":"須貝委員","kind":"質問","question":"これは、教育委員会としても考えるべきだと私は思うのです。こういうことを考えて、どのようにお考えか尋ねました。","respondent":"丸谷教育総合支援センター長、酒川指導課長","answer":"認知については大きな予算をつけていただいて、教員が一つ一つ小さなものも見逃さずに認知を進めて対応していると捉えております。不登校の増加に対しては、今、多様な学びと言われていますけれども… 一定数、毎年、私立中学校に受験で出ていくという実態は承知しております。限られた予算、限られた資源を使って、なるべく各校の特色・魅力といったものを発信するような教育活動を展開していけたらと考えています。","id":"exchange-115"},{"speaker":"須貝委員","kind":"質問","question":"でも、それを変えていかなかったら、本当の教育改革にならないのではないですか。まず教育改革として第１ページで、優先的にやる仕事だと私は思うのですが、もう一度ご見解を説明を求めました。","respondent":"酒川指導課長、丸谷教育総合支援センター長","answer":"やはり学校の管理職の先生と教育委員会が連携を深めて、先生方一人一人が生き生きと働けるような環境をつくっていきたいと考えております。区長部局との連携というのも、今後も継続して図っていきたいと考えています。 子どもたちの居場所づくり、絆づくりということで、支援・対策を進めているところです。","id":"exchange-116"},{"speaker":"須貝委員","kind":"提案","question":"逆に、文部科学省にはっきり言うべきではないですか。やはり、今までの国の、都のカリキュラムではもう対応できないのではないですかと、私ははっきり申し上げるべきだと思いますとの意見を述べました。","respondent":"酒川指導課長","answer":"校長が示す学校の経営方針の中に提案していくような学校経営を行っていきましょうということを、校長連絡会等で広く周知するようにしております。このように考えております。","id":"exchange-117"},{"speaker":"須貝委員","kind":"質問","question":"毎日もう疲弊して帰っているのではないのですか。その辺もよく考えてください。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-118"},{"speaker":"せお委員","kind":"提案","question":"そこで、この生徒の発言についての見解を伺うとともに、補助教材費無償化の今後についても見解を伺います。リサイクルの取組も重要と考えますが、こちらの見解も伺いますとの意見を述べました。","respondent":"石井学務課長","answer":"貸出し制にするのも１つの方法であったり、体験ボードというふうなところで、実際に実施している学校もあるとは聞いております。そういう意味では、今、この無償化事業が始まり、補助教材費保護者負担軽減事業につきましては、令和６年度に実施して２か年目を迎えました。","id":"exchange-119"},{"speaker":"せお委員","kind":"質問","question":"あくまでこのような意見が出たという一例なのですけれども、これを受けて区教育委員会の見解をお聞かせほしいと求めました。来年度はどのように進めていく予定なのか説明を求めました。","respondent":"石井学務課長","answer":"その意見交換会の場でも私は、これまでも同様、現場の声を聞きながら、現場と足並みをそろえながら、しっかり進めていきたいと考えているところです。こういった形で、確実にきちんと持続可能な形で実施できるように、来年度以降も努めてまいりたいと考えております。","id":"exchange-120"},{"speaker":"せお委員","kind":"質問・要望","question":"１食の単価を上げる、メニューの工夫を子どもたちと一緒に行うなどですけれども、こちらに使っていただきたいと私は考えています。国から入ってくる給食費の予算というところで、割り当てる予算についての見解をお聞かせほしいと求めました。","respondent":"石井学務課長","answer":"ある意味、簡易的な試算ですけれども、国の無償化によって４億７,０００万円ぐらいの財源が生まれるところです。給食の充実に向けて取り組んでまいりましたけれども、それは予算の編成や予算の審議の中において、るる進められてくるものだと承知しております。","id":"exchange-121"},{"speaker":"せお委員","kind":"質問・要望","question":"大谷選手が全校に贈ったという思いを酌み取って、もう少し活用できないかと思いますが、こちらも見解を伺います。継続した探究的な学習をお願いしたいのですが、見解を伺います。","respondent":"石井学務課長、丸谷教育総合支援センター長、唐澤教育施策推進担当課長","answer":"令和８年度につきましても、原則として４年生以上の児童・生徒が使用する女子トイレに配布するための事業を継続していくようなところです。… キャッチボール等で使用したという報告も受けておりますが、なかなか貴重なものですので、学校に展示してあるという学校もあると聞いております。… それは、幼児教育からの円滑な連携をして、スタートカリキュラムの中で体験活動を中心に行っております。その生活科の体験的な学習が…","id":"exchange-122"},{"speaker":"せお委員","kind":"質問・要望","question":"そういったところでも、ぜひ大谷選手の思いを届けたいと思いますので、ぜひ活用を教育委員会で考えてほしいと求めました。１・２年生は幼稚園・保育園の延長でよろしいかと思いますので、継続した探究的な学習というところをしていただきたいと思っています。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-123"},{"speaker":"大倉委員","kind":"質問","question":"ほかにも何個か、３８３ページ、学校給食費、４０１ページ、学校ＩＣＴ活用経費、様々伺っていければと思っています。令和３年に内閣府が実施した「子供の生活状況調査」によると、学校としてどういうふうに捉えているかというのを説明を求めました。","respondent":"酒川指導課長、丸谷教育総合支援センター長、石井学務課長","answer":"学校と部活動指導員および地域スポーツクラブ文化団体等との連絡・調整を行うものということで、教員に代わって、そういった業務を担っております。… 会計年度任用職員として任用しておりまして、部活動の実態に合わせて週の勤務日数等は定めているところです。平日は４日まで、土日は１日までという… 様々ベーシックサービスの考え方から、弱者を救うのではなく弱者を生まない社会をつくるという形で無償化施策を進めてきたところです。そういう意味で…","id":"exchange-124"},{"speaker":"大倉委員","kind":"質問・要望","question":"これは今、１人当たりの金額はどういうふうに考えたらいいのかというのを教えていただきたいのと、その範囲でやられているということで理解しました。ただなのか、それとも自己負担なのか、この辺はどうなっているのでしょうかということを教えてほしいと求めました。","respondent":"酒川指導課長、丸谷教育総合支援センター長、石井学務課長","answer":"存在していないというようなことをカバーできるように、指導課では業務委託によって、子どもたちの活動の維持に努めているところです。全校で実施中ですの… 基本的には勤務の振替において進めていくことが原則となりますが、勤務日数が足りなくなった場合の、課題を整理していきたいと考えております。今の仕組み… 教職員が児童・生徒と一緒に食べる給食費ですけれども、それにつきましては教員がそれぞれ自己負担をしているような状況です。","id":"exchange-125"},{"speaker":"大倉委員","kind":"確認","question":"教員の先生たちの給食の時間も勤務ということで確認を今しましたので、１食幾らなのかというところでいうと２００円とか３００円とか、お願いします。例えば人材への支援というところで、何か品川区でも考えていただけないかと思うのですが、いかがか尋ねました。","respondent":"酒川指導課長、石井学務課長","answer":"元保護者といった方々にご協力を頂いている状況ですけれども、学校がどのような人材確保に向けて苦慮しているかということを個別に把握して、また人材確保を協力して進めていきたいと考えています。 は教職員が負担しているものは様々まだ負担があるということは承知しておりますので、委員のご指摘も踏まえながら、様々な観点で考えていきたいと考えています。","id":"exchange-126"},{"speaker":"大倉委員","kind":"質問・要望","question":"費用の面も含めて、ぜひ皆さんの力が必要ですということもあるのかなと思っていますので、ぜひその辺も含めて考えてほしいと求めました。子どもにとっても地域にとっても大切な地域の学校ですから、この辺は上げていただきたいと思うのですが、いかがか尋ねました。","respondent":"石井学務課長","answer":"令和８年度につきましては、鮫浜小学校をはじめ、全部で８校が周年行事を迎えるところです。役務費など様々ありますけれども、物価の動向も踏まえながら適切に予算措置をしていますし、今後も物価の動向なども注視していきたいと考えています。","id":"exchange-127"},{"speaker":"西本委員","kind":"質問","question":"現在３３名、区固有教員ですけれども、令和８年度にプラス５名ということなのですが、何人を目安にしているのでしょうか。そして次に、３８９ページのしながわ教育推進事業の中で、学校選択制をやっているのですが、学校選択制の目的は何か尋ねました。","respondent":"石井学務課長、酒川指導課長","answer":"きめ細やかな指導が実施されるというところで、現状ですと、この辺りについては慎重に検討しなければならない部分であると考えていますし。そのときに実施した目的や、今後も各学校が工夫を凝らして… 固有教員ですが、区独自の教育施策、市民科や英語科の推進役として配置しております。全校に１人配置していきたいですけれども、区全体の予算とバランスを取りながら慎重に考えていきたいと考えています。","id":"exchange-128"},{"speaker":"西本委員","kind":"質問","question":"これは寄附で賄うと言っているわけですから、予算の話をしているわけですから、お知らせください。教育、やはり学校選択制というものの見直しを図るべき時期に来ているのではないかと思いますが、いかがか尋ねました。","respondent":"酒川指導課長、石井学務課長","answer":"少人数化につきましては、教科によっては少人数指導を既に実施しておりますので、特にこういった点は引き続き力を入れていきたいと思っています。教員の意識改革については、時代に合わせ… まだまだ令和３０年度ぐらいまで一定程度、増え続けるような推計をしておりますが、今後の推計も少しずつ変わってくると思います。きめ細やかな教育ということはすごく必要なことであると考えていますので…","id":"exchange-129"},{"speaker":"西本委員","kind":"意見","question":"これからの品川区の教育に必要なことというのは、やはり一人一人にしっかり向き合った教育にあるべきだと思っています。学校選択制は、もう見直しを図るべき時期に来ていると私は思いますので、ご検討をとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-130"},{"speaker":"こんの委員","kind":"質問","question":"私からは、３８７ページ、学級集団アセスメント、３９３ページ、学校生活支援員等委託をお伺いしたいと思います。こうした現状が及ぼす学級経営への影響はどのように捉えていますか尋ねました。","respondent":"丸谷教育総合支援センター長、新井特別支援教育担当課長","answer":"そうした中で、学級経営、子どもたちへの、クラスの様子を知るアセスメントという観点から、学校風土調査というものを昨年度から実施しています。学校全体の風土と同時に、学級や学年の状況も見ることができますので… １校当たりの支援員の配置数といったところですけれども、通常の学級に在籍するお子さんたちへの支援員の配置というところで、まず大きく分かれます。委託事業については、この３つの種類の支援員を配置しています。","id":"exchange-131"},{"speaker":"こんの委員","kind":"質問・要望","question":"実施体制についてお伺いしたいのと、あとアセスメントの内容など、現在の取組状況などを教えてください。できるだけ万全の体制で受入れ体制をつくっていただきたいし、さらなる増員が必要ではないかと思うのですが、いかがか尋ねました。","respondent":"丸谷教育総合支援センター長、新井特別支援教育担当課長","answer":"実施学年についてですが、１年生から９年生までの全学校・全学年が対象となっております。６月と１２月に実施しておりまして、１人１台端末を用いて、実施後すぐに学校でも結果が分かるような仕組みになっております。 支援員の配置については鋭意、人材を確保していくというのを１つ、課題としても認識しています。配置が必要なところにきちんと充足されるような人材を充てるといったところを今後も進めてまいりたいと思います。","id":"exchange-132"},{"speaker":"こんの委員","kind":"質問・要望","question":"生徒との関わりといったことを、先生たち自らが、信頼関係ができる取組の一つとして活用できるようにしていただきたい。このように要望して終わります。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-133"},{"speaker":"高橋（し）委員","kind":"質問","question":"源氏前小学校と鈴ケ森小学校で、授業用バス借り上げ、３９０万円ですが、プール利用と伺っています。これは、改築中ずっと学校行事で使うものなのか尋ねました。","respondent":"荒木学校施設担当課長","answer":"２点目の式典につきましては、きゅりあんを借り上げて実施する予定です。今後の予定といたしましては、令和８年度から１１年度まで継続して予算措置をして、学校運営を支援してまいりたいと考えています。","id":"exchange-134"},{"speaker":"高橋（し）委員","kind":"質問","question":"そこで教育委員会に伺います。教育委員会は令和７年度の事務事業評価で、それとも拡充が必要と認識しているのか、現場からのニーズも含めてお答えください。","respondent":"新井特別支援教育担当課長","answer":"なので、私どもとしては、今後拡充していく必要があるという認識は持ってあります。その一方で、いわゆる配置の最適化といいますか、本当にどれだけの支援が必要かといったところをきちんと見極めてまいりたいと考えています。","id":"exchange-135"},{"speaker":"高橋（し）委員","kind":"質問","question":"教育委員会がこのように成果を認めて、現場にも増員ニーズがある中、なぜ拡充を認めなかったのか、財政課に伺います。必要性は認めるが今回は見送ったということであれば、何を条件に今後の拡充を判断していくのか尋ねました。","respondent":"加島財政課長","answer":"発達障害教育支援員につきましては、令和６年度の小学校・義務教育学校（前期課程）全校配置からまだ間もないため、見送りといたしました。配置の最適化等を図った上で、また来年度、令和９年度の予算編成の中で判断していくことになろうかと考えております。","id":"exchange-136"},{"speaker":"高橋（し）委員","kind":"質問・要望","question":"ぜひ今後、年度途中でもいいですから、拡充していただくことを強く要望いたします。この窓口を予算要求したのは、現場にどのような課題があり、教員の負担軽減や学校運営の安定にどのような効果が必要だと考えたのか尋ねました。","respondent":"丸谷教育総合支援センター長","answer":"国が学校と教師の業務の３分類の中で、学校では対応が困難な事案への対応については、学校以外が担うべき業務ということで記しています。東京都からは、これを受けて本区でも体制強化が必要と捉えまして、教員の負担軽減も含めまして要求したものです。","id":"exchange-137"},{"speaker":"高橋（し）委員","kind":"質問","question":"ということで、教育委員会が必要性を認識して要求したにもかかわらず、なぜこの窓口開設を見送ったのでしょうか。教員の保護者対応負担を軽減する代替策をどう講じるのか、また、いつ窓口開設を再検討するのか、考えがあるのか伺います。","respondent":"加島財政課長","answer":"既に利用している法律相談等のサービスでの対応可否を含め、事業実施手法の検討余地があるというところで判断したところです。教育総合支援センター長ともよく話をいたしまして、保護者対応専用窓口の開設については見送りといたしましたけれども、ご理解を得たところです。","id":"exchange-138"},{"speaker":"高橋（し）委員","kind":"質問・要望","question":"スクールロイヤーが１人増えていますが、年度途中でもいいですから、充実させて予算化していく。いかがか尋ねました。","respondent":"加島財政課長、丸谷教育総合支援センター長","answer":"令和８年度予算編成の中で、スクールロイヤーを２人体制にさせていただきましたので、そちらの効果検証が先だと考えます。 与えられた条件の中で、まずは窓口の開設を、令和８年度、進めてまいります。","id":"exchange-139"},{"speaker":"松本委員","kind":"質問・要望","question":"私からは、３８７ページ、いじめ防止対策費について伺います。この単価増についても、「附属機関の構成員の報酬および費用弁償に関する条例」で改正する必要があるのではないかと思いますが、いかがか尋ねました。","respondent":"丸谷教育総合支援センター長","answer":"委員長を務めている弁護士への費用ということで、増額が適切ではないかということで、今回要求させていただいているものです。条例改正も併せてということで認識がございまして、第２回定例会で、こちらは進めていく予定です。","id":"exchange-140"},{"speaker":"松本委員","kind":"質問・要望","question":"これはどういった費用なのでしょうか。伺います。","respondent":"丸谷教育総合支援センター長","answer":"それ掛ける１０事案、１０事案程度重大事態が起こるであろうという想定の下、算出しているものです。","id":"exchange-141"},{"speaker":"松本委員","kind":"確認","question":"今回、これまでの２万３,０００円などというところだけだと、これは調査報告素案の作成というところまで計上していただいているのだと思います。念のため確認ですが、各委員、この委員の方たちが実際に報告書の素案を作成するための費用ということでよろしいか尋ねました。","respondent":"丸谷教育総合支援センター長","answer":"調査結果につきましては、全て委員で作成することにしておりまして、そのための費用ということで捉えていただければと思います。","id":"exchange-142"},{"speaker":"松本委員","kind":"質問","question":"当区も重大事態の調査が、諮問から１年を超えるものが出始めているというところで、その滞留がまた始まっているのかなと思います。品川区のいじめ対策委員会規則に規定されている調査部会の活用について、現状と、滞留を解消するための対策について伺えればと思います。","respondent":"丸谷教育総合支援センター長","answer":"限られた時間の中で品川区いじめ対策委員会を開いておりまして、並行して複数の事案を同日に検証しているという実態があります。委員である弁護士を増やしておりますので、そういった意味での滞留を少しずつ解消できるような体制を、今整えているところです。","id":"exchange-143"},{"speaker":"松本委員","kind":"提案","question":"その場合は調査がなかなか深掘りできないという問題があるかと思いますので、ここは本当に事案に合わせてやっていただくのが大事なのかなと思います。ここはもう時間がないので、今後、議事要旨も出されることを再び提案して質問を終わりますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-144"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"私からは、３８４ページの教育指導費から、項目はないのですがジェンダー教育について伺いたいと思います。第３回定例会の一般質問で、包括的性教育を区民向けに、そして小・中学校で実施をと求めました。","respondent":"丸谷教育総合支援センター長","answer":"保健予防課による事業として、令和５年度、令和６年度、令和７年度、それぞれ１校ずつ、実施状況があります。全ての学校の養護教諭が対象となっておりまして、ご紹介いただいたＮＰＯ法人ピルコンを講師に招いて実施したものです。","id":"exchange-145"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"学校の教員や校長先生が、性に関する教育に意識が向いていないと、要望は上がってこないと思うのです。各学校に、こうした連携等を含めて性に関する教育を進めるように呼びかけていただきたいと思うのですけれども、いかがか尋ねました。","respondent":"丸谷教育総合支援センター長","answer":"昨今、「生命の安全教育」を全校実施するということで取組が始まりまして、学校の意識も徐々に高まっていると認識しています。区としても、こういった取組を広く周知するとともに、実施に向けた後押しをしていきたいと考えております。","id":"exchange-146"},{"speaker":"石田（ち）委員","kind":"質問","question":"それを復活させるべきだ」ということを質問しましたところ、区は。なので、働きかけはしていただいたのか、その後の状況を聞かせてください。","respondent":"丸谷教育総合支援センター長","answer":"すみません。今、把握していないところですけれども、性教育についても広く周知してまいりたいと考えております。","id":"exchange-147"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"そうした声は本当に多く寄せられていますので、ぜひ幼児期の親だけでなく、多くの保護者に必要だし、求められていると思うのです。小・中学校の保護者に対しても、教育委員会としてこうした対応をしていただきたいと思うのですけれども、いかがか尋ねました。","respondent":"丸谷教育総合支援センター長","answer":"外部講師の選定については、各学校が行うものと認識しておりまして、こちらから事業者に直接的に声をかけるということは行っておりません。現状、保護者のニーズなどといったものを捉えながら、事業を進めていくものと捉えております。","id":"exchange-148"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"ですので、やはり親がどう性と向き合って、子どもたちにどういう言葉を発していくかというのは大変重要になっていきます。そうした、保護者に対してのニーズをつかむという検討もしていただきたいのですが、いかがか尋ねました。","respondent":"丸谷教育総合支援センター長","answer":"１つ、各学校でＰＴＡが実施しているものがありますが、ＰＴＡ主催で実施していくことは十分可能だと捉えております。教育委員会といたしましては、人権・ジェンダー平等推進課や「しながわほけんしつ」などとも連携しながら取り組んでまいりたいと考えております。","id":"exchange-149"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"ぜひ進めていただきたいと思うのですが、あと、先ほどの養護教諭のところで、それだけ研修をして、全養護教諭に研修をしていただいたということで、それを今後どのように活かしていくのかというのを最後にお聞きしたいと思います。","respondent":"丸谷教育総合支援センター長","answer":"昨年、養護教諭向けに研修を致しましたので、養護教諭の認識というものは高まったと捉えております。各学校に持ち帰りながら、児童・生徒の実態を捉えて、こうした教育の実践につなげていけるようにしたいと考えております。","id":"exchange-150"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"ぜひ引き続き、そうした団体の力も借りながら、連携して区内でさらにジェンダー平等を進めていくために、力を尽くしてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-151"},{"speaker":"若林委員","kind":"質問","question":"これは、作成委員会がありますけれども、委員の選定や資料内容のチェックはどのように行われているでしょうか。それから、時代とともに変化している特徴があれば、来年度の予定の内容も含めてお聞きしたいと思います。","respondent":"丸谷教育総合支援センター長","answer":"開催についてですけれども、年間を通じて行っておりまして、今年度は７回、実施いたしました。ほぼ６月から毎月のように集まりまして、授業を４回、幼稚園・小学校・中学校と、それぞれ実施しております。","id":"exchange-152"},{"speaker":"若林委員","kind":"質問・要望","question":"区の平和教育では、討論や探求学習など、主体的・対話的な学びをどのように取り入れているのかを伺いたいと思います。戦争がなぜ起きるのかを考えることは、戦争を起こさないために私たちが何をすべきかを考えることにつながると思います。","respondent":"藤村総務課長、唐澤教育施策推進担当課長","answer":"８月２９日に区長と教育長ご参加の下、それぞれグループの発表の後に、講評というか感想を頂いたというような形で開催させていただきました。多くの子どもたちに、総務課の事業になるのですが… １年生から９年生、命の大切さを実感できる、こうしたものが重要な視点だと考えています。人権教育につきましては、こうしたものを各学年の発達段階に応じて教育を積み重ねる中で、一人一人の育成を図っていきたいと考えております。","id":"exchange-153"},{"speaker":"若林委員","kind":"意見","question":"なぜ戦争が起きるのかという角度でのお答えはなかったように思います。では、ご答弁をとの意見を述べました。","respondent":"丸谷教育総合支援センター長","answer":"現在、世界中が今、我々の自分事として考えていくということがますます大事になってくると捉えております。この資料が今後、学校に配布されますので、しっかりと活用できるように推進してまいります。","id":"exchange-154"},{"speaker":"若林委員","kind":"意見","question":"深めることで、子どもたちの学びや気づきが充実できればという、また現場の創意工夫をお願いしたいと存じますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-155"},{"speaker":"藤原委員","kind":"質問","question":"３８１ページ、文化財保護費、３８９ページ、市民科・各教科充実経費についてお伺いします。区長もこの投稿の中で触れていらっしゃいますが、今回この能楽堂の何が評価されて登録に至ったのか、まずお伺いします。","respondent":"舩木庶務課長","answer":"これまでいろいろ国の登録にというような訴えかけもある中で、このたび令和８年２月１０日の官報告示をもって、国の登録の有形文化財に登録されたものです。","id":"exchange-156"},{"speaker":"藤原委員","kind":"質問","question":"私は文教委員会で伺ったのではなくて、区民委員会でお伺いしたと思っているので、連携をどういうふうにしていくのか。その辺についてお伺いします。","respondent":"舩木庶務課長","answer":"記念の講演も予定されておりますし、文化の所管とも教育委員会としては連携を図った上で、品川区の地域の価値を高めていければと考えております。","id":"exchange-157"},{"speaker":"藤原委員","kind":"質問","question":"これからも長く続いていくためには必要なことだと思っています。今、そういった地域学習でも独自カリキュラムでも取り組むことがあるのか教えていただけますか。","respondent":"丸谷教育総合支援センター長","answer":"過去にも喜多能楽堂での体験学習というものを複数校でさせていただいているという実績がありますので、今回改めてこうした体験活動を実施できるような取組が進められればいいなと、教育委員会としても思っております。","id":"exchange-158"},{"speaker":"藤原委員","kind":"質問","question":"その辺についていかがですかという点と、以前にも質問したのですが、どこの団体も自分たちの自力でやっていくことというのが大変だとよく聞きます。そういったところへの区としての経済的な支援について、何か検討の余地がないかお伺いします。","respondent":"丸谷教育総合支援センター長、舩木庶務課長","answer":"体験については、体験のみで終わらせないということで、まず目的設定が大事だと考えております。それを継承していくという意識も高めていくことが目的になってありますので、そうした意識づけを子どもたちにしていきたいと考えておりま… 文化財保護のための奨励金制度というものが区にはありますけれども、その重要性は十分に認識しています。昭和６２年度より開始しておりまして、２３区の状況に向けますと…","id":"exchange-159"},{"speaker":"藤原委員","kind":"質問・要望","question":"確実に足りないわけですから、もっと踏み込んでやってほしいと求めましたので、よろしくお願いいたします。図書館運営費についてお伺いするのですが、それが確認なのと、どのように考えていますか。","respondent":"三ツ橋品川図書館長","answer":"図書館のあり方については、またレファレンス機能や様々なことが、こちらに書かれております。品川区立図書館といたしましても、やはりこれからしっかりと、地域に愛されて、地域から必要とされるような図書館づくりを目指してまいります。","id":"exchange-160"},{"speaker":"藤原委員","kind":"質問・要望","question":"そして、社会福祉協議会にもいらっしゃった。館長として前のキャリアを活かしていただくような図書館になっていっていただきたいと思うのですが、最後にその辺の思いをもう一度説明を求めました。","respondent":"三ツ橋品川図書館長","answer":"委員のご紹介のように、私もいろいろな部署を経験させていただきました。それらを踏まえて、これからの図書館像、品川区立図書館のあり方については、しっかりと対応してまいります。","id":"exchange-161"},{"speaker":"まつざわ委員","kind":"質問","question":"私からは、３８９ページ、しながわ教育推進事業から市民科についてお聞きします。再検討を掲げている意図、これまでの市民科の課題、具体的にどうアップデートしていくのか説明を求めました。","respondent":"唐澤教育施策推進担当課長","answer":"区の教育につきましても、国の動向を踏まえながら、改訂に向けての動きを始めていく中で、今年度より市民科検討委員会を立ち上げたところです。児童・生徒、教員へのアンケート調査を実施しており、これまで実施してきた市民科の成果・課題を分析しているところです。","id":"exchange-162"},{"speaker":"まつざわ委員","kind":"提案","question":"企業が実際に直面している課題に対して子どもたちが解決策を提案する、本区、品川区が誇る中小企業。そういった部分での多様な職種というのを確保するべきと考えますが、いかがか尋ねました。","respondent":"唐澤教育施策推進担当課長","answer":"現在、市民科「一貫プラン」の中で実施している探究的な学習においては、市民科でこれまで大切にしてきた実学的な要素を重要視しております。子どもたちの探求課題に応じながら様々な活動につなげられるように、学校への支援の充実には努めていきたいと思います。","id":"exchange-163"},{"speaker":"まつざわ委員","kind":"質問","question":"そこで、東京都が令和８年度に拡充しました、子供の未来を育む「体験活動・遊び」の推進事業。これは、こういった東京都の補助メニューをいろいろと組み合わせてやっていったりといった、財源の獲得の視点で説明を求めました。","respondent":"丸谷教育総合支援センター長","answer":"区立学校において、笑顔と学びの体験活動プロジェクトとして、令和５年度から取り組んでいるものです。令和８年度の募集も始まりましたので、多くの学校で本事業を活用するよう働きかけてまいります。","id":"exchange-164"},{"speaker":"まつざわ委員","kind":"質問・要望","question":"そういったメニューの中から選ぶというので、いろいろな補充メニューというのは、しっかりと研究して組み合わせてほしいと求めました。ぜひ本区においても、あるいは事務局の機能を強化するといった方向性・考えはあるのか尋ねました。","respondent":"唐澤教育施策推進担当課長","answer":"地域や企業との連携につきましては、現在、学校地域コーディネーターが中心となって進めているところです。今後のあり方につきましては市民科検討委員会の中で議論を深めたいと思います。","id":"exchange-165"},{"speaker":"まつざわ委員","kind":"質問","question":"教育委員会側が、標準的な学習のパッケージやワークシートといったものを用意して、質の担保を図っていました。事前学習のガイドといったものを準備して、先生が迷わず指導できる体制を整えようとしているのか、お伺いします。","respondent":"唐澤教育施策推進担当課長","answer":"探究的な学習に係る構想図、年間指導計画、単元指導計画等についての補助資料を今回提示したところです。次年度より探究的な学習の支援アプリを導入する予定となっておりますので、教員は生徒の実態に応じた支援を展開できるように。","id":"exchange-166"},{"speaker":"まつざわ委員","kind":"質問・要望","question":"ただの感想文で終わらせるのではなくて、学習履歴の蓄積、独自の評価指数といったものを可視化するべきだと私は思います。どのような評価指数や手法を考えているのか説明を求めました。","respondent":"唐澤教育施策推進担当課長","answer":"探究的な学習を、子どもたち同士もですし、それを聞かれる地域・保護者の方からの総合評価といったものも大事な観点ではないかと考えています。今後の評価のあり方については、現在、国でも議論が進んでおりますので…","id":"exchange-167"},{"speaker":"まつざわ委員","kind":"質問","question":"商店街の活性化といった、地域のリアルな課題に挑む地域探究プロジェクトといったものも、市民科の柱にしてはいかがでしょうか。これこそが、社会課題を自分事化する究極の主権者教育ではないか尋ねました。","respondent":"唐澤教育施策推進担当課長","answer":"企業提案も含めまして、地域貢献の取組も、まとめのところで想定しているところです。各学校の中で、こうした地域と連携した取組を実践している学校が何校かありますので、改めてまた学校間で共有できるようにしてまいります。","id":"exchange-168"},{"speaker":"まつざわ委員","kind":"提案","question":"では、最後に提案します。ああいったものを公式に設けてはいかがか尋ねました。","respondent":"唐澤教育施策推進担当課長","answer":"体験実学を重視する市民科では、地域の方々と関わる事業は数多くありますし、これからも充実することは大変重要なことだと認識しております。そうした提案などの発信の機会などについても引き続き検討してまいります。","id":"exchange-169"},{"speaker":"まつざわ委員","kind":"質問・要望","question":"今回の再構築で、人の力も総動員して、世界一の教育環境を整えていただきたい。そんな教育の品川区への決意を、ぜひ教育長、お願いいたします。","respondent":"伊崎教育長","answer":"今、課長からご説明申し上げたとおり、再構築を行ってまいります。個人と社会のウェルビーイングを目指して、このプランの一つ一つの前進に全力を尽くしてまいります。","id":"exchange-170"}]}],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/629350?Template=document&Id=7391#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=3&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":120226,"voices":388}}]);
